DOR_DAYS.push({"thema": "Sich vorstellen — Presentarsi", "level": "A1", "lesen": {"title": "Ein neuer Anfang in Berlin", "text": "Mein Name ist Lena und ich bin dreiundzwanzig Jahre alt. Ich komme aus Italien, aus einer kleinen Stadt in der Nähe von Rom. Seit zwei Monaten wohne ich in Berlin. Hier studiere ich Kunst an der Universität. Am Anfang war alles schwer: Die Sprache, die Stadt und das Wetter. Berlin ist viel größer als meine Heimatstadt und am Anfang habe ich mich oft verloren gefühlt. Aber jetzt geht es mir gut. Ich habe schon ein paar Freunde gefunden und jeden Tag lerne ich etwas Neues. Mein Lieblingsort ist ein kleines Café neben der Universität. Dort trinke ich morgens einen Kaffee und schreibe in mein Tagebuch — natürlich auf Deutsch, auch wenn ich noch viele Fehler mache.", "glos": {"Name": "nome", "komme": "vengo", "Italien": "Italia", "Nähe": "vicinanze", "Stadt": "città", "wohne": "abito", "studiere": "studio", "Kunst": "arte", "Anfang": "inizio", "schwer": "difficile", "Sprache": "lingua", "Wetter": "tempo (meteo)", "größer": "più grande", "Heimatstadt": "città natale", "verloren": "perso/a", "Freunde": "amici", "gefunden": "trovato", "lerne": "imparo", "Neues": "di nuovo", "Lieblingsort": "posto preferito", "Café": "caffè (locale)", "trinke": "bevo", "Tagebuch": "diario", "Fehler": "errori", "schon": "già", "etwas": "qualcosa"}, "q": [{"q": "Woher kommt Lena genau?", "o": ["Aus Rom selbst", "Aus einer kleinen Stadt bei Rom", "Aus Berlin"], "c": 1, "e": "„aus einer kleinen Stadt in der Nähe von Rom\" = vicino a Roma, non Roma stessa."}, {"q": "Was studiert sie in Berlin?", "o": ["Sprachen", "Kunst", "Musik"], "c": 1, "e": "„Hier studiere ich Kunst\" = studio arte."}, {"q": "Wie fühlt sie sich jetzt?", "o": ["Immer noch verloren", "Es geht ihr gut", "Sie will zurück nach Italien"], "c": 1, "e": "„Aber jetzt geht es mir gut\" = adesso sto bene."}], "frage": "Und du? Stell dich kurz vor: Wie heißt du, woher kommst du, und warum lernst du Deutsch?"}, "artikel": {"title": "Warum lernen so viele Menschen Deutsch?", "text": "Deutsch ist nach Englisch eine der wichtigsten Sprachen in Europa. Über 100 Millionen Menschen sprechen Deutsch als Muttersprache, vor allem in Deutschland, Österreich und der Schweiz. Aber warum lernen jedes Jahr Millionen von Menschen diese Sprache? Ein wichtiger Grund ist die Arbeit. Deutschland hat eine starke Wirtschaft und sucht viele Fachkräfte, zum Beispiel Ingenieure, Pflegekräfte und Programmierer. Ein anderer Grund ist das Studium: Universitäten in Deutschland sind oft kostenlos, auch für Studenten aus dem Ausland. Und schließlich gibt es die Kultur — die Musik, die Bücher und die Filme. Viele Menschen sagen: „Deutsch ist schwer, aber es öffnet viele Türen.\"", "glos": {"wichtigsten": "più importanti", "Millionen": "milioni", "sprechen": "parlano", "Muttersprache": "lingua madre", "Österreich": "Austria", "Schweiz": "Svizzera", "Grund": "motivo", "Arbeit": "lavoro", "Wirtschaft": "economia", "sucht": "cerca", "Fachkräfte": "manodopera qualificata", "Ingenieure": "ingegneri", "Pflegekräfte": "personale sanitario", "Studium": "studi (universitari)", "kostenlos": "gratuito", "Ausland": "estero", "Kultur": "cultura", "Bücher": "libri", "öffnet": "apre", "Türen": "porte", "schwer": "difficile"}, "q": [{"q": "Wo spricht man Deutsch als Muttersprache?", "o": ["Nur in Deutschland", "In Deutschland, Österreich und der Schweiz", "In ganz Europa"], "c": 1, "e": "Il testo cita Deutschland, Österreich und die Schweiz."}, {"q": "Warum lernen viele Menschen Deutsch für die Arbeit?", "o": ["Weil es leicht ist", "Weil Deutschland Fachkräfte sucht", "Weil es Pflicht ist"], "c": 1, "e": "„Deutschland … sucht viele Fachkräfte\"."}], "news": "Deutsch lernen Gründe"}, "dialog": {"title": "Im Sprachkurs — Erstes Treffen", "lines": [{"who": "Lehrer", "de": "Guten Morgen! Willkommen im Deutschkurs. Wie heißen Sie?"}, {"who": "Marco", "de": "Guten Morgen. Ich heiße Marco Rossi."}, {"who": "Lehrer", "de": "Freut mich, Marco. Und woher kommen Sie?"}, {"who": "Marco", "de": "Ich komme aus Italien, aus Mailand."}, {"who": "Lehrer", "de": "Sehr schön. Sprechen Sie schon ein bisschen Deutsch?"}, {"who": "Marco", "de": "Ein bisschen. Ich lerne seit drei Wochen."}, {"who": "Lehrer", "de": "Das ist gut! Und warum lernen Sie Deutsch?"}, {"who": "Marco", "de": "Ich möchte in Deutschland arbeiten. Ich bin Ingenieur."}, {"who": "Lehrer", "de": "Perfekt. Dann fangen wir an. Setzen Sie sich, bitte."}], "q": [{"q": "Woher kommt Marco?", "o": ["Aus Rom", "Aus Mailand", "Aus Berlin"], "c": 1, "e": "„aus Italien, aus Mailand\"."}, {"q": "Seit wann lernt er Deutsch?", "o": ["Seit drei Wochen", "Seit drei Jahren", "Seit drei Tagen"], "c": 0, "e": "„seit drei Wochen\"."}, {"q": "Was ist Marco von Beruf?", "o": ["Lehrer", "Ingenieur", "Student"], "c": 1, "e": "„Ich bin Ingenieur\"."}]}, "musik": {"key": "bendzko", "task": "Ascolto guidato: la canzone parla di una persona molto occupata che ripete „Muss nur noch kurz die Welt retten\". Conta quante volte senti la parola „nur\" (solo). È un brano lento e con pronuncia chiarissima: ideale per i primi ascolti.", "level": "Pronuncia molto chiara · A1–A2"}, "sprechen": {"read": "Hallo! Ich heiße Marco. Ich komme aus Italien und ich wohne jetzt in Berlin. Ich lerne Deutsch, weil ich hier arbeiten möchte. Deutsch ist nicht leicht, aber ich übe jeden Tag.", "prompts": [{"q": "Wie heißt du und woher kommst du?", "e": "Ich heiße … und ich komme aus …"}, {"q": "Warum lernst du Deutsch?", "e": "Ich lerne Deutsch, weil …"}, {"q": "Was machst du gern in deiner Freizeit?", "e": "In meiner Freizeit … ich gern …"}], "scenario": "Du triffst einen neuen Nachbarn im Treppenhaus. Stell dich vor und frag ihn, woher er kommt."}, "grammatik": {"titel": "Die Verben „sein\" und „haben\" im Präsens", "regel_html": "<p>I due verbi più importanti del tedesco sono <b>sein</b> (essere) e <b>haben</b> (avere). Sono irregolari, quindi vanno imparati a memoria. Si usano da soli e anche per formare il passato.</p><table class='gtab'><tr><th></th><th>sein</th><th>haben</th></tr><tr><td>ich</td><td>bin</td><td>habe</td></tr><tr><td>du</td><td>bist</td><td>hast</td></tr><tr><td>er/sie/es</td><td>ist</td><td>hat</td></tr><tr><td>wir</td><td>sind</td><td>haben</td></tr><tr><td>ihr</td><td>seid</td><td>habt</td></tr><tr><td>sie/Sie</td><td>sind</td><td>haben</td></tr></table><p><b>Esempi:</b> <i>Ich <u>bin</u> müde.</i> (Sono stanco.) · <i>Du <u>hast</u> Zeit.</i> (Hai tempo.) · <i>Wir <u>sind</u> Freunde.</i> (Siamo amici.)</p><p>💡 Attenzione: in italiano dici „ho 23 anni\", ma in tedesco si usa <b>sein</b>: <i>Ich <u>bin</u> 23 Jahre alt.</i></p>", "ex": [{"l": "Ich ", "r": " Student.", "o": ["bin", "bist", "ist", "sind"], "c": 0, "e": "<b>ich bin</b> = io sono."}, {"l": "Wie alt ", "r": " du?", "o": ["bin", "bist", "hat", "seid"], "c": 1, "e": "<b>du bist</b>; per l'età si usa sein."}, {"l": "Wir ", "r": " heute keine Zeit.", "o": ["habt", "hat", "haben", "habe"], "c": 2, "e": "<b>wir haben</b> = noi abbiamo."}, {"l": "Meine Eltern ", "r": " in Italien.", "o": ["ist", "bin", "sind", "seid"], "c": 2, "e": "<b>sie sind</b> (loro) = i miei genitori sono."}]}, "wortschatz": [{"de": "der Name", "it": "il nome", "exde": "Mein Name ist Lena.", "exit": "Il mio nome è Lena."}, {"de": "wohnen", "it": "abitare", "exde": "Ich wohne in Berlin.", "exit": "Abito a Berlino."}, {"de": "kommen aus", "it": "venire da", "exde": "Ich komme aus Italien.", "exit": "Vengo dall'Italia."}, {"de": "lernen", "it": "imparare", "exde": "Wir lernen Deutsch.", "exit": "Impariamo il tedesco."}, {"de": "die Sprache", "it": "la lingua", "exde": "Deutsch ist eine schöne Sprache.", "exit": "Il tedesco è una bella lingua."}, {"de": "der Freund", "it": "l'amico", "exde": "Er ist mein bester Freund.", "exit": "È il mio migliore amico."}, {"de": "arbeiten", "it": "lavorare", "exde": "Ich möchte in Deutschland arbeiten.", "exit": "Voglio lavorare in Germania."}, {"de": "die Stadt", "it": "la città", "exde": "Berlin ist eine große Stadt.", "exit": "Berlino è una grande città."}, {"de": "der Tag", "it": "il giorno", "exde": "Jeden Tag lerne ich etwas Neues.", "exit": "Ogni giorno imparo qualcosa di nuovo."}, {"de": "der Fehler", "it": "l'errore", "exde": "Ich mache noch viele Fehler.", "exit": "Faccio ancora molti errori."}, {"de": "die Freizeit", "it": "il tempo libero", "exde": "In der Freizeit lese ich gern.", "exit": "Nel tempo libero leggo volentieri."}, {"de": "schwer", "it": "difficile", "exde": "Die Grammatik ist schwer.", "exit": "La grammatica è difficile."}], "idiome": [{"de": "Aller Anfang ist schwer.", "lit": "Ogni inizio è difficile.", "mean": "Le prime volte sono sempre faticose; non scoraggiarti.", "it": "Chi ben comincia è a metà dell'opera (≈).", "exde": "Keine Sorge, aller Anfang ist schwer!", "exit": "Tranquillo, ogni inizio è difficile!"}, {"de": "Übung macht den Meister.", "lit": "L'esercizio fa il maestro.", "mean": "Con la pratica costante si diventa bravi.", "it": "La pratica rende perfetti.", "exde": "Sprich jeden Tag — Übung macht den Meister.", "exit": "Parla ogni giorno: la pratica rende perfetti."}], "schreiben": {"impuls": "Schreib einen kurzen Steckbrief über dich (3–5 Sätze): Name, Alter, Herkunft, Wohnort und warum du Deutsch lernst.", "fragen": ["Was ist dein wichtigstes Ziel mit der deutschen Sprache?", "Was fällt dir am Deutschen am schwersten — und warum?"]}, "freunde": [{"de": "die Familie", "it": "famiglia / family"}, {"de": "das Hotel", "it": "hotel"}, {"de": "der Computer", "it": "computer"}, {"de": "die Musik", "it": "musica / music"}, {"de": "das Problem", "it": "problema / problem"}, {"de": "die Idee", "it": "idea"}], "falsch": [{"de": "bekommen", "it": "ricevere", "warn": "NON „diventare\" (to become)"}, {"de": "das Gift", "it": "il veleno", "warn": "NON „regalo\" (gift)"}, {"de": "der Chef", "it": "il capo", "warn": "NON il cuoco (= der Koch)"}, {"de": "kalt", "it": "freddo", "warn": "NON „caldo\": è l'opposto!"}, {"de": "die Firma", "it": "la ditta / azienda", "warn": "NON la firma (= die Unterschrift)"}], "lit": {"de": "Es irrt der Mensch, solang er strebt.", "it": "Finché l'uomo cerca, egli erra.", "src": "J. W. Goethe, Faust"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Ich bin Italiener und ich habe zwei Geschwister.", "it": "Sono italiano e ho due fratelli."}, {"de": "Bist du müde? — Nein, ich bin fit!", "it": "Sei stanco? — No, sono in forma!"}], "song1": {"id": "4BAKb2p450Q", "artist": "Tim Bendzko", "titel": "Nur noch kurz die Welt retten"}, "song2": {"id": "BgWgufeKUgU", "artist": "Giovanni Zarrella feat. Pietro Lombardi", "titel": "Senza te", "original": "Cover italo-tedesca di „Ohne dich\" (Münchner Freiheit)."}, "articles": [{"title": "Wikipedia: Begr%C3%BC%C3%9Fung", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Begr%C3%BC%C3%9Fung"}, {"title": "Klexikon: H%C3%B6flichkeit (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/H%C3%B6flichkeit"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Familie & Menschen — Famiglia e persone", "level": "A1", "lesen": {"title": "Meine Familie", "text": "Ich möchte euch meine Familie vorstellen. Wir sind fünf Personen. Mein Vater heißt Paolo und arbeitet als Lehrer an einer Schule. Meine Mutter, Giulia, ist Ärztin und arbeitet im Krankenhaus. Ich habe auch einen älteren Bruder und eine jüngere Schwester. Mein Bruder Luca ist fünfundzwanzig und studiert noch. Meine Schwester Sofia ist erst zwölf und geht in die Schule. Wir wohnen zusammen in einem alten Haus mit einem schönen Garten. Am Wochenende essen wir oft zusammen zu Mittag. Meine Großeltern wohnen nicht weit weg und besuchen uns fast jeden Sonntag. Meine Familie ist mir sehr wichtig, auch wenn wir uns manchmal streiten.", "glos": {"vorstellen": "presentare", "Personen": "persone", "Vater": "padre", "arbeitet": "lavora", "Lehrer": "insegnante", "Schule": "scuola", "Mutter": "madre", "Ärztin": "dottoressa", "Krankenhaus": "ospedale", "älteren": "più grande", "Bruder": "fratello", "jüngere": "più giovane", "Schwester": "sorella", "studiert": "studia", "Haus": "casa", "Garten": "giardino", "Wochenende": "fine settimana", "Mittag": "mezzogiorno/pranzo", "Großeltern": "nonni", "besuchen": "visitano", "wichtig": "importante", "streiten": "litigare"}, "q": [{"q": "Was ist die Mutter von Beruf?", "o": ["Lehrerin", "Ärztin", "Studentin"], "c": 1, "e": "„Meine Mutter … ist Ärztin\"."}, {"q": "Wie alt ist die Schwester?", "o": ["Zwölf", "Fünfundzwanzig", "Zwanzig"], "c": 0, "e": "„Meine Schwester Sofia ist erst zwölf\"."}, {"q": "Wann kommen die Großeltern oft?", "o": ["Jeden Samstag", "Fast jeden Sonntag", "Nie"], "c": 1, "e": "„fast jeden Sonntag\"."}], "frage": "Beschreib deine Familie: Wie viele seid ihr und was machen sie beruflich?"}, "artikel": {"title": "Wie wohnen Familien in Deutschland heute?", "text": "Die klassische Familie mit Vater, Mutter und zwei Kindern ist in Deutschland nicht mehr die Regel. Heute gibt es viele verschiedene Formen des Zusammenlebens. Viele Paare heiraten später oder gar nicht. Es gibt mehr Alleinerziehende, also Mütter oder Väter, die allein mit ihren Kindern leben. Auch Patchwork-Familien sind häufig: Hier bringen beide Partner Kinder aus früheren Beziehungen mit. In den großen Städten leben außerdem viele Menschen in Wohngemeinschaften, kurz „WG\". Sie teilen sich eine Wohnung, die Küche und oft auch das Bad. Eins bleibt aber gleich: Die meisten Menschen wünschen sich Nähe, Vertrauen und Menschen, die für sie da sind.", "glos": {"klassische": "classica", "Regel": "regola", "verschiedene": "diverse", "Zusammenlebens": "del convivere", "Paare": "coppie", "heiraten": "sposarsi", "später": "più tardi", "Alleinerziehende": "genitori single", "leben": "vivono", "häufig": "frequenti", "früheren": "precedenti", "Beziehungen": "relazioni", "Wohngemeinschaften": "appartamenti condivisi", "teilen": "condividono", "Küche": "cucina", "Bad": "bagno", "wünschen": "desiderano", "Nähe": "vicinanza", "Vertrauen": "fiducia"}, "q": [{"q": "Was ist heute NICHT mehr die Regel?", "o": ["Die WG", "Die klassische Familie mit zwei Kindern", "Die Patchwork-Familie"], "c": 1, "e": "„Die klassische Familie … ist … nicht mehr die Regel\"."}, {"q": "Was teilen Menschen in einer WG?", "o": ["Nur das Geld", "Wohnung, Küche und oft das Bad", "Nichts"], "c": 1, "e": "„Sie teilen sich eine Wohnung, die Küche …\"."}], "news": "Familie Deutschland Formen Zusammenleben"}, "dialog": {"title": "Fotos von der Familie", "lines": [{"who": "Anna", "de": "Oh, ist das ein Foto von deiner Familie?"}, {"who": "Ben", "de": "Ja, genau. Das hier sind meine Eltern."}, {"who": "Anna", "de": "Und wer ist der Mann neben deiner Mutter?"}, {"who": "Ben", "de": "Das ist mein Onkel. Er wohnt in Hamburg."}, {"who": "Anna", "de": "Hast du auch Geschwister?"}, {"who": "Ben", "de": "Ja, eine Schwester. Sie ist hier, links."}, {"who": "Anna", "de": "Sie sieht nett aus. Wie alt ist sie?"}, {"who": "Ben", "de": "Sie ist neunzehn und studiert Medizin."}, {"who": "Anna", "de": "Eine schöne Familie! Und der Hund?"}, {"who": "Ben", "de": "Das ist Rocky. Er gehört auch zur Familie!"}], "q": [{"q": "Wer wohnt in Hamburg?", "o": ["Bens Vater", "Bens Onkel", "Bens Schwester"], "c": 1, "e": "„Das ist mein Onkel. Er wohnt in Hamburg\"."}, {"q": "Was studiert Bens Schwester?", "o": ["Medizin", "Kunst", "Musik"], "c": 0, "e": "„… und studiert Medizin\"."}, {"q": "Wer ist Rocky?", "o": ["Ein Freund", "Der Hund", "Der Onkel"], "c": 1, "e": "„Das ist Rocky\" — der Hund."}]}, "musik": {"key": "helden", "task": "„Nur ein Wort\" gioca con i verbi sehen, denken, fühlen, wollen, hören. Mentre ascolti, prova a riconoscere questi verbi. Il ritornello chiede „Gib mir ein Wort\" (dammi una parola). Testo chiaro e ripetitivo: ottimo per principianti.", "level": "Ritmo medio · A2"}, "sprechen": {"read": "Das ist meine Familie. Wir sind vier Personen: mein Vater, meine Mutter, mein Bruder und ich. Mein Vater arbeitet als Lehrer und meine Mutter ist Ärztin. Wir wohnen zusammen in einem Haus mit Garten.", "prompts": [{"q": "Wie viele Personen seid ihr in deiner Familie?", "e": "Wir sind … Personen."}, {"q": "Hast du Geschwister?", "e": "Ja, ich habe … / Nein, ich bin Einzelkind."}, {"q": "Was machen deine Eltern beruflich?", "e": "Mein Vater ist … und meine Mutter ist …"}], "scenario": "Zeig einem Freund ein Familienfoto und erklär, wer die Personen sind."}, "grammatik": {"titel": "Possessivartikel: mein, dein, sein, ihr …", "regel_html": "<p>I <b>possessivi</b> indicano a chi appartiene qualcosa. Si comportano come l'articolo indeterminativo <i>ein/eine</i> e prendono la desinenza <b>-e</b> davanti a nomi femminili e plurali.</p><table class='gtab'><tr><th>persona</th><th>+ nome masch./neutro</th><th>+ nome femm./plur.</th></tr><tr><td>ich</td><td>mein Vater</td><td>meine Mutter</td></tr><tr><td>du</td><td>dein Bruder</td><td>deine Schwester</td></tr><tr><td>er</td><td>sein Hund</td><td>seine Familie</td></tr><tr><td>sie</td><td>ihr Sohn</td><td>ihre Tochter</td></tr><tr><td>wir</td><td>unser Haus</td><td>unsere Eltern</td></tr></table><p><b>Esempi:</b> <i>Das ist <u>mein</u> Bruder.</i> · <i>Wo ist <u>deine</u> Schwester?</i> · <i><u>Ihre</u> Großeltern wohnen in Rom.</i></p><p>💡 Attento alla differenza tra <b>ihr</b> (suo, di lei / loro) e <b>sein</b> (suo, di lui).</p>", "ex": [{"l": "Das ist ", "r": " Vater. (io)", "o": ["meine", "mein", "dein", "seine"], "c": 1, "e": "<b>mein Vater</b> (maschile)."}, {"l": "Wo wohnt ", "r": " Schwester? (tu)", "o": ["dein", "deine", "ihre", "sein"], "c": 1, "e": "<b>deine Schwester</b> (femminile → -e)."}, {"l": "Anna liebt ", "r": " Hund. (lei)", "o": ["sein", "ihren", "ihr", "seine"], "c": 2, "e": "<b>ihr Hund</b> (di lei, maschile)."}, {"l": "Das ist ", "r": " Haus. (noi)", "o": ["unsere", "unser", "euer", "mein"], "c": 1, "e": "<b>unser Haus</b> (neutro)."}]}, "wortschatz": [{"de": "die Familie", "it": "la famiglia", "exde": "Meine Familie ist groß.", "exit": "La mia famiglia è grande."}, {"de": "die Eltern", "it": "i genitori", "exde": "Meine Eltern wohnen in Rom.", "exit": "I miei genitori abitano a Roma."}, {"de": "der Bruder", "it": "il fratello", "exde": "Mein Bruder ist älter als ich.", "exit": "Mio fratello è più grande di me."}, {"de": "die Schwester", "it": "la sorella", "exde": "Ich habe eine kleine Schwester.", "exit": "Ho una sorella piccola."}, {"de": "der Sohn", "it": "il figlio", "exde": "Ihr Sohn heißt Tim.", "exit": "Suo figlio si chiama Tim."}, {"de": "die Tochter", "it": "la figlia", "exde": "Ihre Tochter ist drei.", "exit": "Sua figlia ha tre anni."}, {"de": "die Großeltern", "it": "i nonni", "exde": "Meine Großeltern sind nett.", "exit": "I miei nonni sono gentili."}, {"de": "der Onkel", "it": "lo zio", "exde": "Mein Onkel wohnt in Hamburg.", "exit": "Mio zio abita ad Amburgo."}, {"de": "heiraten", "it": "sposarsi", "exde": "Sie wollen im Sommer heiraten.", "exit": "Vogliono sposarsi in estate."}, {"de": "der Beruf", "it": "la professione", "exde": "Was ist dein Beruf?", "exit": "Qual è la tua professione?"}, {"de": "zusammen", "it": "insieme", "exde": "Wir essen zusammen.", "exit": "Mangiamo insieme."}, {"de": "wichtig", "it": "importante", "exde": "Familie ist mir wichtig.", "exit": "La famiglia è importante per me."}], "idiome": [{"de": "Blut ist dicker als Wasser.", "lit": "Il sangue è più denso dell'acqua.", "mean": "I legami familiari contano più di tutto.", "it": "Il sangue non è acqua.", "exde": "Am Ende hilft die Familie — Blut ist dicker als Wasser.", "exit": "Alla fine la famiglia aiuta: il sangue non è acqua."}, {"de": "Der Apfel fällt nicht weit vom Stamm.", "lit": "La mela non cade lontano dal tronco.", "mean": "I figli somigliano ai genitori.", "it": "La mela non cade lontano dall'albero.", "exde": "Er kocht wie sein Vater — der Apfel fällt nicht weit vom Stamm.", "exit": "Cucina come suo padre: tale padre, tale figlio."}], "schreiben": {"impuls": "Beschreib deine Familie in 4–6 Sätzen. Wer gehört dazu? Was machen sie? Wie ist euer Verhältnis?", "fragen": ["Wer in deiner Familie hat dich am meisten geprägt — und wie?", "Wie stellst du dir deine eigene Familie in zehn Jahren vor?"]}, "freunde": [{"de": "das Problem", "it": "problema / problem"}, {"de": "die Idee", "it": "idea"}, {"de": "der Moment", "it": "momento"}, {"de": "die Natur", "it": "natura / nature"}, {"de": "die Information", "it": "informazione"}, {"de": "die Situation", "it": "situazione"}], "falsch": [{"de": "kalt", "it": "freddo", "warn": "NON „caldo\": è l'opposto!"}, {"de": "die Firma", "it": "la ditta / azienda", "warn": "NON la firma (= die Unterschrift)"}, {"de": "das Regal", "it": "lo scaffale", "warn": "NON il regalo (= das Geschenk)"}, {"de": "eventuell", "it": "forse / se necessario", "warn": "NON „eventually\" (= schließlich)"}, {"de": "das Handy", "it": "il cellulare", "warn": "NON „handy / pratico\""}], "lit": {"de": "Was mich nicht umbringt, macht mich stärker.", "it": "Ciò che non mi uccide mi rende più forte.", "src": "F. Nietzsche"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [{"de": "Das ist mein Bruder und das ist seine Frau.", "it": "Questo è mio fratello e questa è sua moglie."}, {"de": "Wie heißt deine Mutter?", "it": "Come si chiama tua madre?"}], "song1": {"id": "X5kmM98iklo", "artist": "Wir sind Helden", "titel": "Nur ein Wort"}, "song2": {"id": "jP4-XrbGt3M", "artist": "Mark Forster", "titel": "Sowieso"}, "articles": [{"title": "Wikipedia: Familie", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Familie"}, {"title": "Klexikon: Familie (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Familie"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Essen & Trinken — Cibo e bevande", "level": "A1", "lesen": {"title": "Frühstück, Mittag und Abend", "text": "In Deutschland ist das Frühstück oft die wichtigste Mahlzeit des Tages. Viele Menschen essen morgens Brot oder Brötchen mit Butter, Käse, Wurst oder Marmelade. Dazu trinken sie Kaffee oder Tee. Zu Mittag gibt es traditionell eine warme Mahlzeit, zum Beispiel Kartoffeln mit Gemüse und Fleisch oder Fisch. Am Abend essen viele Familien dann kalt — das nennt man „Abendbrot\": Brot mit Käse und Wurst. Heute ändern sich diese Gewohnheiten aber. Junge Leute essen mittags oft schnell in der Kantine oder im Café, und am Abend kochen sie warm. Auch internationale Küche ist sehr beliebt: Pizza, Sushi und Döner gehören für viele längst zum Alltag.", "glos": {"Frühstück": "colazione", "wichtigste": "più importante", "Mahlzeit": "pasto", "morgens": "di mattina", "Brot": "pane", "Brötchen": "panino", "Butter": "burro", "Käse": "formaggio", "Wurst": "salume/würstel", "Marmelade": "marmellata", "Mittag": "pranzo/mezzogiorno", "warme": "calda", "Kartoffeln": "patate", "Gemüse": "verdura", "Fleisch": "carne", "Fisch": "pesce", "Abend": "sera", "kalt": "freddo", "Gewohnheiten": "abitudini", "Kantine": "mensa", "beliebt": "popolare", "Alltag": "vita quotidiana"}, "q": [{"q": "Was ist oft die wichtigste Mahlzeit?", "o": ["Das Mittagessen", "Das Frühstück", "Das Abendbrot"], "c": 1, "e": "„das Frühstück … die wichtigste Mahlzeit\"."}, {"q": "Was bedeutet „Abendbrot\"?", "o": ["Eine warme Suppe", "Kalt essen am Abend", "Ein Restaurantbesuch"], "c": 1, "e": "„am Abend … kalt — das nennt man Abendbrot\"."}, {"q": "Was ist heute auch sehr beliebt?", "o": ["Nur deutsches Essen", "Internationale Küche", "Gar kein Essen"], "c": 1, "e": "„Auch internationale Küche ist sehr beliebt\"."}], "frage": "Wie sieht ein typischer Esstag bei dir aus? Was isst du morgens, mittags und abends?"}, "artikel": {"title": "Brot: das Lieblingsessen der Deutschen", "text": "Es gibt wohl kein Land, das so viele Brotsorten kennt wie Deutschland. Über dreihundert verschiedene Sorten stehen in den Bäckereien: helles Brot, dunkles Brot, Brot mit Körnern oder mit Nüssen. Das deutsche Brot ist sogar offiziell ein Teil des Kulturerbes. Für viele Deutsche, die im Ausland leben, ist Brot das, was sie am meisten vermissen. „Das Brot dort schmeckt einfach nicht wie zu Hause\", sagen sie oft. In jeder Stadt gibt es viele kleine Bäckereien, und am Sonntagmorgen ist der Geruch von frischen Brötchen für viele ein kleines Stück Glück. Doch es gibt ein Problem: Immer mehr kleine Bäckereien schließen, weil große Supermärkte billiger sind.", "glos": {"Land": "paese", "Brotsorten": "tipi di pane", "Bäckereien": "panetterie", "helles": "chiaro", "dunkles": "scuro", "Körnern": "semi/cereali", "Nüssen": "noci", "Kulturerbes": "patrimonio culturale", "vermissen": "sentire la mancanza", "schmeckt": "sa di / ha sapore", "Geruch": "odore", "frischen": "freschi", "Glück": "felicità", "Problem": "problema", "schließen": "chiudono", "billiger": "più economici"}, "q": [{"q": "Wie viele Brotsorten gibt es ungefähr?", "o": ["Etwa 30", "Über 300", "Genau 100"], "c": 1, "e": "„Über dreihundert verschiedene Sorten\"."}, {"q": "Warum schließen kleine Bäckereien?", "o": ["Niemand isst Brot", "Große Supermärkte sind billiger", "Es gibt kein Mehl"], "c": 1, "e": "„weil große Supermärkte billiger sind\"."}], "news": "deutsches Brot Bäckerei Kultur"}, "dialog": {"title": "Im Café bestellen", "lines": [{"who": "Kellner", "de": "Guten Tag! Was möchten Sie bestellen?"}, {"who": "Gast", "de": "Hallo. Ich hätte gern einen Kaffee, bitte."}, {"who": "Kellner", "de": "Gern. Mit Milch und Zucker?"}, {"who": "Gast", "de": "Nur mit Milch, danke. Und haben Sie Kuchen?"}, {"who": "Kellner", "de": "Ja, wir haben Apfelkuchen und Käsekuchen."}, {"who": "Gast", "de": "Dann nehme ich ein Stück Apfelkuchen."}, {"who": "Kellner", "de": "Sehr gern. Möchten Sie sonst noch etwas?"}, {"who": "Gast", "de": "Nein danke, das ist alles. Was macht das?"}, {"who": "Kellner", "de": "Das macht zusammen sechs Euro fünfzig."}, {"who": "Gast", "de": "Hier, bitte. Stimmt so."}], "q": [{"q": "Was bestellt der Gast zu trinken?", "o": ["Tee", "Kaffee mit Milch", "Wasser"], "c": 1, "e": "„einen Kaffee … nur mit Milch\"."}, {"q": "Welchen Kuchen nimmt der Gast?", "o": ["Käsekuchen", "Apfelkuchen", "Keinen"], "c": 1, "e": "„ein Stück Apfelkuchen\"."}, {"q": "Wie viel kostet alles zusammen?", "o": ["6,50 €", "5,60 €", "16 €"], "c": 0, "e": "„sechs Euro fünfzig\"."}]}, "musik": {"key": "fox", "task": "„Haus am See\" racconta il sogno di una vita semplice e felice in una casa vicino al lago. Ascolta il ritornello e prova a cogliere la parola „See\" (lago) e „Kinder\" (bambini). Ritmo reggae rilassato.", "level": "B1 · ritmo calmo"}, "sprechen": {"read": "Zum Frühstück esse ich gern Brot mit Marmelade und ich trinke einen Kaffee. Mittags koche ich oft Pasta mit Gemüse. Am Abend esse ich etwas Leichtes, zum Beispiel einen Salat.", "prompts": [{"q": "Was isst du gern zum Frühstück?", "e": "Zum Frühstück esse ich gern …"}, {"q": "Kochst du gern? Was ist dein Lieblingsgericht?", "e": "Ja/Nein … Mein Lieblingsgericht ist …"}, {"q": "Was bestellst du normalerweise im Café?", "e": "Im Café bestelle ich meistens …"}], "scenario": "Du bist im Café. Bestell ein Getränk und etwas zu essen und frag nach dem Preis."}, "grammatik": {"titel": "Der Akkusativ: den, einen … (complemento oggetto)", "regel_html": "<p>L'<b>accusativo</b> è il caso del complemento oggetto (chi/che cosa?). In tedesco cambia soprattutto il <b>maschile</b>: <i>der → den</i>, <i>ein → einen</i>. Femminile, neutro e plurale restano uguali al nominativo.</p><table class='gtab'><tr><th></th><th>maschile</th><th>femminile</th><th>neutro</th><th>plurale</th></tr><tr><td>Nominativo</td><td>der / ein</td><td>die / eine</td><td>das / ein</td><td>die / –</td></tr><tr><td>Accusativo</td><td><b>den / einen</b></td><td>die / eine</td><td>das / ein</td><td>die / –</td></tr></table><p><b>Esempi:</b> <i>Ich trinke <u>einen</u> Kaffee.</i> · <i>Ich esse <u>den</u> Apfel.</i> · <i>Ich nehme <u>eine</u> Suppe.</i> (femm., invariato) · <i>Ich möchte <u>ein</u> Brötchen.</i></p><p>💡 Verbi tipici con l'accusativo: <i>essen, trinken, nehmen, kaufen, haben, möchten</i>.</p>", "ex": [{"l": "Ich trinke ", "r": " Kaffee.", "o": ["ein", "einen", "einem", "der"], "c": 1, "e": "<b>einen Kaffee</b> (maschile, accusativo)."}, {"l": "Sie isst ", "r": " Suppe.", "o": ["einen", "ein", "eine", "der"], "c": 2, "e": "<b>eine Suppe</b> (femminile, invariato)."}, {"l": "Wir nehmen ", "r": " Apfelkuchen.", "o": ["den", "dem", "der", "das"], "c": 0, "e": "<b>den Apfelkuchen</b> (maschile → den)."}, {"l": "Hast du ", "r": " Brötchen?", "o": ["einen", "eine", "ein", "einem"], "c": 2, "e": "<b>ein Brötchen</b> (neutro, invariato)."}]}, "wortschatz": [{"de": "das Frühstück", "it": "la colazione", "exde": "Das Frühstück ist fertig.", "exit": "La colazione è pronta."}, {"de": "das Brot", "it": "il pane", "exde": "Ich kaufe frisches Brot.", "exit": "Compro pane fresco."}, {"de": "der Käse", "it": "il formaggio", "exde": "Der Käse riecht stark.", "exit": "Il formaggio ha un odore forte."}, {"de": "das Fleisch", "it": "la carne", "exde": "Ich esse wenig Fleisch.", "exit": "Mangio poca carne."}, {"de": "das Gemüse", "it": "la verdura", "exde": "Gemüse ist gesund.", "exit": "La verdura fa bene."}, {"de": "der Kaffee", "it": "il caffè", "exde": "Ein Kaffee, bitte.", "exit": "Un caffè, per favore."}, {"de": "essen", "it": "mangiare", "exde": "Was möchtest du essen?", "exit": "Cosa vuoi mangiare?"}, {"de": "trinken", "it": "bere", "exde": "Ich trinke viel Wasser.", "exit": "Bevo molta acqua."}, {"de": "kochen", "it": "cucinare", "exde": "Heute koche ich Pasta.", "exit": "Oggi cucino la pasta."}, {"de": "bestellen", "it": "ordinare", "exde": "Wir bestellen eine Pizza.", "exit": "Ordiniamo una pizza."}, {"de": "lecker", "it": "gustoso", "exde": "Das Essen ist lecker.", "exit": "Il cibo è gustoso."}, {"de": "der Hunger", "it": "la fame", "exde": "Ich habe großen Hunger.", "exit": "Ho molta fame."}], "idiome": [{"de": "Der Hunger ist der beste Koch.", "lit": "La fame è il miglior cuoco.", "mean": "Quando hai fame, tutto sembra buono.", "it": "L'appetito è il miglior condimento.", "exde": "Probier mal — Hunger ist der beste Koch!", "exit": "Assaggia: la fame è il miglior cuoco!"}, {"de": "Das ist mir Wurst.", "lit": "Per me è salame.", "mean": "Non mi importa, mi è indifferente.", "it": "Per me fa lo stesso.", "exde": "Pizza oder Pasta? Das ist mir Wurst.", "exit": "Pizza o pasta? Per me fa lo stesso."}], "schreiben": {"impuls": "Beschreib dein Lieblingsgericht: Was ist es, was kommt hinein, und wann isst du es?", "fragen": ["Essen ist auch Kultur. Was sagt das typische Essen über ein Land aus?", "Würdest du lieber jeden Tag dein Lieblingsgericht essen oder immer etwas Neues probieren? Warum?"]}, "freunde": [{"de": "die Information", "it": "informazione"}, {"de": "die Situation", "it": "situazione"}, {"de": "das Telefon", "it": "telefono"}, {"de": "die Universität", "it": "università"}, {"de": "der Tourist", "it": "turista"}, {"de": "das Restaurant", "it": "ristorante"}], "falsch": [{"de": "eventuell", "it": "forse / se necessario", "warn": "NON „eventually\" (= schließlich)"}, {"de": "das Handy", "it": "il cellulare", "warn": "NON „handy / pratico\""}, {"de": "die Kantine", "it": "la mensa", "warn": "NON la cantina (= der Keller)"}, {"de": "die Note", "it": "il voto / la nota musicale", "warn": "NON la notte (= die Nacht)"}, {"de": "die Art", "it": "il tipo / il modo", "warn": "NON l'arte (= die Kunst)"}], "lit": {"de": "Wo man Bücher verbrennt, verbrennt man am Ende auch Menschen.", "it": "Dove si bruciano i libri, alla fine si bruciano anche gli uomini.", "src": "H. Heine, Almansor"}, "trad": {"id": "gedanken", "title": "Die Gedanken sind frei", "artist": "Volkslied", "note": "Canto popolare sulla libertà di pensiero, amatissimo in Germania.", "ytq": "Die Gedanken sind frei Lied", "de": ["Die Gedanken sind frei,", "wer kann sie erraten?", "Sie fliehen vorbei", "wie nächtliche Schatten.", "Kein Mensch kann sie wissen,", "kein Jäger erschießen;", "es bleibet dabei:", "die Gedanken sind frei!"], "it": ["I pensieri sono liberi,", "chi può indovinarli?", "Volano via", "come ombre nella notte.", "Nessuno può conoscerli,", "nessun cacciatore può abbatterli;", "resta così:", "i pensieri sono liberi!"]}, "voice": {"id": "kRq3WzSwUw0", "t": "Straßeninterviews in Magdeburg", "note": "Ascolto autentico con sottotitoli tedeschi."}, "gram_extra": [{"de": "Ich kaufe einen Apfel und eine Banane.", "it": "Compro una mela e una banana."}, {"de": "Nimmst du den Kuchen oder das Eis?", "it": "Prendi la torta o il gelato?"}], "song1": {"id": "1il3RFk5Okw", "artist": "Mark Forster", "titel": "Chöre"}, "song2": {"id": "Vf0MC3CFihY", "artist": "Revolverheld", "titel": "Ich lass für dich das Licht an"}, "articles": [{"title": "Wikipedia: Brot", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Brot"}, {"title": "Klexikon: Brot (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Brot"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Stadt & Wege — Città e orientarsi", "level": "A1", "lesen": {"title": "Ein Tag in der Stadt", "text": "Heute habe ich frei, also fahre ich in die Stadt. Ich nehme die U-Bahn, weil das Auto in der Innenstadt nur Stress bedeutet. Mein erster Halt ist die Bibliothek, dort gebe ich zwei Bücher zurück. Danach gehe ich zu Fuß weiter zum Markt. Auf dem Markt kaufe ich frisches Obst und Blumen für meine Wohnung. Die Sonne scheint, und überall sitzen Menschen in den Cafés. Am Nachmittag treffe ich eine Freundin vor dem Museum. Wir schauen uns eine Ausstellung an und reden über Kunst. Am Abend bin ich müde, aber zufrieden. Eine Stadt zu Fuß zu entdecken ist für mich das Schönste am Wochenende.", "glos": {"frei": "libero (giorno)", "U-Bahn": "metropolitana", "Innenstadt": "centro", "Halt": "fermata", "Bibliothek": "biblioteca", "Bücher": "libri", "zurück": "indietro", "Fuß": "piedi", "Markt": "mercato", "Obst": "frutta", "Blumen": "fiori", "Wohnung": "appartamento", "Sonne": "sole", "scheint": "splende", "Nachmittag": "pomeriggio", "treffe": "incontro", "Museum": "museo", "Ausstellung": "mostra", "reden": "parlare", "müde": "stanco", "zufrieden": "soddisfatto", "entdecken": "scoprire"}, "q": [{"q": "Womit fährt die Person in die Stadt?", "o": ["Mit dem Auto", "Mit der U-Bahn", "Mit dem Fahrrad"], "c": 1, "e": "„Ich nehme die U-Bahn\"."}, {"q": "Was kauft sie auf dem Markt?", "o": ["Bücher", "Obst und Blumen", "Kleidung"], "c": 1, "e": "„frisches Obst und Blumen\"."}, {"q": "Wo trifft sie ihre Freundin?", "o": ["Im Café", "Vor dem Museum", "Am Bahnhof"], "c": 1, "e": "„vor dem Museum\"."}], "frage": "Wie verbringst du am liebsten einen freien Tag in der Stadt?"}, "artikel": {"title": "Warum viele Deutsche das Fahrrad lieben", "text": "In vielen deutschen Städten gehört das Fahrrad einfach dazu. Morgens fahren Tausende Menschen mit dem Rad zur Arbeit, oft auch bei Regen oder Kälte. Das hat mehrere Gründe. Erstens ist das Fahrrad günstig: Man braucht kein Benzin und keinen teuren Parkplatz. Zweitens ist es gut für die Gesundheit und für die Umwelt. Und drittens ist man in der Stadt mit dem Rad oft schneller als mit dem Auto. Viele Städte bauen darum immer mehr Radwege. In Münster zum Beispiel gibt es fast mehr Fahrräder als Einwohner. Natürlich gibt es auch Probleme: Im Winter ist es kalt, und nicht jeder Radweg ist sicher. Trotzdem bleibt das Fahrrad für viele das liebste Verkehrsmittel.", "glos": {"Fahrrad": "bicicletta", "Rad": "bici", "Regen": "pioggia", "Kälte": "freddo", "Gründe": "motivi", "günstig": "economico", "Benzin": "benzina", "Parkplatz": "parcheggio", "Gesundheit": "salute", "Umwelt": "ambiente", "schneller": "più veloce", "Radwege": "piste ciclabili", "Einwohner": "abitanti", "sicher": "sicuro", "Trotzdem": "tuttavia", "Verkehrsmittel": "mezzo di trasporto"}, "q": [{"q": "Nenne einen Grund für das Fahrrad.", "o": ["Es ist teuer", "Es ist gut für die Umwelt", "Es ist langsam"], "c": 1, "e": "„gut für die Gesundheit und für die Umwelt\"."}, {"q": "Was ist in Münster besonders?", "o": ["Es gibt keine Autos", "Fast mehr Fahrräder als Einwohner", "Keine Radwege"], "c": 1, "e": "„fast mehr Fahrräder als Einwohner\"."}], "news": "Fahrrad Stadt Deutschland Radwege"}, "dialog": {"title": "Nach dem Weg fragen", "lines": [{"who": "Tourist", "de": "Entschuldigung, können Sie mir helfen?"}, {"who": "Frau", "de": "Ja, natürlich. Was suchen Sie?"}, {"who": "Tourist", "de": "Ich suche den Bahnhof. Ist er weit von hier?"}, {"who": "Frau", "de": "Nein, nur fünf Minuten zu Fuß."}, {"who": "Tourist", "de": "Und wie komme ich dorthin?"}, {"who": "Frau", "de": "Gehen Sie hier geradeaus bis zur Ampel."}, {"who": "Tourist", "de": "Geradeaus bis zur Ampel, okay."}, {"who": "Frau", "de": "Dann gehen Sie rechts. Der Bahnhof ist auf der linken Seite."}, {"who": "Tourist", "de": "Vielen Dank für Ihre Hilfe!"}, {"who": "Frau", "de": "Gern geschehen. Gute Reise!"}], "q": [{"q": "Was sucht der Tourist?", "o": ["Das Hotel", "Den Bahnhof", "Das Museum"], "c": 1, "e": "„Ich suche den Bahnhof\"."}, {"q": "Wie weit ist es?", "o": ["Fünf Minuten zu Fuß", "Eine Stunde", "Sehr weit"], "c": 0, "e": "„nur fünf Minuten zu Fuß\"."}, {"q": "Wo muss er an der Ampel hingehen?", "o": ["Links", "Rechts", "Geradeaus"], "c": 1, "e": "„Dann gehen Sie rechts\"."}]}, "musik": {"key": "forster", "task": "„Chöre\" è un inno positivo: parla delle voci (cori) che ci accompagnano nei momenti difficili. Ascolta e cerca di sentire la parola „Chöre\" e „dich\". Buon ritmo per memorizzare.", "level": "A2 · melodico"}, "sprechen": {"read": "Entschuldigung, können Sie mir helfen? Ich suche den Bahnhof. Gehe ich hier geradeaus oder muss ich links abbiegen? Vielen Dank für Ihre Hilfe.", "prompts": [{"q": "Wie kommst du normalerweise zur Arbeit oder Schule?", "e": "Ich fahre meistens mit …"}, {"q": "Was gefällt dir an deiner Stadt?", "e": "An meiner Stadt gefällt mir …"}, {"q": "Beschreib den Weg von deinem Haus zum nächsten Supermarkt.", "e": "Zuerst gehe ich …, dann …"}], "scenario": "Ein Tourist fragt dich nach dem Weg zum Bahnhof. Erklär ihm den Weg."}, "grammatik": {"titel": "Präpositionen mit Akkusativ und Dativ (Wegbeschreibung)", "regel_html": "<p>Per orientarsi servono le preposizioni di luogo. Alcune reggono il <b>dativo</b> (dove sei, stato in luogo), altre indicano la direzione.</p><table class='gtab'><tr><th>preposizione</th><th>significato</th><th>esempio</th></tr><tr><td>zu (+ Dativ)</td><td>verso (persone/luoghi)</td><td>Ich gehe <b>zum</b> Bahnhof.</td></tr><tr><td>in (+ Akk. = moto)</td><td>dentro (movimento)</td><td>Ich gehe <b>in die</b> Stadt.</td></tr><tr><td>an … vorbei</td><td>oltre / accanto</td><td>Gehen Sie <b>am</b> Park <b>vorbei</b>.</td></tr><tr><td>bis zu</td><td>fino a</td><td>Geradeaus <b>bis zur</b> Ampel.</td></tr></table><p><b>Parole utili:</b> geradeaus (dritto), links (a sinistra), rechts (a destra), die Ecke (l'angolo), die Kreuzung (l'incrocio), die Ampel (il semaforo).</p><p>💡 <i>zu + dem = zum</i>, <i>zu + der = zur</i>, <i>in + dem = im</i>, <i>an + dem = am</i>.</p>", "ex": [{"l": "Ich gehe ", "r": " Bahnhof.", "o": ["zur", "zum", "in", "an"], "c": 1, "e": "<b>zum Bahnhof</b> (zu + dem)."}, {"l": "Wir fahren ", "r": " Stadt.", "o": ["in die", "in der", "zur", "am"], "c": 0, "e": "moto → <b>in die Stadt</b> (Akkusativo)."}, {"l": "Gehen Sie geradeaus ", "r": " Ampel.", "o": ["bis zur", "bis zum", "zu der", "an die"], "c": 0, "e": "<b>bis zur Ampel</b> (bis zu + der)."}, {"l": "Das Café ist ", "r": " linken Seite.", "o": ["auf der", "auf die", "an die", "zur"], "c": 0, "e": "stato in luogo → <b>auf der linken Seite</b> (Dativo)."}]}, "wortschatz": [{"de": "der Bahnhof", "it": "la stazione", "exde": "Der Bahnhof ist dort drüben.", "exit": "La stazione è laggiù."}, {"de": "die Straße", "it": "la strada", "exde": "Die Straße ist sehr lang.", "exit": "La strada è molto lunga."}, {"de": "die Ampel", "it": "il semaforo", "exde": "Warte an der Ampel.", "exit": "Aspetta al semaforo."}, {"de": "links", "it": "a sinistra", "exde": "Geh nach links.", "exit": "Vai a sinistra."}, {"de": "rechts", "it": "a destra", "exde": "Das Hotel ist rechts.", "exit": "L'hotel è a destra."}, {"de": "geradeaus", "it": "dritto", "exde": "Geh immer geradeaus.", "exit": "Vai sempre dritto."}, {"de": "die U-Bahn", "it": "la metropolitana", "exde": "Ich nehme die U-Bahn.", "exit": "Prendo la metro."}, {"de": "der Markt", "it": "il mercato", "exde": "Der Markt ist am Samstag.", "exit": "Il mercato è il sabato."}, {"de": "das Museum", "it": "il museo", "exde": "Das Museum ist heute zu.", "exit": "Il museo oggi è chiuso."}, {"de": "zu Fuß", "it": "a piedi", "exde": "Ich gehe zu Fuß.", "exit": "Vado a piedi."}, {"de": "der Weg", "it": "la strada/il percorso", "exde": "Kennst du den Weg?", "exit": "Conosci la strada?"}, {"de": "entschuldigung", "it": "scusi", "exde": "Entschuldigung, wo ist …?", "exit": "Scusi, dov'è …?"}], "idiome": [{"de": "Viele Wege führen nach Rom.", "lit": "Molte strade portano a Roma.", "mean": "Ci sono molti modi per raggiungere un obiettivo.", "it": "Tutte le strade portano a Roma.", "exde": "Mach es anders — viele Wege führen nach Rom.", "exit": "Fallo in un altro modo: tutte le strade portano a Roma."}, {"de": "Ich verstehe nur Bahnhof.", "lit": "Capisco solo „stazione\".", "mean": "Non capisco assolutamente niente.", "it": "Per me è arabo / non ci capisco un'acca.", "exde": "Bei der Grammatik verstehe ich nur Bahnhof.", "exit": "Con la grammatica non ci capisco niente."}], "schreiben": {"impuls": "Beschreib deine Stadt: Was gibt es dort? Was magst du, was stört dich?", "fragen": ["Lebst du lieber in einer großen Stadt oder auf dem Land? Begründe deine Meinung.", "Wie sieht für dich die ideale Stadt der Zukunft aus?"]}, "freunde": [{"de": "der Tourist", "it": "turista"}, {"de": "das Restaurant", "it": "ristorante"}, {"de": "die Pizza", "it": "pizza"}, {"de": "das Auto", "it": "auto"}, {"de": "der Bus", "it": "autobus / bus"}, {"de": "das Theater", "it": "teatro"}], "falsch": [{"de": "die Note", "it": "il voto / la nota musicale", "warn": "NON la notte (= die Nacht)"}, {"de": "die Art", "it": "il tipo / il modo", "warn": "NON l'arte (= die Kunst)"}, {"de": "brav", "it": "ubbidiente / buono", "warn": "NON „bravo / capace\""}, {"de": "also", "it": "quindi / dunque", "warn": "NON „anche\" (= auch)"}, {"de": "fast", "it": "quasi", "warn": "NON „veloce\" (= schnell)"}], "lit": {"de": "Du musst dein Leben ändern.", "it": "Devi cambiare la tua vita.", "src": "R. M. Rilke"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Geh über die Brücke und dann nach links.", "it": "Attraversa il ponte e poi a sinistra."}, {"de": "Die Bank ist neben dem Supermarkt.", "it": "La banca è accanto al supermercato."}], "song1": {"id": "k9EYjn5f_nE", "artist": "Andreas Bourani", "titel": "Auf uns"}, "song2": {"id": "VNttGAaek2U", "artist": "Revolverheld", "titel": "Lass uns gehen"}, "articles": [{"title": "Wikipedia: Stadt", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Stadt"}, {"title": "Klexikon: Stadt (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Stadt"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Zahlen & Uhrzeit — Numeri e ora", "level": "A1", "lesen": {"title": "Wie spät ist es?", "text": "Tim hat heute viel zu tun. Um sieben Uhr steht er auf. Um halb acht frühstückt er und um acht Uhr fährt er zur Arbeit. Die Arbeit beginnt um neun. Um Viertel nach zwölf macht er Mittagspause. Am Nachmittag hat er um drei Uhr eine Besprechung. Sie dauert eine Stunde. Um Viertel vor fünf ist er fertig und fährt nach Hause. Am Abend, um halb acht, trifft er seine Freundin im Kino. Der Film beginnt um acht und dauert zwei Stunden. Tim sagt immer: „Zeit ist kostbar, also nutze ich jede Minute.\"", "glos": {"viel zu tun": "molto da fare", "steht … auf": "si alza", "halb acht": "7:30", "frühstückt": "fa colazione", "beginnt": "comincia", "Viertel nach": "e un quarto", "Mittagspause": "pausa pranzo", "Nachmittag": "pomeriggio", "Besprechung": "riunione", "dauert": "dura", "Stunde": "ora", "Viertel vor": "meno un quarto", "fertig": "finito", "trifft": "incontra", "Kino": "cinema", "Film": "film", "kostbar": "prezioso", "nutze": "sfrutto", "Minute": "minuto"}, "q": [{"q": "Um wie viel Uhr steht Tim auf?", "o": ["Um sechs", "Um sieben", "Um acht"], "c": 1, "e": "„Um sieben Uhr steht er auf\"."}, {"q": "Wann hat er eine Besprechung?", "o": ["Um drei Uhr", "Um zwölf", "Um fünf"], "c": 0, "e": "„um drei Uhr eine Besprechung\"."}, {"q": "Wie lange dauert der Film?", "o": ["Eine Stunde", "Zwei Stunden", "Drei Stunden"], "c": 1, "e": "„dauert zwei Stunden\"."}], "frage": "Beschreib deinen Tag mit Uhrzeiten: Wann stehst du auf, wann isst du, wann gehst du schlafen?"}, "artikel": {"title": "Warum sind die Deutschen so pünktlich?", "text": "„Fünf Minuten vor der Zeit ist des Deutschen Pünktlichkeit\", sagt ein bekannter Spruch. In Deutschland ist Pünktlichkeit sehr wichtig. Wer zu einem Termin zu spät kommt, gilt schnell als unhöflich oder unzuverlässig. Das gilt für die Arbeit, für den Arzt und sogar für ein Treffen mit Freunden. Auch Busse und Züge sollen pünktlich sein — auch wenn das in der Realität nicht immer klappt. Für viele Ausländer ist das am Anfang ungewohnt. In manchen Ländern ist eine Verspätung von zehn oder fünfzehn Minuten normal. In Deutschland aber gilt: Wer pünktlich ist, zeigt Respekt. Ein guter Tipp ist deshalb: Komm lieber ein paar Minuten zu früh als eine Minute zu spät.", "glos": {"Spruch": "detto", "Pünktlichkeit": "puntualità", "Termin": "appuntamento", "zu spät": "in ritardo", "gilt als": "è considerato", "unhöflich": "maleducato", "unzuverlässig": "inaffidabile", "Treffen": "incontro", "Realität": "realtà", "klappt": "funziona", "Ausländer": "stranieri", "ungewohnt": "inusuale", "Verspätung": "ritardo", "zeigt": "mostra", "Respekt": "rispetto", "Tipp": "consiglio", "zu früh": "in anticipo"}, "q": [{"q": "Wie wirkt man in Deutschland, wenn man zu spät kommt?", "o": ["Sympathisch", "Unhöflich", "Lustig"], "c": 1, "e": "„gilt schnell als unhöflich\"."}, {"q": "Was ist ein guter Tipp?", "o": ["Immer zu spät kommen", "Lieber ein paar Minuten zu früh", "Gar nicht kommen"], "c": 1, "e": "„Komm lieber ein paar Minuten zu früh\"."}], "news": "Pünktlichkeit Deutschland Kultur"}, "dialog": {"title": "Einen Termin machen", "lines": [{"who": "Praxis", "de": "Praxis Dr. Weber, guten Tag."}, {"who": "Patient", "de": "Guten Tag, ich möchte einen Termin machen."}, {"who": "Praxis", "de": "Gern. Wann passt es Ihnen?"}, {"who": "Patient", "de": "Geht es am Montag?"}, {"who": "Praxis", "de": "Montag … um zehn Uhr ist noch frei."}, {"who": "Patient", "de": "Zehn Uhr ist gut. Wie lange dauert es ungefähr?"}, {"who": "Praxis", "de": "Etwa zwanzig Minuten. Wie ist Ihr Name?"}, {"who": "Patient", "de": "Marco Rossi."}, {"who": "Praxis", "de": "Danke, Herr Rossi. Bis Montag um zehn!"}, {"who": "Patient", "de": "Vielen Dank. Auf Wiederhören."}], "q": [{"q": "An welchem Tag ist der Termin?", "o": ["Am Montag", "Am Freitag", "Am Sonntag"], "c": 0, "e": "„Geht es am Montag?\""}, {"q": "Um wie viel Uhr?", "o": ["Um zehn", "Um zwölf", "Um zwei"], "c": 0, "e": "„um zehn Uhr ist noch frei\"."}, {"q": "Wie lange dauert der Termin?", "o": ["Etwa 20 Minuten", "Eine Stunde", "Den ganzen Tag"], "c": 0, "e": "„Etwa zwanzig Minuten\"."}]}, "musik": {"key": "helden", "task": "Conta i numeri o le parole che riconosci in „Nur ein Wort\". Concentrati sul ritmo costante: aiuta a sentire dove cadono gli accenti delle parole.", "level": "A2 · ritmo medio"}, "sprechen": {"read": "Guten Tag, ich möchte einen Termin machen. Geht es am Montag um zehn Uhr? Wie lange dauert es ungefähr? Mein Name ist Marco Rossi. Vielen Dank!", "prompts": [{"q": "Wie spät ist es jetzt bei dir?", "e": "Es ist jetzt …"}, {"q": "Um wie viel Uhr stehst du normalerweise auf?", "e": "Ich stehe um … auf."}, {"q": "Bist du eher pünktlich oder oft zu spät?", "e": "Ich bin eher …, weil …"}], "scenario": "Ruf in einer Arztpraxis an und vereinbare einen Termin: Tag, Uhrzeit und dein Name."}, "grammatik": {"titel": "Die Uhrzeit und Zahlen", "regel_html": "<p>Per dire l'ora si usa <b>Es ist …</b> e la domanda è <b>Wie spät ist es?</b> / <b>Wie viel Uhr ist es?</b></p><table class='gtab'><tr><th>orologio</th><th>tedesco (parlato)</th></tr><tr><td>8:00</td><td>acht Uhr</td></tr><tr><td>8:15</td><td><b>Viertel nach</b> acht</td></tr><tr><td>8:30</td><td><b>halb</b> neun (= mezza verso le 9!)</td></tr><tr><td>8:45</td><td><b>Viertel vor</b> neun</td></tr><tr><td>8:20</td><td>zwanzig nach acht</td></tr></table><p>⚠️ Attenzione: <b>halb neun</b> = 8:30 (mezz'ora <i>verso</i> le 9), non le 9:30!</p><p><b>Numeri:</b> eins, zwei, drei, vier, fünf, sechs, sieben, acht, neun, zehn … <b>21</b> = <i>einundzwanzig</i> (prima l'unità, poi la decina: „uno-e-venti\").</p>", "ex": [{"l": "Es ist ", "r": " neun. (8:30)", "o": ["Viertel", "halb", "vor", "nach"], "c": 1, "e": "8:30 = <b>halb neun</b>."}, {"l": "Es ist Viertel ", "r": " sieben. (6:45)", "o": ["nach", "vor", "halb", "um"], "c": 1, "e": "6:45 = Viertel <b>vor</b> sieben."}, {"l": "Der Zug fährt ", "r": " zehn Uhr.", "o": ["um", "in", "an", "auf"], "c": 0, "e": "orario preciso: <b>um</b> zehn Uhr."}, {"l": "21 schreibt man: ", "r": "", "o": ["zwanzigeins", "einundzwanzig", "einzwanzig", "zwanzigundeins"], "c": 1, "e": "<b>einundzwanzig</b> (unità + zwanzig)."}]}, "wortschatz": [{"de": "die Uhr", "it": "l'orologio", "exde": "Die Uhr ist kaputt.", "exit": "L'orologio è rotto."}, {"de": "die Zeit", "it": "il tempo", "exde": "Ich habe keine Zeit.", "exit": "Non ho tempo."}, {"de": "die Stunde", "it": "l'ora (durata)", "exde": "Eine Stunde hat 60 Minuten.", "exit": "Un'ora ha 60 minuti."}, {"de": "die Minute", "it": "il minuto", "exde": "Warte eine Minute.", "exit": "Aspetta un minuto."}, {"de": "der Termin", "it": "l'appuntamento", "exde": "Ich habe einen Termin.", "exit": "Ho un appuntamento."}, {"de": "pünktlich", "it": "puntuale", "exde": "Sei bitte pünktlich.", "exit": "Sii puntuale, per favore."}, {"de": "früh", "it": "presto", "exde": "Ich stehe früh auf.", "exit": "Mi alzo presto."}, {"de": "spät", "it": "tardi", "exde": "Es ist schon spät.", "exit": "È già tardi."}, {"de": "der Morgen", "it": "la mattina", "exde": "Am Morgen trinke ich Kaffee.", "exit": "La mattina bevo caffè."}, {"de": "der Abend", "it": "la sera", "exde": "Am Abend lese ich.", "exit": "La sera leggo."}, {"de": "dauern", "it": "durare", "exde": "Wie lange dauert es?", "exit": "Quanto dura?"}, {"de": "beginnen", "it": "cominciare", "exde": "Der Film beginnt um acht.", "exit": "Il film comincia alle otto."}], "idiome": [{"de": "Zeit ist Geld.", "lit": "Il tempo è denaro.", "mean": "Non bisogna sprecare il tempo.", "it": "Il tempo è denaro.", "exde": "Schnell, Zeit ist Geld!", "exit": "Veloce, il tempo è denaro!"}, {"de": "höchste Eisenbahn", "lit": "massima ferrovia", "mean": "È l'ultimo momento, bisogna sbrigarsi.", "it": "È ora / non c'è più tempo.", "exde": "Komm, es ist höchste Eisenbahn!", "exit": "Dai, è l'ultimo momento!"}], "schreiben": {"impuls": "Schreib deinen Stundenplan für morgen: Was machst du um welche Uhrzeit?", "fragen": ["Bist du ein Morgenmensch oder ein Abendmensch? Erkläre.", "Hast du genug Zeit für die wichtigen Dinge im Leben? Was würdest du ändern?"]}, "freunde": [{"de": "der Bus", "it": "autobus / bus"}, {"de": "das Theater", "it": "teatro"}, {"de": "die Kultur", "it": "cultura"}, {"de": "das Konzert", "it": "concerto"}, {"de": "der Park", "it": "parco"}, {"de": "das Museum", "it": "museo"}], "falsch": [{"de": "also", "it": "quindi / dunque", "warn": "NON „anche\" (= auch)"}, {"de": "fast", "it": "quasi", "warn": "NON „veloce\" (= schnell)"}, {"de": "bald", "it": "presto", "warn": "NON „baldo\""}, {"de": "komisch", "it": "strano (spesso) / buffo", "warn": "attenzione: di solito = strano"}, {"de": "die Birne", "it": "la pera / la lampadina", "warn": "NON „birra\" (= das Bier)"}], "lit": {"de": "Der brave Mann denkt an sich selbst zuletzt.", "it": "L'uomo valoroso pensa a sé per ultimo.", "src": "F. Schiller, Wilhelm Tell"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [{"de": "Es ist Viertel nach drei.", "it": "Sono le tre e un quarto."}, {"de": "Der Bus kommt um zwanzig vor neun.", "it": "Il bus arriva alle nove meno venti."}], "song1": {"id": "Fpu5a0Bl8eY", "artist": "Nena", "titel": "99 Luftballons"}, "song2": {"id": "GsRuJjgyZdQ", "artist": "Silbermond", "titel": "Irgendwas bleibt"}, "articles": [{"title": "Wikipedia: Uhrzeit", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Uhrzeit"}, {"title": "Klexikon: Uhr (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Uhr"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Wohnen & Zuhause — Casa e arredamento", "level": "A1", "lesen": {"title": "Meine neue Wohnung", "text": "Seit letztem Monat habe ich eine neue Wohnung. Sie ist nicht groß, aber sehr gemütlich. Es gibt ein Wohnzimmer, ein Schlafzimmer, eine kleine Küche und ein Bad. Mein Lieblingszimmer ist das Wohnzimmer. Dort stehen ein altes Sofa, ein Tisch und ein großes Bücherregal. Am Fenster habe ich viele Pflanzen, denn ich liebe Grün in der Wohnung. Die Küche ist klein, aber praktisch. Leider habe ich keinen Balkon, und das vermisse ich ein bisschen. Am besten gefällt mir das Licht: Morgens scheint die Sonne direkt ins Wohnzimmer. Hier fühle ich mich wohl, und langsam wird die Wohnung ein echtes Zuhause.", "glos": {"Wohnung": "appartamento", "gemütlich": "accogliente", "Wohnzimmer": "soggiorno", "Schlafzimmer": "camera da letto", "Küche": "cucina", "Bad": "bagno", "Lieblingszimmer": "stanza preferita", "Sofa": "divano", "Tisch": "tavolo", "Bücherregal": "libreria (scaffale)", "Fenster": "finestra", "Pflanzen": "piante", "praktisch": "pratica", "Balkon": "balcone", "vermisse": "sento la mancanza", "Licht": "luce", "fühle mich wohl": "mi sento bene", "Zuhause": "casa (focolare)"}, "q": [{"q": "Welches ist das Lieblingszimmer?", "o": ["Die Küche", "Das Wohnzimmer", "Das Bad"], "c": 1, "e": "„Mein Lieblingszimmer ist das Wohnzimmer\"."}, {"q": "Was vermisst die Person?", "o": ["Eine Küche", "Einen Balkon", "Ein Sofa"], "c": 1, "e": "„keinen Balkon, und das vermisse ich\"."}, {"q": "Was gefällt ihr am besten?", "o": ["Das Licht", "Der Balkon", "Die Größe"], "c": 0, "e": "„Am besten gefällt mir das Licht\"."}], "frage": "Beschreib deine Wohnung: Welche Zimmer gibt es und welches magst du am liebsten?"}, "artikel": {"title": "Wohnen in der Stadt: teuer und knapp", "text": "In vielen deutschen Städten ist es schwer, eine Wohnung zu finden. Vor allem in Großstädten wie München, Hamburg oder Berlin sind die Mieten in den letzten Jahren stark gestiegen. Junge Leute und Familien geben oft mehr als ein Drittel ihres Einkommens nur für die Miete aus. Bei jeder freien Wohnung melden sich manchmal hundert Interessenten. Deshalb wohnen viele Studenten in einer WG oder bleiben länger bei den Eltern. Die Politik versucht, mehr günstige Wohnungen zu bauen, aber das dauert lange. Manche Menschen ziehen deshalb aufs Land, wo das Wohnen billiger ist. Doch dort fehlen oft Arbeit, Busse und Geschäfte. Das Thema Wohnen bleibt also eine der größten Fragen für viele Menschen.", "glos": {"finden": "trovare", "Großstädten": "grandi città", "Mieten": "affitti", "gestiegen": "aumentati", "Drittel": "terzo", "Einkommens": "reddito", "Miete": "affitto", "Interessenten": "interessati", "WG": "appartamento condiviso", "Politik": "politica", "günstige": "economiche", "bauen": "costruire", "ziehen": "si trasferiscono", "Land": "campagna", "billiger": "più economico", "fehlen": "mancano", "Thema": "tema"}, "q": [{"q": "Was ist mit den Mieten passiert?", "o": ["Sie sind gesunken", "Sie sind stark gestiegen", "Sie sind gleich"], "c": 1, "e": "„die Mieten … stark gestiegen\"."}, {"q": "Warum ziehen manche aufs Land?", "o": ["Mehr Arbeit", "Wohnen ist billiger", "Mehr Busse"], "c": 1, "e": "„wo das Wohnen billiger ist\"."}], "news": "Wohnungsmarkt Mieten Deutschland"}, "dialog": {"title": "Eine Wohnung besichtigen", "lines": [{"who": "Vermieter", "de": "Guten Tag, kommen Sie herein. Das ist die Wohnung."}, {"who": "Interessentin", "de": "Oh, schön hell! Wie groß ist sie?"}, {"who": "Vermieter", "de": "Sechzig Quadratmeter. Zwei Zimmer, Küche und Bad."}, {"who": "Interessentin", "de": "Gibt es einen Balkon?"}, {"who": "Vermieter", "de": "Ja, einen kleinen. Er geht nach Süden."}, {"who": "Interessentin", "de": "Wunderbar. Und wie hoch ist die Miete?"}, {"who": "Vermieter", "de": "Achthundert Euro warm, also mit Nebenkosten."}, {"who": "Interessentin", "de": "Ist das verhandelbar?"}, {"who": "Vermieter", "de": "Leider nein. Aber die Wohnung ist sofort frei."}, {"who": "Interessentin", "de": "Gut. Kann ich sie mir noch einmal in Ruhe ansehen?"}], "q": [{"q": "Wie groß ist die Wohnung?", "o": ["40 m²", "60 m²", "100 m²"], "c": 1, "e": "„Sechzig Quadratmeter\"."}, {"q": "Gibt es einen Balkon?", "o": ["Nein", "Ja, einen kleinen", "Zwei Balkone"], "c": 1, "e": "„Ja, einen kleinen\"."}, {"q": "Wie hoch ist die Miete?", "o": ["800 € warm", "600 € warm", "1000 € warm"], "c": 0, "e": "„Achthundert Euro warm\"."}]}, "musik": {"key": "fox", "task": "„Haus am See\" parla proprio di una casa dei sogni. Mentre ascolti, immagina la tua casa ideale e annota (mentalmente) le parole legate all'abitare che riconosci.", "level": "B1 · calmo"}, "sprechen": {"read": "Das ist meine Wohnung. Sie hat zwei Zimmer, eine Küche und ein Bad. Mein Lieblingszimmer ist das Wohnzimmer mit dem großen Fenster. Leider habe ich keinen Balkon.", "prompts": [{"q": "Wie viele Zimmer hat deine Wohnung?", "e": "Meine Wohnung hat … Zimmer."}, {"q": "Was steht in deinem Wohnzimmer?", "e": "In meinem Wohnzimmer stehen …"}, {"q": "Wo möchtest du gern wohnen: Stadt oder Land?", "e": "Ich möchte gern … wohnen, weil …"}], "scenario": "Du besichtigst eine Wohnung. Frag nach Größe, Balkon und Miete."}, "grammatik": {"titel": "„es gibt\", Plural der Nomen und die Negation „kein\"", "regel_html": "<p>Per dire „c'è / ci sono\" si usa sempre <b>es gibt</b> + <b>accusativo</b>: <i>Es gibt <u>einen</u> Balkon.</i> · <i>Es gibt <u>keine</u> Küche.</i></p><p>Il <b>plurale</b> dei nomi è irregolare; va imparato con l'articolo. Forme tipiche:</p><table class='gtab'><tr><th>singolare</th><th>plurale</th></tr><tr><td>das Zimmer</td><td>die Zimmer (uguale)</td></tr><tr><td>der Tisch</td><td>die Tisch<b>e</b></td></tr><tr><td>das Buch</td><td>die B<b>ü</b>ch<b>er</b></td></tr><tr><td>die Wohnung</td><td>die Wohnung<b>en</b></td></tr><tr><td>das Sofa</td><td>die Sofa<b>s</b></td></tr></table><p>💡 Negazione: <b>nicht</b> nega verbi/aggettivi, <b>kein</b> nega un nome: <i>Ich habe <u>keinen</u> Balkon.</i></p>", "ex": [{"l": "In der Wohnung gibt es ", "r": " Balkon.", "o": ["kein", "keinen", "keine", "nicht"], "c": 1, "e": "es gibt + Akk.: <b>keinen Balkon</b> (masch.)."}, {"l": "Ich habe zwei ", "r": ". (Buch)", "o": ["Buchs", "Bücher", "Buchen", "Büch"], "c": 1, "e": "plurale di Buch = <b>Bücher</b>."}, {"l": "Hier gibt es drei ", "r": ". (Zimmer)", "o": ["Zimmer", "Zimmern", "Zimmers", "Zimmere"], "c": 0, "e": "Zimmer ha plurale uguale: <b>Zimmer</b>."}, {"l": "Das Sofa ist ", "r": " bequem.", "o": ["kein", "nicht", "keine", "keinen"], "c": 1, "e": "nega l'aggettivo → <b>nicht</b> bequem."}]}, "wortschatz": [{"de": "die Wohnung", "it": "l'appartamento", "exde": "Die Wohnung ist hell.", "exit": "L'appartamento è luminoso."}, {"de": "das Zimmer", "it": "la stanza", "exde": "Mein Zimmer ist klein.", "exit": "La mia stanza è piccola."}, {"de": "die Küche", "it": "la cucina", "exde": "Die Küche ist neu.", "exit": "La cucina è nuova."}, {"de": "das Bad", "it": "il bagno", "exde": "Das Bad ist sauber.", "exit": "Il bagno è pulito."}, {"de": "der Tisch", "it": "il tavolo", "exde": "Der Tisch ist aus Holz.", "exit": "Il tavolo è di legno."}, {"de": "der Stuhl", "it": "la sedia", "exde": "Der Stuhl ist bequem.", "exit": "La sedia è comoda."}, {"de": "das Bett", "it": "il letto", "exde": "Das Bett ist groß.", "exit": "Il letto è grande."}, {"de": "das Fenster", "it": "la finestra", "exde": "Mach das Fenster auf.", "exit": "Apri la finestra."}, {"de": "die Miete", "it": "l'affitto", "exde": "Die Miete ist hoch.", "exit": "L'affitto è alto."}, {"de": "gemütlich", "it": "accogliente", "exde": "Das Zimmer ist gemütlich.", "exit": "La stanza è accogliente."}, {"de": "hell", "it": "luminoso", "exde": "Die Wohnung ist hell.", "exit": "L'appartamento è luminoso."}, {"de": "der Balkon", "it": "il balcone", "exde": "Wir haben einen Balkon.", "exit": "Abbiamo un balcone."}], "idiome": [{"de": "Trautes Heim, Glück allein.", "lit": "Casa cara, felicità sicura.", "mean": "A casa propria si sta meglio che ovunque.", "it": "Casa dolce casa.", "exde": "Endlich zu Hause — trautes Heim, Glück allein.", "exit": "Finalmente a casa: casa dolce casa."}, {"de": "sich wie zu Hause fühlen", "lit": "Sentirsi come a casa.", "mean": "Sentirsi a proprio agio in un posto.", "it": "Sentirsi a casa.", "exde": "Komm rein und fühl dich wie zu Hause!", "exit": "Entra e fai come se fossi a casa tua!"}], "schreiben": {"impuls": "Beschreib dein Traumhaus: Wo steht es, wie sieht es aus, was gibt es darin?", "fragen": ["Was macht für dich ein Haus zu einem echten Zuhause?", "Würdest du lieber zur Miete wohnen oder ein Haus kaufen? Warum?"]}, "freunde": [{"de": "der Park", "it": "parco"}, {"de": "das Museum", "it": "museo"}, {"de": "die Person", "it": "persona"}, {"de": "die Politik", "it": "politica"}, {"de": "die Energie", "it": "energia"}, {"de": "das System", "it": "sistema"}], "falsch": [{"de": "komisch", "it": "strano (spesso) / buffo", "warn": "attenzione: di solito = strano"}, {"de": "die Birne", "it": "la pera / la lampadina", "warn": "NON „birra\" (= das Bier)"}, {"de": "sensibel", "it": "sensibile / delicato", "warn": "NON „sensato\" (= vernünftig)"}, {"de": "der Termin", "it": "l'appuntamento", "warn": "NON il „termine/scadenza-parola\""}, {"de": "das Rezept", "it": "la ricetta / la prescrizione", "warn": "vale sia in cucina sia dal medico"}], "lit": {"de": "Edel sei der Mensch, hilfreich und gut.", "it": "Sia nobile l'uomo, generoso e buono.", "src": "J. W. Goethe"}, "trad": {"id": "gedanken", "title": "Die Gedanken sind frei", "artist": "Volkslied", "note": "Canto popolare sulla libertà di pensiero, amatissimo in Germania.", "ytq": "Die Gedanken sind frei Lied", "de": ["Die Gedanken sind frei,", "wer kann sie erraten?", "Sie fliehen vorbei", "wie nächtliche Schatten.", "Kein Mensch kann sie wissen,", "kein Jäger erschießen;", "es bleibet dabei:", "die Gedanken sind frei!"], "it": ["I pensieri sono liberi,", "chi può indovinarli?", "Volano via", "come ombre nella notte.", "Nessuno può conoscerli,", "nessun cacciatore può abbatterli;", "resta così:", "i pensieri sono liberi!"]}, "voice": {"id": "kRq3WzSwUw0", "t": "Straßeninterviews in Magdeburg", "note": "Ascolto autentico con sottotitoli tedeschi."}, "gram_extra": [{"de": "In der Wohnung gibt es zwei Zimmer, aber keinen Balkon.", "it": "Nell'appartamento ci sono due stanze, ma nessun balcone."}, {"de": "Es gibt viele Bücher, aber keine Stühle.", "it": "Ci sono molti libri, ma nessuna sedia."}], "song1": {"id": "cIfx8QiNXfs", "artist": "Peter Fox", "titel": "Haus am See"}, "song2": {"id": "deDquONycuA", "artist": "Silbermond", "titel": "Symphonie"}, "articles": [{"title": "Wikipedia: Wohnung", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Wohnung"}, {"title": "Klexikon: Haus (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Haus"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Hobbys & Freizeit — Hobby e tempo libero", "level": "A1", "lesen": {"title": "Was ich gern mache", "text": "In meiner Freizeit mache ich viele verschiedene Dinge. Am liebsten spiele ich Gitarre — das entspannt mich nach einem langen Tag. Zweimal pro Woche gehe ich auch zum Sport. Ich finde Schwimmen toll, weil ich danach immer ruhig und müde bin. An Wochenenden treffe ich gern Freunde. Wir kochen zusammen, schauen einen Film oder gehen einfach spazieren. Lesen mag ich auch sehr, besonders Krimis. Was ich nicht mag, ist Fernsehen den ganzen Tag — das finde ich langweilig. Hobbys sind für mich wichtig, denn sie geben mir Energie und gute Laune.", "glos": {"Freizeit": "tempo libero", "verschiedene": "diverse", "am liebsten": "più di tutto", "Gitarre": "chitarra", "entspannt": "rilassa", "Sport": "sport", "Schwimmen": "nuoto", "ruhig": "calmo", "müde": "stanco", "Wochenenden": "fine settimana", "spazieren": "passeggiare", "Krimis": "gialli (libri)", "langweilig": "noioso", "Energie": "energia", "Laune": "umore"}, "q": [{"q": "Was macht die Person am liebsten?", "o": ["Schwimmen", "Gitarre spielen", "Fernsehen"], "c": 1, "e": "„Am liebsten spiele ich Gitarre\"."}, {"q": "Wie oft geht sie zum Sport?", "o": ["Jeden Tag", "Zweimal pro Woche", "Nie"], "c": 1, "e": "„Zweimal pro Woche\"."}, {"q": "Was findet sie langweilig?", "o": ["Lesen", "Den ganzen Tag fernsehen", "Kochen"], "c": 1, "e": "„Fernsehen den ganzen Tag … langweilig\"."}], "frage": "Was sind deine Hobbys? Was machst du am liebsten in deiner Freizeit?"}, "artikel": {"title": "Der Verein: ein Stück deutsche Kultur", "text": "In Deutschland gibt es für fast alles einen Verein. Ob Fußball, Schach, Singen, Wandern oder sogar Briefmarken sammeln — überall treffen sich Menschen mit dem gleichen Hobby. Es gibt über 600.000 Vereine im Land. Viele Deutsche sind schon als Kind in einem Sportverein. Ein Verein ist mehr als nur Freizeit: Man lernt neue Leute kennen, übernimmt Verantwortung und gehört zu einer Gemeinschaft. Gerade für Menschen, die neu in eine Stadt ziehen, ist ein Verein eine gute Möglichkeit, Freunde zu finden und die Sprache zu üben. Wer also in Deutschland lebt und Kontakte sucht, sollte einfach mal in einem Verein vorbeischauen.", "glos": {"Verein": "associazione/club", "Schach": "scacchi", "Wandern": "escursionismo", "Briefmarken": "francobolli", "sammeln": "collezionare", "gleichen": "stesso", "Land": "paese", "Verantwortung": "responsabilità", "Gemeinschaft": "comunità", "ziehen": "trasferirsi", "Möglichkeit": "possibilità", "Kontakte": "contatti", "vorbeischauen": "fare un salto"}, "q": [{"q": "Wie viele Vereine gibt es ungefähr?", "o": ["Etwa 6.000", "Über 600.000", "Genau 100"], "c": 1, "e": "„über 600.000 Vereine\"."}, {"q": "Warum ist ein Verein für Neue gut?", "o": ["Es kostet nichts", "Man findet Freunde und übt die Sprache", "Man muss nichts tun"], "c": 1, "e": "„Freunde zu finden und die Sprache zu üben\"."}], "news": "Verein Deutschland Mitglieder"}, "dialog": {"title": "Pläne fürs Wochenende", "lines": [{"who": "Jonas", "de": "Hast du am Samstag schon was vor?"}, {"who": "Mia", "de": "Nein, noch nicht. Warum fragst du?"}, {"who": "Jonas", "de": "Ich gehe wandern. Hast du Lust mitzukommen?"}, {"who": "Mia", "de": "Wandern? Hmm, ich weiß nicht. Wie lange dauert das?"}, {"who": "Jonas", "de": "Ungefähr drei Stunden. Es ist nicht zu schwer."}, {"who": "Mia", "de": "Okay, das klingt gut. Wann treffen wir uns?"}, {"who": "Jonas", "de": "Um neun Uhr am Bahnhof. Bring gute Schuhe mit!"}, {"who": "Mia", "de": "Mach ich. Und Essen?"}, {"who": "Jonas", "de": "Jeder bringt etwas mit. Ich nehme Wasser und Obst."}, {"who": "Mia", "de": "Super, ich freue mich!"}], "q": [{"q": "Was möchte Jonas machen?", "o": ["Schwimmen", "Wandern", "Ins Kino gehen"], "c": 1, "e": "„Ich gehe wandern\"."}, {"q": "Wie lange dauert die Wanderung?", "o": ["Eine Stunde", "Drei Stunden", "Den ganzen Tag"], "c": 1, "e": "„Ungefähr drei Stunden\"."}, {"q": "Wo treffen sie sich?", "o": ["Im Café", "Am Bahnhof", "Zu Hause"], "c": 1, "e": "„um neun Uhr am Bahnhof\"."}]}, "musik": {"key": "amk", "task": "„Pocahontas\" degli AnnenMayKantereit ha un tedesco moderno e una voce particolare. Ascolta senza testo e prova a riconoscere singole parole. Non capire tutto è normale: allena l'orecchio al ritmo della lingua.", "level": "B1 · voce particolare"}, "sprechen": {"read": "In meiner Freizeit spiele ich gern Gitarre und gehe zweimal pro Woche schwimmen. Am Wochenende treffe ich Freunde. Wir kochen zusammen oder gehen spazieren. Lesen mag ich auch sehr.", "prompts": [{"q": "Was machst du gern am Wochenende?", "e": "Am Wochenende … ich gern …"}, {"q": "Hast du ein Hobby seit der Kindheit?", "e": "Seit ich klein bin, …"}, {"q": "Lädst du einen Freund zu deinem Lieblingshobby ein — wie?", "e": "Hast du Lust, … mitzukommen?"}], "scenario": "Lad einen Freund zu einer Freizeitaktivität ein. Sag, was, wann und wo — und reagier auf seine Fragen."}, "grammatik": {"titel": "Verben mit „gern\" und die Wortstellung", "regel_html": "<p>Per dire che ti piace <b>fare</b> qualcosa, in tedesco non serve un verbo come „piacere\": basta il verbo + <b>gern</b> (volentieri). Per il preferito si usa <b>am liebsten</b>.</p><table class='gtab'><tr><th>grado</th><th>parola</th><th>esempio</th></tr><tr><td>+</td><td>gern</td><td>Ich spiele <b>gern</b> Fußball.</td></tr><tr><td>++</td><td>lieber</td><td>Ich schwimme <b>lieber</b>.</td></tr><tr><td>+++</td><td>am liebsten</td><td><b>Am liebsten</b> lese ich.</td></tr></table><p><b>Regola V2:</b> il verbo coniugato è sempre al 2° posto. Se inizi con un'altra parola (es. „Am Wochenende\"), il verbo resta secondo e il soggetto va dopo: <i>Am Wochenende <u>spiele</u> ich Gitarre.</i></p>", "ex": [{"l": "Ich ", "r": " gern Musik.", "o": ["höre", "hören", "gehört", "hörst"], "c": 0, "e": "<b>höre</b> gern (ich)."}, {"l": "Am liebsten ", "r": " ich.", "o": ["lese", "lesen", "liest", "gelesen"], "c": 0, "e": "V2: dopo „Am liebsten\" il verbo è 2°: <b>lese</b> ich."}, {"l": "Ich schwimme ", "r": " als ich laufe.", "o": ["gern", "lieber", "am liebsten", "gut"], "c": 1, "e": "comparativo della preferenza: <b>lieber</b>."}, {"l": "Am Wochenende ", "r": " wir Freunde.", "o": ["treffen", "wir treffen", "getroffen", "trifft"], "c": 0, "e": "V2: <b>treffen</b> wir (verbo prima del soggetto)."}]}, "wortschatz": [{"de": "die Freizeit", "it": "il tempo libero", "exde": "Was machst du in der Freizeit?", "exit": "Cosa fai nel tempo libero?"}, {"de": "das Hobby", "it": "l'hobby", "exde": "Mein Hobby ist Malen.", "exit": "Il mio hobby è disegnare."}, {"de": "spielen", "it": "giocare/suonare", "exde": "Ich spiele Klavier.", "exit": "Suono il pianoforte."}, {"de": "der Sport", "it": "lo sport", "exde": "Sport macht Spaß.", "exit": "Lo sport è divertente."}, {"de": "lesen", "it": "leggere", "exde": "Ich lese gern Krimis.", "exit": "Leggo volentieri gialli."}, {"de": "schwimmen", "it": "nuotare", "exde": "Wir gehen schwimmen.", "exit": "Andiamo a nuotare."}, {"de": "wandern", "it": "fare escursioni", "exde": "Am Sonntag wandern wir.", "exit": "La domenica facciamo escursioni."}, {"de": "treffen", "it": "incontrare", "exde": "Ich treffe Freunde.", "exit": "Incontro amici."}, {"de": "gern", "it": "volentieri", "exde": "Ich koche gern.", "exit": "Cucino volentieri."}, {"de": "Lust haben", "it": "aver voglia", "exde": "Hast du Lust?", "exit": "Hai voglia?"}, {"de": "Spaß machen", "it": "essere divertente", "exde": "Das macht Spaß.", "exit": "È divertente."}, {"de": "langweilig", "it": "noioso", "exde": "Der Film ist langweilig.", "exit": "Il film è noioso."}], "idiome": [{"de": "Lust und Laune", "lit": "Voglia e umore.", "mean": "Fare qualcosa quando se ne ha voglia, senza obblighi.", "it": "Quando gira / a piacimento.", "exde": "Ich male, ganz nach Lust und Laune.", "exit": "Dipingo, solo quando mi va."}, {"de": "die Seele baumeln lassen", "lit": "Lasciare dondolare l'anima.", "mean": "Rilassarsi completamente, staccare la mente.", "it": "Rilassarsi / staccare la spina.", "exde": "Am See lasse ich die Seele baumeln.", "exit": "Al lago mi rilasso completamente."}], "schreiben": {"impuls": "Beschreib dein Lieblingshobby: Was ist es, wie oft machst du es, und warum magst du es?", "fragen": ["Brauchen Erwachsene Hobbys? Oder ist das Zeitverschwendung?", "Wenn du ein neues Hobby anfangen könntest — was wäre es und warum?"]}, "freunde": [{"de": "die Energie", "it": "energia"}, {"de": "das System", "it": "sistema"}, {"de": "das Projekt", "it": "progetto"}, {"de": "die Million", "it": "milione"}, {"de": "der Doktor", "it": "dottore"}, {"de": "die Medizin", "it": "medicina"}], "falsch": [{"de": "der Termin", "it": "l'appuntamento", "warn": "NON il „termine/scadenza-parola\""}, {"de": "das Rezept", "it": "la ricetta / la prescrizione", "warn": "vale sia in cucina sia dal medico"}, {"de": "bekommen", "it": "ricevere", "warn": "NON „diventare\" (to become)"}, {"de": "das Gift", "it": "il veleno", "warn": "NON „regalo\" (gift)"}, {"de": "der Chef", "it": "il capo", "warn": "NON il cuoco (= der Koch)"}], "lit": {"de": "Früh übt sich, was ein Meister werden will.", "it": "Presto si esercita chi vuol diventare maestro.", "src": "F. Schiller"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Am Samstag spiele ich gern Fußball.", "it": "Il sabato gioco volentieri a calcio."}, {"de": "Sie liest am liebsten Krimis.", "it": "Lei legge soprattutto gialli."}], "song1": {"id": "HeW9ZmB3-_g", "artist": "Howard Carpendale", "titel": "Ti Amo", "original": "Cover di „Ti amo\" di Umberto Tozzi (1977)."}, "song2": {"id": "ohHJjPSsW8c", "artist": "Silbermond", "titel": "Leichtes Gepäck"}, "articles": [{"title": "Wikipedia: Freizeit", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Freizeit"}, {"title": "Klexikon: Sport (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Sport"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Kleidung & Farben — Vestiti e colori", "level": "A1", "lesen": {"title": "Was ziehe ich heute an?", "text": "Jeden Morgen stehe ich vor meinem Schrank und denke: Was ziehe ich heute an? Heute ist es kalt, also nehme ich einen warmen Pullover und eine blaue Jeans. Dazu trage ich meine braunen Schuhe und einen dicken Schal. Meine Lieblingsfarbe ist Grün, aber grüne Kleidung habe ich fast nie. Für die Arbeit ziehe ich oft ein weißes Hemd an, das sieht ordentlich aus. Am Wochenende ist es anders: Da trage ich am liebsten ein bequemes T-Shirt und eine Jogginghose. Wenn es regnet, brauche ich natürlich noch eine Jacke und einen Schirm. Mode ist mir nicht so wichtig — Hauptsache, ich fühle mich wohl.", "glos": {"ziehe … an": "indosso", "Schrank": "armadio", "kalt": "freddo", "Pullover": "maglione", "Jeans": "jeans", "trage": "porto/indosso", "Schuhe": "scarpe", "Schal": "sciarpa", "Lieblingsfarbe": "colore preferito", "Grün": "verde", "Kleidung": "abbigliamento", "Hemd": "camicia", "ordentlich": "in ordine", "bequemes": "comodo", "Jogginghose": "pantaloni della tuta", "regnet": "piove", "Jacke": "giacca", "Schirm": "ombrello", "Mode": "moda", "wohl": "a proprio agio"}, "q": [{"q": "Was trägt die Person bei Kälte?", "o": ["Ein T-Shirt", "Einen warmen Pullover", "Eine Jogginghose"], "c": 1, "e": "„einen warmen Pullover und eine blaue Jeans\"."}, {"q": "Welche Farbe mag sie am liebsten?", "o": ["Blau", "Grün", "Weiß"], "c": 1, "e": "„Meine Lieblingsfarbe ist Grün\"."}, {"q": "Was ist ihr bei Mode wichtig?", "o": ["Teuer sein", "Sich wohlfühlen", "Modern sein"], "c": 1, "e": "„Hauptsache, ich fühle mich wohl\"."}], "frage": "Was trägst du gern? Beschreib deinen Lieblingsstil und deine Lieblingsfarben."}, "artikel": {"title": "Schwarz: die Lieblingsfarbe der Deutschen?", "text": "Wenn man durch eine deutsche Stadt geht, sieht man vor allem eine Farbe: Schwarz. Viele Menschen tragen schwarze Jacken, schwarze Hosen und schwarze Schuhe. Warum ist das so? Schwarz gilt als praktisch und elegant. Es passt zu allem, man sieht keinen Schmutz, und man wirkt schnell seriös. Besonders im Winter und in großen Städten wie Berlin oder Hamburg ist die Kleidung oft sehr dunkel. Manche finden das langweilig und wünschen sich mehr Farbe auf der Straße. Andere sagen: Schwarz ist einfach bequem, weil man morgens nicht lange überlegen muss. Eines ist sicher: Mit einem schwarzen Mantel macht man in Deutschland selten etwas falsch.", "glos": {"Schwarz": "nero", "tragen": "indossano", "Jacken": "giacche", "Hosen": "pantaloni", "praktisch": "pratico", "elegant": "elegante", "Schmutz": "sporco", "wirkt": "sembra", "seriös": "serio", "dunkel": "scuro", "langweilig": "noioso", "Farbe": "colore", "bequem": "comodo", "überlegen": "riflettere", "Mantel": "cappotto", "selten": "raramente"}, "q": [{"q": "Welche Farbe tragen viele Deutsche?", "o": ["Rot", "Schwarz", "Gelb"], "c": 1, "e": "„sieht man vor allem eine Farbe: Schwarz\"."}, {"q": "Warum mögen viele Schwarz?", "o": ["Es ist bunt", "Es ist praktisch und elegant", "Es ist billig"], "c": 1, "e": "„Schwarz gilt als praktisch und elegant\"."}], "news": "Mode Farben Deutschland Kleidung"}, "dialog": {"title": "Im Bekleidungsgeschäft", "lines": [{"who": "Verkäuferin", "de": "Hallo! Suchen Sie etwas Bestimmtes?"}, {"who": "Kunde", "de": "Ja, ich suche ein Hemd für eine Hochzeit."}, {"who": "Verkäuferin", "de": "Schön! An welche Farbe haben Sie gedacht?"}, {"who": "Kunde", "de": "Vielleicht hellblau oder weiß."}, {"who": "Verkäuferin", "de": "Welche Größe tragen Sie?"}, {"who": "Kunde", "de": "Normalerweise Größe M."}, {"who": "Verkäuferin", "de": "Hier ist ein hellblaues Hemd in M. Möchten Sie es anprobieren?"}, {"who": "Kunde", "de": "Ja, gern. Wo sind die Umkleidekabinen?"}, {"who": "Verkäuferin", "de": "Gleich dort rechts. … Und, wie sitzt es?"}, {"who": "Kunde", "de": "Perfekt! Das nehme ich."}], "q": [{"q": "Wofür braucht der Kunde ein Hemd?", "o": ["Für die Arbeit", "Für eine Hochzeit", "Für den Sport"], "c": 1, "e": "„ein Hemd für eine Hochzeit\"."}, {"q": "Welche Farben möchte er?", "o": ["Schwarz oder grau", "Hellblau oder weiß", "Rot oder grün"], "c": 1, "e": "„Vielleicht hellblau oder weiß\"."}, {"q": "Welche Größe trägt er?", "o": ["S", "M", "L"], "c": 1, "e": "„Normalerweise Größe M\"."}]}, "musik": {"key": "forster", "task": "Riascolta una canzone che ti piace e nota i colori o i vestiti se vengono nominati. Canta il ritornello e divertiti: la musica aiuta a memorizzare le parole nuove.", "level": "A2 · melodico"}, "sprechen": {"read": "Heute ist es kalt. Ich ziehe einen warmen Pullover, eine blaue Jeans und braune Schuhe an. Dazu nehme ich einen Schal und eine Jacke. Meine Lieblingsfarbe ist Grün.", "prompts": [{"q": "Welche Kleidung trägst du heute?", "e": "Heute trage ich …"}, {"q": "Was ist deine Lieblingsfarbe?", "e": "Meine Lieblingsfarbe ist …"}, {"q": "Was ziehst du an, wenn es regnet?", "e": "Wenn es regnet, ziehe ich … an."}], "scenario": "Du bist im Geschäft und suchst eine Jacke. Sag Farbe und Größe und frag, ob du sie anprobieren kannst."}, "grammatik": {"titel": "Adjektive und Farben (con il verbo „sein\")", "regel_html": "<p>Quando l'aggettivo viene <b>dopo il verbo</b> (es. <i>sein</i>), resta <b>invariato</b>: non prende desinenze. È il caso più facile!</p><table class='gtab'><tr><th>frase</th><th>aggettivo</th></tr><tr><td>Die Jacke <b>ist</b> blau.</td><td>blau (invariato)</td></tr><tr><td>Die Schuhe <b>sind</b> braun.</td><td>braun (invariato)</td></tr><tr><td>Das Hemd <b>ist</b> weiß.</td><td>weiß (invariato)</td></tr></table><p><b>Colori utili:</b> rot (rosso), blau (blu), grün (verde), gelb (giallo), schwarz (nero), weiß (bianco), grau (grigio), braun (marrone), orange, rosa.</p><p>💡 Attento: davanti al nome l'aggettivo cambia (<i>ein <u>blaues</u> Hemd</i>), ma dopo „sein\" no (<i>das Hemd ist <u>blau</u></i>).</p>", "ex": [{"l": "Die Jeans ", "r": " blau.", "o": ["ist", "bin", "sind", "bist"], "c": 0, "e": "„die Jeans\" (sing.) → <b>ist</b> blau."}, {"l": "Meine Schuhe ", "r": " braun.", "o": ["ist", "sind", "bin", "seid"], "c": 1, "e": "plurale → <b>sind</b> braun."}, {"l": "Welche Farbe hat Gras? — Es ist ", "r": ".", "o": ["grün", "rot", "blau", "gelb"], "c": 0, "e": "l'erba è <b>grün</b> (verde)."}, {"l": "Schnee ist ", "r": ".", "o": ["schwarz", "weiß", "grün", "rot"], "c": 1, "e": "la neve è <b>weiß</b> (bianca)."}]}, "wortschatz": [{"de": "die Kleidung", "it": "l'abbigliamento", "exde": "Ich kaufe neue Kleidung.", "exit": "Compro vestiti nuovi."}, {"de": "das Hemd", "it": "la camicia", "exde": "Das Hemd ist weiß.", "exit": "La camicia è bianca."}, {"de": "die Hose", "it": "i pantaloni", "exde": "Die Hose ist zu lang.", "exit": "I pantaloni sono troppo lunghi."}, {"de": "die Jacke", "it": "la giacca", "exde": "Nimm eine warme Jacke.", "exit": "Prendi una giacca calda."}, {"de": "der Schuh", "it": "la scarpa", "exde": "Meine Schuhe sind neu.", "exit": "Le mie scarpe sono nuove."}, {"de": "tragen", "it": "indossare", "exde": "Ich trage gern Blau.", "exit": "Mi piace vestirmi di blu."}, {"de": "rot", "it": "rosso", "exde": "Der Apfel ist rot.", "exit": "La mela è rossa."}, {"de": "blau", "it": "blu", "exde": "Der Himmel ist blau.", "exit": "Il cielo è blu."}, {"de": "grün", "it": "verde", "exde": "Das Gras ist grün.", "exit": "L'erba è verde."}, {"de": "schwarz", "it": "nero", "exde": "Ich trage oft Schwarz.", "exit": "Vesto spesso di nero."}, {"de": "weiß", "it": "bianco", "exde": "Das Hemd ist weiß.", "exit": "La camicia è bianca."}, {"de": "die Farbe", "it": "il colore", "exde": "Welche Farbe magst du?", "exit": "Che colore ti piace?"}], "idiome": [{"de": "alles in Butter", "lit": "Tutto nel burro.", "mean": "Va tutto bene, tutto a posto.", "it": "Tutto a posto / liscio come l'olio.", "exde": "Keine Sorge, alles in Butter!", "exit": "Tranquillo, è tutto a posto!"}, {"de": "schwarzsehen", "lit": "Vedere nero.", "mean": "Essere pessimisti, vedere tutto negativo.", "it": "Vedere tutto nero / essere pessimisti.", "exde": "Sei nicht so negativ, du siehst immer schwarz.", "exit": "Non essere così negativo, vedi sempre tutto nero."}], "schreiben": {"impuls": "Beschreib dein Lieblingskleidungsstück: Was ist es, welche Farbe hat es und wann trägst du es?", "fragen": ["Ist Mode wichtig für dich, oder zählt nur der Komfort? Begründe.", "Sagt Kleidung etwas über einen Menschen aus? Was meinst du?"]}, "freunde": [{"de": "der Doktor", "it": "dottore"}, {"de": "die Medizin", "it": "medicina"}, {"de": "die Rose", "it": "rosa"}, {"de": "der Salat", "it": "insalata (≈ salad)"}, {"de": "die Tomate", "it": "pomodoro (≈ tomato)"}, {"de": "die Banane", "it": "banana"}], "falsch": [{"de": "das Gift", "it": "il veleno", "warn": "NON „regalo\" (gift)"}, {"de": "der Chef", "it": "il capo", "warn": "NON il cuoco (= der Koch)"}, {"de": "kalt", "it": "freddo", "warn": "NON „caldo\": è l'opposto!"}, {"de": "die Firma", "it": "la ditta / azienda", "warn": "NON la firma (= die Unterschrift)"}, {"de": "das Regal", "it": "lo scaffale", "warn": "NON il regalo (= das Geschenk)"}], "lit": {"de": "Wer fremde Sprachen nicht kennt, weiß nichts von seiner eigenen.", "it": "Chi non conosce lingue straniere non sa nulla della propria.", "src": "J. W. Goethe"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [], "song1": {"id": "DraA3PUuoQc", "artist": "AnnenMayKantereit", "titel": "Pocahontas"}, "song2": {"id": "1gDbpWC_9pE", "artist": "Sarah Connor", "titel": "Wie schön du bist"}, "articles": [{"title": "Wikipedia: Kleidung", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Kleidung"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Im Restaurant — Al ristorante", "level": "A1", "lesen": {"title": "Ein Abend im Restaurant", "text": "Heute Abend gehen wir essen, denn meine Schwester hat Geburtstag. Wir haben einen Tisch für vier Personen reserviert. Das Restaurant ist gemütlich und nicht zu teuer. Der Kellner bringt uns die Speisekarte und wir schauen lange. Es gibt so viele leckere Gerichte! Meine Schwester nimmt eine Suppe und einen Salat, mein Vater bestellt ein Schnitzel mit Pommes. Ich kann mich nicht entscheiden, also nehme ich am Ende eine Pizza. Zum Trinken bestellen wir Wasser und eine Limonade. Das Essen schmeckt wunderbar. Am Ende singen alle „Happy Birthday\" und es gibt sogar einen kleinen Kuchen mit einer Kerze. Ein schöner Abend!", "glos": {"essen gehen": "andare a mangiare fuori", "Geburtstag": "compleanno", "Tisch": "tavolo", "reserviert": "prenotato", "gemütlich": "accogliente", "teuer": "caro", "Kellner": "cameriere", "Speisekarte": "menù", "Gerichte": "piatti", "Suppe": "zuppa", "Salat": "insalata", "bestellt": "ordina", "Schnitzel": "cotoletta", "Pommes": "patatine", "entscheiden": "decidere", "schmeckt": "sa di buono", "Kerze": "candela"}, "q": [{"q": "Warum gehen sie ins Restaurant?", "o": ["Sie haben Hunger", "Die Schwester hat Geburtstag", "Es regnet"], "c": 1, "e": "„meine Schwester hat Geburtstag\"."}, {"q": "Was bestellt der Vater?", "o": ["Eine Pizza", "Ein Schnitzel mit Pommes", "Eine Suppe"], "c": 1, "e": "„mein Vater bestellt ein Schnitzel mit Pommes\"."}, {"q": "Was gibt es am Ende?", "o": ["Einen Kuchen mit Kerze", "Nichts", "Eine Rechnung"], "c": 0, "e": "„einen kleinen Kuchen mit einer Kerze\"."}], "frage": "Gehst du gern ins Restaurant? Was bestellst du am liebsten?"}, "artikel": {"title": "Trinkgeld in Deutschland: Wie viel ist normal?", "text": "In Deutschland gibt man im Restaurant fast immer ein Trinkgeld, wenn man zufrieden war. Aber wie viel ist richtig? Eine einfache Regel sagt: etwa zehn Prozent. Bei einer Rechnung von zwanzig Euro rundet man also auf zweiundzwanzig Euro auf. Wichtig ist: Man legt das Geld nicht einfach auf den Tisch wie in manchen Ländern. Stattdessen sagt man dem Kellner direkt, wie viel man zahlen möchte. Wenn die Rechnung 18,50 Euro ist und man 20 Euro geben will, sagt man einfach „Zwanzig, bitte\". Trinkgeld ist kein Muss, aber es gehört zur Höflichkeit. Wer guten Service bekommt, bedankt sich auf diese Weise.", "glos": {"Trinkgeld": "mancia", "zufrieden": "soddisfatto", "Regel": "regola", "Prozent": "percento", "Rechnung": "conto", "rundet … auf": "arrotonda", "stattdessen": "invece", "direkt": "direttamente", "zahlen": "pagare", "Muss": "obbligo", "Höflichkeit": "cortesia", "Service": "servizio", "bedankt sich": "ringrazia"}, "q": [{"q": "Wie viel Trinkgeld ist üblich?", "o": ["50 Prozent", "Etwa 10 Prozent", "Gar nichts"], "c": 1, "e": "„etwa zehn Prozent\"."}, {"q": "Wie gibt man das Trinkgeld?", "o": ["Man legt es auf den Tisch", "Man sagt dem Kellner den Betrag", "Man gibt es nie"], "c": 1, "e": "„sagt man dem Kellner direkt, wie viel man zahlen möchte\"."}], "news": "Trinkgeld Restaurant Deutschland"}, "dialog": {"title": "Bestellen und bezahlen", "lines": [{"who": "Kellner", "de": "Guten Abend! Haben Sie schon gewählt?"}, {"who": "Gast", "de": "Ja. Ich hätte gern die Tomatensuppe als Vorspeise."}, {"who": "Kellner", "de": "Sehr gern. Und als Hauptgericht?"}, {"who": "Gast", "de": "Das Schnitzel mit Kartoffeln, bitte."}, {"who": "Kellner", "de": "Möchten Sie etwas trinken?"}, {"who": "Gast", "de": "Ein großes Wasser, bitte."}, {"who": "Kellner", "de": "Gerne. … So, hat es Ihnen geschmeckt?"}, {"who": "Gast", "de": "Ja, sehr gut, danke! Ich würde gern zahlen."}, {"who": "Kellner", "de": "Natürlich. Das macht 19,50 Euro."}, {"who": "Gast", "de": "Zweiundzwanzig, bitte. Stimmt so."}, {"who": "Kellner", "de": "Vielen Dank! Schönen Abend noch."}], "q": [{"q": "Was nimmt der Gast als Vorspeise?", "o": ["Salat", "Tomatensuppe", "Nichts"], "c": 1, "e": "„die Tomatensuppe als Vorspeise\"."}, {"q": "Was trinkt der Gast?", "o": ["Limonade", "Ein großes Wasser", "Wein"], "c": 1, "e": "„Ein großes Wasser, bitte\"."}, {"q": "Wie viel zahlt er am Ende?", "o": ["19,50 €", "22 € (mit Trinkgeld)", "18 €"], "c": 1, "e": "„Zweiundzwanzig, bitte. Stimmt so\"."}]}, "musik": {"key": "forster", "task": "Mentre ascolti, immagina di essere a cena con amici. Cogli le parole legate alle persone e ai sentimenti. Canta il ritornello: ti aiuta con la pronuncia.", "level": "A2 · melodico"}, "sprechen": {"read": "Guten Abend! Ich hätte gern die Tomatensuppe als Vorspeise und das Schnitzel mit Kartoffeln. Zum Trinken ein großes Wasser, bitte. … Es hat sehr gut geschmeckt. Ich würde gern zahlen.", "prompts": [{"q": "Was isst du am liebsten im Restaurant?", "e": "Am liebsten esse ich …"}, {"q": "Was bestellst du zu trinken?", "e": "Ich bestelle meistens …"}, {"q": "Gibst du Trinkgeld? Wie viel?", "e": "Ja/Nein, ich gebe normalerweise …"}], "scenario": "Du bist im Restaurant. Bestell eine Vorspeise, ein Hauptgericht und ein Getränk, dann frag nach der Rechnung."}, "grammatik": {"titel": "Modalverben: möchten, können, müssen", "regel_html": "<p>I <b>verbi modali</b> esprimono desiderio, capacità o necessità. La regola d'oro: il modale è coniugato al <b>2° posto</b>, e l'altro verbo va <b>all'infinito alla fine</b> della frase.</p><table class='gtab'><tr><th></th><th>möchten (vorrei)</th><th>können (potere)</th><th>müssen (dovere)</th></tr><tr><td>ich</td><td>möchte</td><td>kann</td><td>muss</td></tr><tr><td>du</td><td>möchtest</td><td>kannst</td><td>musst</td></tr><tr><td>er/sie</td><td>möchte</td><td>kann</td><td>muss</td></tr><tr><td>wir</td><td>möchten</td><td>können</td><td>müssen</td></tr></table><p><b>Esempi:</b> <i>Ich <u>möchte</u> eine Pizza <u>essen</u>.</i> · <i>Wir <u>können</u> hier <u>bezahlen</u>.</i> · <i>Du <u>musst</u> den Tisch <u>reservieren</u>.</i></p><p>💡 „möchten\" è la forma gentile per ordinare al ristorante: <i>Ich möchte … bitte.</i></p>", "ex": [{"l": "Ich ", "r": " eine Suppe bestellen.", "o": ["möchte", "möchtest", "muss nicht", "kann nicht"], "c": 0, "e": "desiderio gentile: <b>möchte</b> + infinito."}, {"l": "", "r": " du mir die Speisekarte geben?", "o": ["Kann", "Kannst", "Muss", "Möchte"], "c": 1, "e": "domanda con „du\": <b>Kannst</b> du …?"}, {"l": "Wir ", "r": " den Tisch reservieren.", "o": ["müssen", "muss", "möchtest", "kannst"], "c": 0, "e": "„wir\" → <b>müssen</b> + infinito."}, {"l": "Ich ", "r": " heute leider nicht kommen.", "o": ["kann", "kannst", "möchte", "muss"], "c": 0, "e": "capacità (impossibilità): <b>kann</b> nicht kommen."}]}, "wortschatz": [{"de": "das Restaurant", "it": "il ristorante", "exde": "Das Restaurant ist voll.", "exit": "Il ristorante è pieno."}, {"de": "der Kellner", "it": "il cameriere", "exde": "Der Kellner ist freundlich.", "exit": "Il cameriere è gentile."}, {"de": "die Speisekarte", "it": "il menù", "exde": "Die Speisekarte, bitte.", "exit": "Il menù, per favore."}, {"de": "bestellen", "it": "ordinare", "exde": "Was möchtest du bestellen?", "exit": "Cosa vuoi ordinare?"}, {"de": "die Vorspeise", "it": "l'antipasto", "exde": "Als Vorspeise nehme ich Suppe.", "exit": "Come antipasto prendo la zuppa."}, {"de": "das Hauptgericht", "it": "il piatto principale", "exde": "Das Hauptgericht ist lecker.", "exit": "Il piatto principale è gustoso."}, {"de": "die Rechnung", "it": "il conto", "exde": "Die Rechnung, bitte!", "exit": "Il conto, per favore!"}, {"de": "zahlen", "it": "pagare", "exde": "Ich möchte zahlen.", "exit": "Vorrei pagare."}, {"de": "das Trinkgeld", "it": "la mancia", "exde": "Wir geben Trinkgeld.", "exit": "Lasciamo la mancia."}, {"de": "reservieren", "it": "prenotare", "exde": "Ich habe einen Tisch reserviert.", "exit": "Ho prenotato un tavolo."}, {"de": "lecker", "it": "buono/gustoso", "exde": "Das Essen ist lecker!", "exit": "Il cibo è buonissimo!"}, {"de": "satt", "it": "sazio", "exde": "Ich bin satt.", "exit": "Sono sazio."}], "idiome": [{"de": "Das Auge isst mit.", "lit": "Anche l'occhio mangia.", "mean": "La presentazione del cibo conta, non solo il sapore.", "it": "Anche l'occhio vuole la sua parte.", "exde": "Schön angerichtet — das Auge isst mit!", "exit": "Bel piatto: anche l'occhio vuole la sua parte!"}, {"de": "Hunger haben wie ein Bär", "lit": "Avere una fame da orso.", "mean": "Avere moltissima fame.", "it": "Avere una fame da lupi.", "exde": "Nach dem Sport habe ich Hunger wie ein Bär.", "exit": "Dopo lo sport ho una fame da lupi."}], "schreiben": {"impuls": "Beschreib dein Lieblingsrestaurant: Wo ist es, was isst du dort und warum magst du es?", "fragen": ["Kochst du lieber selbst oder gehst du lieber essen? Warum?", "Was sagt das Essen in einem Restaurant über ein Land oder eine Kultur aus?"]}, "freunde": [{"de": "die Tomate", "it": "pomodoro (≈ tomato)"}, {"de": "die Banane", "it": "banana"}, {"de": "der Tee", "it": "tè / tea"}, {"de": "die Lampe", "it": "lampada / lamp"}, {"de": "die Garage", "it": "garage"}, {"de": "die Schokolade", "it": "cioccolato (≈ chocolate)"}], "falsch": [{"de": "die Firma", "it": "la ditta / azienda", "warn": "NON la firma (= die Unterschrift)"}, {"de": "das Regal", "it": "lo scaffale", "warn": "NON il regalo (= das Geschenk)"}, {"de": "eventuell", "it": "forse / se necessario", "warn": "NON „eventually\" (= schließlich)"}, {"de": "das Handy", "it": "il cellulare", "warn": "NON „handy / pratico\""}, {"de": "die Kantine", "it": "la mensa", "warn": "NON la cantina (= der Keller)"}], "lit": {"de": "Es war einmal …", "it": "C'era una volta …", "src": "Brüder Grimm, Märchen"}, "trad": {"id": "gedanken", "title": "Die Gedanken sind frei", "artist": "Volkslied", "note": "Canto popolare sulla libertà di pensiero, amatissimo in Germania.", "ytq": "Die Gedanken sind frei Lied", "de": ["Die Gedanken sind frei,", "wer kann sie erraten?", "Sie fliehen vorbei", "wie nächtliche Schatten.", "Kein Mensch kann sie wissen,", "kein Jäger erschießen;", "es bleibet dabei:", "die Gedanken sind frei!"], "it": ["I pensieri sono liberi,", "chi può indovinarli?", "Volano via", "come ombre nella notte.", "Nessuno può conoscerli,", "nessun cacciatore può abbatterli;", "resta così:", "i pensieri sono liberi!"]}, "voice": {"id": "kRq3WzSwUw0", "t": "Straßeninterviews in Magdeburg", "note": "Ascolto autentico con sottotitoli tedeschi."}, "gram_extra": [{"de": "Ich möchte bitte zahlen.", "it": "Vorrei pagare, per favore."}, {"de": "Können wir die Karte sehen?", "it": "Possiamo vedere il menù?"}], "song1": {"id": "1SG5A3PYaUs", "artist": "Herbert Grönemeyer", "titel": "Mensch"}, "song2": {"id": "AvYwpEDfOWk", "artist": "Howard Carpendale & Stereoact", "titel": "Ti Amo (Remix)", "original": "Versione moderna di „Ti amo\" (Umberto Tozzi)."}, "articles": [{"title": "Wikipedia: Im", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Im"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Tiere — Gli animali", "level": "A1", "lesen": {"title": "Unser Hund Bello", "text": "Wir haben ein Haustier: einen Hund. Er heißt Bello und ist drei Jahre alt. Bello ist braun und weiß und hat lange Ohren. Jeden Morgen weckt er mich, weil er nach draußen will. Wir gehen dann zusammen in den Park. Dort rennt er gern hinter dem Ball her und spielt mit anderen Hunden. Bello ist sehr freundlich, aber wenn es klingelt, bellt er laut. Am Abend liegt er müde auf seinem Platz und schläft. Meine kleine Schwester möchte auch eine Katze, aber meine Mutter sagt: „Ein Tier ist genug!\" Ich finde, Bello gehört einfach zu unserer Familie. Ohne ihn wäre es zu Hause viel zu still.", "glos": {"Haustier": "animale domestico", "Hund": "cane", "Ohren": "orecchie", "weckt": "sveglia", "draußen": "fuori", "Park": "parco", "rennt": "corre", "Ball": "palla", "spielt": "gioca", "freundlich": "amichevole", "klingelt": "suona (campanello)", "bellt": "abbaia", "müde": "stanco", "schläft": "dorme", "Katze": "gatto", "Tier": "animale", "still": "silenzioso"}, "q": [{"q": "Wie alt ist Bello?", "o": ["Ein Jahr", "Drei Jahre", "Zehn Jahre"], "c": 1, "e": "„ist drei Jahre alt\"."}, {"q": "Was macht Bello, wenn es klingelt?", "o": ["Er schläft", "Er bellt laut", "Er rennt weg"], "c": 1, "e": "„wenn es klingelt, bellt er laut\"."}, {"q": "Was möchte die kleine Schwester?", "o": ["Einen zweiten Hund", "Eine Katze", "Einen Vogel"], "c": 1, "e": "„möchte auch eine Katze\"."}], "frage": "Hast du ein Haustier oder hättest du gern eins? Welches Tier magst du am liebsten?"}, "artikel": {"title": "Warum Haustiere gut für uns sind", "text": "Millionen Menschen in Deutschland haben ein Haustier — meistens einen Hund oder eine Katze. Aber Tiere sind nicht nur nett: Sie tun uns auch gut. Wer einen Hund hat, geht jeden Tag nach draußen und bewegt sich mehr. Das ist gesund für Körper und Kopf. Tiere helfen auch gegen Einsamkeit. Sie hören zu, ohne zu urteilen, und sie freuen sich immer, wenn man nach Hause kommt. Studien zeigen sogar, dass das Streicheln einer Katze den Stress senken kann. Natürlich ist ein Tier auch viel Arbeit: Es braucht Futter, Pflege und Zeit. Wer ein Haustier nimmt, übernimmt Verantwortung für ein ganzes Leben.", "glos": {"Millionen": "milioni", "Haustier": "animale domestico", "bewegt sich": "si muove", "gesund": "sano", "Einsamkeit": "solitudine", "zuhören": "ascoltare", "urteilen": "giudicare", "Studien": "studi", "Streicheln": "accarezzare", "Stress": "stress", "senken": "abbassare", "Futter": "cibo (animali)", "Pflege": "cure", "Verantwortung": "responsabilità"}, "q": [{"q": "Was ist gut an einem Hund?", "o": ["Man bewegt sich mehr", "Man schläft mehr", "Man isst mehr"], "c": 0, "e": "„geht jeden Tag nach draußen und bewegt sich mehr\"."}, {"q": "Was kann das Streicheln einer Katze bewirken?", "o": ["Mehr Stress", "Weniger Stress", "Nichts"], "c": 1, "e": "„den Stress senken kann\"."}], "news": "Haustiere Gesundheit Hund Katze"}, "dialog": {"title": "Beim Tierarzt", "lines": [{"who": "Tierärztin", "de": "Guten Tag! Wer ist denn dieser Süße?"}, {"who": "Herr Weber", "de": "Das ist Bello. Er frisst seit gestern nicht mehr."}, {"who": "Tierärztin", "de": "Oh je. Ist er auch ruhiger als sonst?"}, {"who": "Herr Weber", "de": "Ja, er liegt nur in seinem Körbchen."}, {"who": "Tierärztin", "de": "Ich schaue ihn mir kurz an. … Sein Bauch tut ihm weh."}, {"who": "Herr Weber", "de": "Ist es etwas Schlimmes?"}, {"who": "Tierärztin", "de": "Nein, keine Sorge. Er braucht nur eine leichte Diät."}, {"who": "Herr Weber", "de": "Was darf er denn essen?"}, {"who": "Tierärztin", "de": "Zwei Tage nur Reis und etwas Hühnchen. Dann geht es ihm besser."}, {"who": "Herr Weber", "de": "Vielen Dank! Das beruhigt mich."}], "q": [{"q": "Was ist das Problem mit Bello?", "o": ["Er bellt zu viel", "Er frisst nicht mehr", "Er ist zu dick"], "c": 1, "e": "„Er frisst seit gestern nicht mehr\"."}, {"q": "Was tut Bello weh?", "o": ["Der Kopf", "Der Bauch", "Das Bein"], "c": 1, "e": "„Sein Bauch tut ihm weh\"."}, {"q": "Was darf Bello essen?", "o": ["Nichts", "Reis und etwas Hühnchen", "Nur Wasser"], "c": 1, "e": "„nur Reis und etwas Hühnchen\"."}]}, "musik": {"key": "bourani", "task": "Ascolta e rilassati. Prova a riconoscere parole che già conosci. Non serve capire tutto: l'importante è abituare l'orecchio al suono del tedesco.", "level": "A2–B1 · energico"}, "sprechen": {"read": "Das ist mein Hund Bello. Er ist drei Jahre alt und sehr freundlich. Jeden Morgen gehen wir zusammen in den Park. Dort spielt er mit dem Ball und mit anderen Hunden.", "prompts": [{"q": "Hast du ein Haustier? Wie heißt es?", "e": "Ja, ich habe … / Nein, aber ich hätte gern …"}, {"q": "Welches Tier magst du am liebsten und warum?", "e": "Ich mag … am liebsten, weil …"}, {"q": "Was muss man für ein Haustier tun?", "e": "Man muss … (füttern, spielen, …)"}], "scenario": "Dein Haustier ist krank. Erklär dem Tierarzt, was es hat und seit wann."}, "grammatik": {"titel": "Der Plural der Nomen (il plurale)", "regel_html": "<p>In tedesco il plurale dei nomi si forma in modi diversi: non c'è una sola regola, quindi conviene impararlo <b>insieme alla parola</b>. Ecco i gruppi più comuni:</p><table class='gtab'><tr><th>tipo</th><th>singolare → plurale</th></tr><tr><td>+ -e</td><td>der Hund → die Hund<b>e</b></td></tr><tr><td>+ -er (+ Umlaut)</td><td>das Kind → die Kind<b>er</b> · das Buch → die B<b>ü</b>ch<b>er</b></td></tr><tr><td>+ -(e)n</td><td>die Katze → die Katze<b>n</b> · die Frau → die Frau<b>en</b></td></tr><tr><td>+ -s</td><td>das Auto → die Auto<b>s</b> (spesso parole straniere)</td></tr><tr><td>solo Umlaut</td><td>der Vogel → die V<b>ö</b>gel</td></tr></table><p>💡 Al plurale l'articolo determinativo è sempre <b>die</b>: <i>die Hunde, die Katzen, die Kinder</i>.</p>", "ex": [{"l": "ein Hund → zwei ", "r": "", "o": ["Hunde", "Hunds", "Hunden", "Hünde"], "c": 0, "e": "+ -e: <b>Hunde</b>."}, {"l": "eine Katze → drei ", "r": "", "o": ["Katzes", "Katzen", "Katze", "Kätze"], "c": 1, "e": "+ -n: <b>Katzen</b>."}, {"l": "ein Kind → vier ", "r": "", "o": ["Kinder", "Kinds", "Kinde", "Kindern"], "c": 0, "e": "+ -er: <b>Kinder</b>."}, {"l": "ein Auto → fünf ", "r": "", "o": ["Autoen", "Auten", "Autos", "Auti"], "c": 2, "e": "+ -s: <b>Autos</b>."}]}, "wortschatz": [{"de": "das Tier", "it": "l'animale", "exde": "Ich liebe Tiere.", "exit": "Amo gli animali."}, {"de": "der Hund", "it": "il cane", "exde": "Der Hund bellt.", "exit": "Il cane abbaia."}, {"de": "die Katze", "it": "il gatto", "exde": "Die Katze schläft.", "exit": "Il gatto dorme."}, {"de": "der Vogel", "it": "l'uccello", "exde": "Der Vogel singt.", "exit": "L'uccello canta."}, {"de": "das Pferd", "it": "il cavallo", "exde": "Das Pferd ist groß.", "exit": "Il cavallo è grande."}, {"de": "der Fisch", "it": "il pesce", "exde": "Der Fisch schwimmt.", "exit": "Il pesce nuota."}, {"de": "das Haustier", "it": "l'animale domestico", "exde": "Hast du ein Haustier?", "exit": "Hai un animale domestico?"}, {"de": "füttern", "it": "dare da mangiare", "exde": "Ich füttere die Katze.", "exit": "Do da mangiare al gatto."}, {"de": "der Bauernhof", "it": "la fattoria", "exde": "Auf dem Bauernhof leben Kühe.", "exit": "Nella fattoria vivono le mucche."}, {"de": "wild", "it": "selvatico", "exde": "Der Wolf ist ein wildes Tier.", "exit": "Il lupo è un animale selvatico."}, {"de": "süß", "it": "carino/dolce", "exde": "Der Hund ist so süß!", "exit": "Il cane è così carino!"}, {"de": "der Schwanz", "it": "la coda", "exde": "Der Hund wedelt mit dem Schwanz.", "exit": "Il cane scodinzola."}], "idiome": [{"de": "Da liegt der Hund begraben.", "lit": "Lì è sepolto il cane.", "mean": "È questo il vero problema / il nocciolo della questione.", "it": "Qui sta il busillis / il problema.", "exde": "Kein Geld? Da liegt der Hund begraben!", "exit": "Niente soldi? È qui il problema!"}, {"de": "die Katze im Sack kaufen", "lit": "Comprare il gatto nel sacco.", "mean": "Comprare qualcosa senza averlo visto/controllato.", "it": "Comprare a scatola chiusa.", "exde": "Probier es erst — kauf nicht die Katze im Sack.", "exit": "Provalo prima: non comprare a scatola chiusa."}], "schreiben": {"impuls": "Beschreib ein Tier, das du magst (oder dein Haustier): Wie sieht es aus, was macht es gern?", "fragen": ["Sollte jeder, der Zeit hat, ein Tier aus dem Tierheim aufnehmen? Was meinst du?", "Tiere im Zoo: sinnvoll oder nicht? Begründe deine Meinung."]}, "freunde": [{"de": "die Garage", "it": "garage"}, {"de": "die Schokolade", "it": "cioccolato (≈ chocolate)"}, {"de": "der Tiger", "it": "tigre"}, {"de": "die Familie", "it": "famiglia"}, {"de": "die Familie", "it": "famiglia / family"}, {"de": "das Hotel", "it": "hotel"}], "falsch": [{"de": "das Handy", "it": "il cellulare", "warn": "NON „handy / pratico\""}, {"de": "die Kantine", "it": "la mensa", "warn": "NON la cantina (= der Keller)"}, {"de": "die Note", "it": "il voto / la nota musicale", "warn": "NON la notte (= die Nacht)"}, {"de": "die Art", "it": "il tipo / il modo", "warn": "NON l'arte (= die Kunst)"}, {"de": "brav", "it": "ubbidiente / buono", "warn": "NON „bravo / capace\""}], "lit": {"de": "Mut verloren – alles verloren.", "it": "Perso il coraggio, perso tutto.", "src": "J. W. Goethe"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Im Zoo gibt es viele Tiere: Löwen, Affen und Vögel.", "it": "Allo zoo ci sono molti animali: leoni, scimmie e uccelli."}, {"de": "Meine zwei Katzen schlafen den ganzen Tag.", "it": "Le mie due gatte dormono tutto il giorno."}], "song1": {"id": "xSWJBClrmgo", "artist": "Herbert Grönemeyer", "titel": "Der Weg"}, "song2": {"id": "qkrrqTEH_zg", "artist": "Sarah Connor", "titel": "Vincent"}, "articles": [{"title": "Wikipedia: Tiere", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Tiere"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Arbeit & Tagesablauf — Lavoro e giornata", "level": "A2", "lesen": {"title": "Ein ganz normaler Arbeitstag", "text": "Mein Wecker klingelt jeden Morgen um halb sieben. Ehrlich gesagt hasse ich diesen Moment, aber ich stehe trotzdem auf. Nach einer schnellen Dusche und einem Kaffee fahre ich mit dem Bus ins Büro. Ich arbeite in einer kleinen Firma und bin für die Kunden zuständig. Meistens beantworte ich E-Mails, telefoniere und sitze in Besprechungen. Die Mittagspause verbringe ich oft mit Kollegen in der Kantine — das ist der schönste Teil des Tages. Am Nachmittag lässt meine Konzentration manchmal nach, deshalb trinke ich dann noch einen Espresso. Gegen fünf Uhr habe ich Feierabend. Zu Hause koche ich, lese ein Buch oder treffe Freunde. So sieht mein Alltag aus — nicht spektakulär, aber ich bin zufrieden.", "glos": {"Wecker": "sveglia", "klingelt": "suona", "halb sieben": "6:30", "hasse": "odio", "trotzdem": "comunque", "Dusche": "doccia", "Büro": "ufficio", "Firma": "azienda", "Kunden": "clienti", "zuständig": "responsabile", "beantworte": "rispondo", "Besprechungen": "riunioni", "Mittagspause": "pausa pranzo", "Kollegen": "colleghi", "Konzentration": "concentrazione", "nachlassen": "calare", "Feierabend": "fine lavoro", "Alltag": "quotidianità", "zufrieden": "soddisfatto"}, "q": [{"q": "Wann klingelt der Wecker?", "o": ["Um sechs", "Um halb sieben", "Um sieben"], "c": 1, "e": "„um halb sieben\" = 6:30."}, {"q": "Was ist der schönste Teil des Tages?", "o": ["Die Besprechung", "Die Mittagspause mit Kollegen", "Der Feierabend"], "c": 1, "e": "„der schönste Teil des Tages\"."}, {"q": "Was macht die Person nach der Arbeit NICHT?", "o": ["Kochen", "Lesen", "Ins Kino gehen"], "c": 2, "e": "Genannt werden: kochen, lesen, Freunde treffen."}], "frage": "Beschreib deinen typischen Tag. Was ist die beste und die schlimmste Zeit des Tages?"}, "artikel": {"title": "Die Vier-Tage-Woche: Traum oder Zukunft?", "text": "Immer mehr Firmen in Deutschland und in Europa testen die Vier-Tage-Woche. Die Idee ist einfach: Die Menschen arbeiten nur an vier Tagen, bekommen aber den gleichen Lohn. Viele Studien zeigen überraschende Ergebnisse. Die Mitarbeiter sind oft weniger gestresst, seltener krank und sogar produktiver. Sie haben mehr Zeit für die Familie, für Sport und für sich selbst. Doch nicht alle sind begeistert. Manche Chefs befürchten, dass die Arbeit liegen bleibt. Und in einigen Berufen, zum Beispiel in Krankenhäusern, ist eine kürzere Woche schwer umzusetzen. Trotzdem glauben viele Experten: Die Art, wie wir arbeiten, wird sich in den nächsten Jahren stark verändern.", "glos": {"testen": "sperimentano", "gleichen": "stesso", "Lohn": "stipendio", "Studien": "studi", "Ergebnisse": "risultati", "Mitarbeiter": "dipendenti", "gestresst": "stressati", "seltener": "più raramente", "krank": "malati", "produktiver": "più produttivi", "begeistert": "entusiasti", "Chefs": "capi", "befürchten": "temono", "liegen bleibt": "resta indietro", "umzusetzen": "da realizzare", "verändern": "cambiare"}, "q": [{"q": "Wie viel Lohn bekommen die Mitarbeiter bei der Vier-Tage-Woche?", "o": ["Weniger Lohn", "Den gleichen Lohn", "Mehr Lohn"], "c": 1, "e": "„bekommen aber den gleichen Lohn\"."}, {"q": "Was befürchten manche Chefs?", "o": ["Dass die Arbeit liegen bleibt", "Dass alle kündigen", "Dass es zu teuer ist"], "c": 0, "e": "„dass die Arbeit liegen bleibt\"."}], "news": "Vier-Tage-Woche Deutschland"}, "dialog": {"title": "Ein Problem im Büro", "lines": [{"who": "Chefin", "de": "Herr Klein, haben Sie kurz Zeit?"}, {"who": "Klein", "de": "Natürlich. Worum geht es?"}, {"who": "Chefin", "de": "Das Projekt für den Kunden ist noch nicht fertig. Warum?"}, {"who": "Klein", "de": "Es tut mir leid. Ich hatte diese Woche sehr viele Termine."}, {"who": "Chefin", "de": "Das verstehe ich, aber der Kunde wartet schon."}, {"who": "Klein", "de": "Ich weiß. Kann ich es bis Freitag fertig machen?"}, {"who": "Chefin", "de": "Freitag ist zu spät. Geht es bis Mittwoch?"}, {"who": "Klein", "de": "Bis Mittwoch wird schwierig, aber ich versuche es."}, {"who": "Chefin", "de": "Gut. Wenn Sie Hilfe brauchen, sagen Sie Bescheid."}, {"who": "Klein", "de": "Danke, das ist nett. Ich melde mich."}], "q": [{"q": "Was ist das Problem?", "o": ["Herr Klein ist krank", "Ein Projekt ist nicht fertig", "Der Kunde zahlt nicht"], "c": 1, "e": "„Das Projekt … ist noch nicht fertig\"."}, {"q": "Bis wann soll Herr Klein es fertig machen?", "o": ["Bis Freitag", "Bis Mittwoch", "Bis Montag"], "c": 1, "e": "„Geht es bis Mittwoch?\""}, {"q": "Was bietet die Chefin an?", "o": ["Mehr Geld", "Hilfe", "Urlaub"], "c": 1, "e": "„Wenn Sie Hilfe brauchen …\"."}]}, "musik": {"key": "bourani", "task": "„Auf uns\" è un brindisi alla vita e all'amicizia. Nel ritornello senti „Auf uns!\" (a noi!). Prova a cogliere le parole „Leben\" (vita) e „Freunde\" (amici). Energico e motivante.", "level": "A2–B1 · energico"}, "sprechen": {"read": "Mein Arbeitstag beginnt um neun Uhr. Zuerst lese ich meine E-Mails, dann habe ich oft Besprechungen. Die Mittagspause mache ich mit Kollegen. Um fünf Uhr habe ich Feierabend und fahre nach Hause.", "prompts": [{"q": "Wann beginnt und endet dein Arbeitstag?", "e": "Mein Tag beginnt um … und endet um …"}, {"q": "Was ist das Stressigste an deinem Tag?", "e": "Am stressigsten ist …"}, {"q": "Was würdest du mit einem freien Tag pro Woche machen?", "e": "Mit einem freien Tag würde ich …"}], "scenario": "Du kommst zu spät zur Arbeit. Entschuldige dich beim Chef und erklär den Grund."}, "grammatik": {"titel": "Trennbare Verben (verbi separabili)", "regel_html": "<p>Molti verbi tedeschi hanno un <b>prefisso separabile</b> (auf-, an-, ein-, mit-, zu-, ab-, vor- …). Nella frase principale il prefisso si <b>stacca</b> e va alla fine.</p><table class='gtab'><tr><th>infinito</th><th>significato</th><th>frase</th></tr><tr><td>aufstehen</td><td>alzarsi</td><td>Ich <b>stehe</b> um 7 Uhr <b>auf</b>.</td></tr><tr><td>anrufen</td><td>telefonare</td><td>Ich <b>rufe</b> dich später <b>an</b>.</td></tr><tr><td>einkaufen</td><td>fare la spesa</td><td>Wir <b>kaufen</b> heute <b>ein</b>.</td></tr><tr><td>mitkommen</td><td>venire (con)</td><td><b>Kommst</b> du <b>mit</b>?</td></tr></table><p>💡 Con un verbo modale o all'infinito il verbo resta unito: <i>Ich muss früh <u>aufstehen</u>.</i> Nel passato (Perfekt): <i>Ich bin <u>aufgestanden</u>.</i></p>", "ex": [{"l": "Ich ", "r": " um sieben Uhr auf.", "o": ["stehe", "stehst", "aufstehe", "steht"], "c": 0, "e": "<b>stehe … auf</b>: il verbo coniugato al 2° posto, il prefisso alla fine."}, {"l": "Rufst du mich später ", "r": "?", "o": ["an", "auf", "aus", "ab"], "c": 0, "e": "<b>anrufen</b> → … <b>an</b> alla fine."}, {"l": "Wir ", "r": " heute zusammen ein.", "o": ["kaufen", "kauft", "einkaufen", "kaufte"], "c": 0, "e": "<b>kaufen … ein</b> (einkaufen)."}, {"l": "Ich muss morgen früh ", "r": ".", "o": ["aufstehen", "stehe auf", "aufstehe", "steht auf"], "c": 0, "e": "Con il modale „muss\" il verbo resta unito: <b>aufstehen</b>."}]}, "wortschatz": [{"de": "die Arbeit", "it": "il lavoro", "exde": "Die Arbeit macht Spaß.", "exit": "Il lavoro mi piace."}, {"de": "das Büro", "it": "l'ufficio", "exde": "Ich arbeite im Büro.", "exit": "Lavoro in ufficio."}, {"de": "der Kollege", "it": "il collega", "exde": "Mein Kollege ist nett.", "exit": "Il mio collega è simpatico."}, {"de": "die Besprechung", "it": "la riunione", "exde": "Die Besprechung dauert lange.", "exit": "La riunione dura a lungo."}, {"de": "der Termin", "it": "l'appuntamento", "exde": "Ich habe einen Termin.", "exit": "Ho un appuntamento."}, {"de": "der Feierabend", "it": "la fine del lavoro", "exde": "Schönen Feierabend!", "exit": "Buona serata (fine lavoro)!"}, {"de": "anrufen", "it": "telefonare", "exde": "Ich rufe dich an.", "exit": "Ti chiamo."}, {"de": "aufstehen", "it": "alzarsi", "exde": "Ich stehe früh auf.", "exit": "Mi alzo presto."}, {"de": "müde", "it": "stanco", "exde": "Ich bin sehr müde.", "exit": "Sono molto stanco."}, {"de": "der Lohn", "it": "lo stipendio", "exde": "Der Lohn ist gut.", "exit": "Lo stipendio è buono."}, {"de": "der Chef", "it": "il capo", "exde": "Mein Chef ist streng.", "exit": "Il mio capo è severo."}, {"de": "schwierig", "it": "difficile", "exde": "Das ist schwierig.", "exit": "È difficile."}], "idiome": [{"de": "Feierabend machen", "lit": "Fare il „Feierabend\".", "mean": "Smettere di lavorare per oggi, staccare.", "it": "Staccare / chiudere bottega.", "exde": "Es ist sechs Uhr — ich mache Feierabend.", "exit": "Sono le sei, stacco."}, {"de": "Das ist nicht mein Bier.", "lit": "Questa non è la mia birra.", "mean": "Non è affar mio, non mi riguarda.", "it": "Non sono affari miei.", "exde": "Frag den Chef, das ist nicht mein Bier.", "exit": "Chiedi al capo, non sono affari miei."}], "schreiben": {"impuls": "Beschreib deinen idealen Arbeitstag. Wie würde er aussehen, wenn du frei wählen könntest?", "fragen": ["Arbeitest du, um zu leben, oder lebst du, um zu arbeiten? Erkläre.", "Wäre eine Vier-Tage-Woche gut für dich? Welche Vor- und Nachteile siehst du?"]}, "freunde": [{"de": "die Familie", "it": "famiglia / family"}, {"de": "das Hotel", "it": "hotel"}, {"de": "der Computer", "it": "computer"}, {"de": "die Musik", "it": "musica / music"}, {"de": "das Problem", "it": "problema / problem"}, {"de": "die Idee", "it": "idea"}], "falsch": [{"de": "die Art", "it": "il tipo / il modo", "warn": "NON l'arte (= die Kunst)"}, {"de": "brav", "it": "ubbidiente / buono", "warn": "NON „bravo / capace\""}, {"de": "also", "it": "quindi / dunque", "warn": "NON „anche\" (= auch)"}, {"de": "fast", "it": "quasi", "warn": "NON „veloce\" (= schnell)"}, {"de": "bald", "it": "presto", "warn": "NON „baldo\""}], "lit": {"de": "Der Worte sind genug gewechselt, lasst mich auch endlich Taten sehn!", "it": "Basta con le parole: fatemi vedere finalmente i fatti!", "src": "J. W. Goethe, Faust"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [{"de": "Der Zug fährt um acht Uhr ab.", "it": "Il treno parte alle otto."}, {"de": "Ich rufe dich heute Abend an.", "it": "Ti chiamo stasera."}], "song1": {"id": "_IZsxfo8ITw", "artist": "Herbert Grönemeyer", "titel": "Männer"}, "song2": {"id": "6z8o7qAIlIU", "artist": "Die Toten Hosen", "titel": "Hier kommt Alex"}, "articles": [{"title": "Wikipedia: Arbeit", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Arbeit"}, {"title": "Klexikon: Beruf (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Beruf"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Gesundheit & Körper — Salute e corpo", "level": "A2", "lesen": {"title": "Beim Arzt", "text": "Seit drei Tagen fühle ich mich nicht gut. Ich habe Halsschmerzen, Kopfschmerzen und ein bisschen Fieber. Heute Morgen habe ich deshalb einen Termin beim Arzt gemacht. Im Wartezimmer saßen schon viele Leute, also musste ich fast eine Stunde warten. Endlich rief die Arzthelferin meinen Namen. Der Arzt war sehr freundlich. Er hat mir in den Hals geschaut und gefragt, wie lange ich die Beschwerden schon habe. Zum Glück ist es nichts Schlimmes, nur eine Erkältung. Er hat mir geraten, viel zu trinken, im Bett zu bleiben und Tee mit Honig zu trinken. Ein Medikament brauche ich nicht. „In ein paar Tagen sind Sie wieder fit\", hat er gesagt. Das hoffe ich sehr.", "glos": {"fühle": "mi sento", "Halsschmerzen": "mal di gola", "Kopfschmerzen": "mal di testa", "Fieber": "febbre", "Termin": "appuntamento", "Wartezimmer": "sala d'attesa", "warten": "aspettare", "Arzthelferin": "assistente", "Hals": "gola", "Beschwerden": "disturbi", "Schlimmes": "grave", "Erkältung": "raffreddore", "geraten": "consigliato", "Bett": "letto", "Honig": "miele", "Medikament": "medicinale", "fit": "in forma", "hoffe": "spero"}, "q": [{"q": "Welche Beschwerden hat die Person nicht?", "o": ["Halsschmerzen", "Bauchschmerzen", "Fieber"], "c": 1, "e": "Citati: Hals-, Kopfschmerzen, Fieber."}, {"q": "Was hat die Person?", "o": ["Eine Grippe", "Eine Erkältung", "Nichts"], "c": 1, "e": "„nur eine Erkältung\"."}, {"q": "Was rät der Arzt?", "o": ["Sport machen", "Viel trinken und im Bett bleiben", "Sofort ein Medikament nehmen"], "c": 1, "e": "„viel zu trinken, im Bett zu bleiben\"."}], "frage": "Was machst du, wenn du krank bist? Gehst du schnell zum Arzt oder wartest du ab?"}, "artikel": {"title": "Schlaf: die beste Medizin", "text": "Viele Menschen unterschätzen, wie wichtig guter Schlaf ist. Wer zu wenig schläft, ist nicht nur müde, sondern wird auch schneller krank, kann sich schlechter konzentrieren und ist oft schlechter Laune. Experten empfehlen für Erwachsene sieben bis acht Stunden Schlaf pro Nacht. Doch genau das fällt vielen schwer. Ein großer Grund ist das Handy: Das blaue Licht vom Bildschirm hält das Gehirn wach. Wer besser schlafen will, sollte das Handy abends weglegen, das Schlafzimmer dunkel und kühl halten und jeden Tag zur gleichen Zeit ins Bett gehen. Schlaf ist keine verlorene Zeit — im Gegenteil. Der Körper und das Gehirn brauchen diese Stunden, um sich zu erholen.", "glos": {"unterschätzen": "sottovalutano", "Schlaf": "sonno", "wenig": "poco", "schläft": "dorme", "Laune": "umore", "empfehlen": "raccomandano", "Erwachsene": "adulti", "Stunden": "ore", "Handy": "cellulare", "Licht": "luce", "Bildschirm": "schermo", "Gehirn": "cervello", "wach": "sveglio", "weglegen": "mettere via", "dunkel": "buio", "kühl": "fresco", "verlorene": "persa", "erholen": "riprendersi"}, "q": [{"q": "Wie viel Schlaf empfehlen Experten?", "o": ["4–5 Stunden", "7–8 Stunden", "10 Stunden"], "c": 1, "e": "„sieben bis acht Stunden\"."}, {"q": "Warum stört das Handy den Schlaf?", "o": ["Es ist laut", "Das blaue Licht hält wach", "Es ist schwer"], "c": 1, "e": "„Das blaue Licht … hält das Gehirn wach\"."}], "news": "gesunder Schlaf Tipps"}, "dialog": {"title": "In der Apotheke", "lines": [{"who": "Apotheker", "de": "Guten Tag, was kann ich für Sie tun?"}, {"who": "Kundin", "de": "Hallo. Ich habe starke Kopfschmerzen. Haben Sie etwas dagegen?"}, {"who": "Apotheker", "de": "Ja. Sind die Schmerzen schon lange da?"}, {"who": "Kundin", "de": "Seit heute Morgen. Es wird immer schlimmer."}, {"who": "Apotheker", "de": "Ich kann Ihnen diese Tabletten geben. Nehmen Sie eine nach dem Essen."}, {"who": "Kundin", "de": "Wie oft am Tag darf ich sie nehmen?"}, {"who": "Apotheker", "de": "Maximal dreimal täglich. Und trinken Sie viel Wasser."}, {"who": "Kundin", "de": "Gut. Brauche ich ein Rezept dafür?"}, {"who": "Apotheker", "de": "Nein, die gibt es ohne Rezept. Das macht fünf Euro."}], "q": [{"q": "Was hat die Kundin?", "o": ["Husten", "Kopfschmerzen", "Fieber"], "c": 1, "e": "„Ich habe starke Kopfschmerzen\"."}, {"q": "Wie oft darf sie die Tabletten nehmen?", "o": ["Einmal", "Maximal dreimal täglich", "Immer"], "c": 1, "e": "„Maximal dreimal täglich\"."}, {"q": "Braucht sie ein Rezept?", "o": ["Ja", "Nein", "Sie weiß es nicht"], "c": 1, "e": "„die gibt es ohne Rezept\"."}]}, "musik": {"key": "forster", "task": "Riascolta „Chöre\" pensando al tema del sostegno e dell'energia. Quando ti senti giù, la musica può aiutare. Concentrati sul ritmo e canta il ritornello.", "level": "A2 · melodico"}, "sprechen": {"read": "Guten Tag. Ich fühle mich nicht gut. Ich habe Kopfschmerzen und ein bisschen Fieber. Können Sie mir etwas empfehlen? Brauche ich ein Rezept oder gibt es das ohne Rezept?", "prompts": [{"q": "Wie fühlst du dich heute?", "e": "Heute fühle ich mich …"}, {"q": "Was machst du für deine Gesundheit?", "e": "Für meine Gesundheit …"}, {"q": "Was ist gesünder: Sport oder gutes Essen? Warum?", "e": "Ich denke, … ist wichtiger, weil …"}], "scenario": "Du bist beim Arzt. Beschreib deine Beschwerden (seit wann, wo) und frag, was du tun sollst."}, "grammatik": {"titel": "Das Perfekt (il passato prossimo)", "regel_html": "<p>Per parlare del passato, nel tedesco parlato si usa quasi sempre il <b>Perfekt</b>: <b>haben/sein</b> (coniugato) + <b>participio</b> alla fine.</p><table class='gtab'><tr><th>infinito</th><th>participio</th><th>frase</th></tr><tr><td>machen</td><td>gemacht</td><td>Ich <b>habe</b> einen Termin <b>gemacht</b>.</td></tr><tr><td>essen</td><td>gegessen</td><td>Ich <b>habe</b> schon <b>gegessen</b>.</td></tr><tr><td>gehen</td><td>gegangen</td><td>Ich <b>bin</b> zum Arzt <b>gegangen</b>.</td></tr><tr><td>fahren</td><td>gefahren</td><td>Wir <b>sind</b> nach Berlin <b>gefahren</b>.</td></tr></table><p>💡 Si usa <b>sein</b> con i verbi di movimento e di cambiamento (gehen, fahren, kommen, aufstehen, werden); con quasi tutti gli altri si usa <b>haben</b>.</p>", "ex": [{"l": "Ich ", "r": " gestern Pizza gegessen.", "o": ["habe", "bin", "hat", "ist"], "c": 0, "e": "essen → <b>haben</b>: ich habe gegessen."}, {"l": "Wir ", "r": " nach Hause gegangen.", "o": ["haben", "sind", "habt", "seid"], "c": 1, "e": "gehen (movimento) → <b>sein</b>: wir sind gegangen."}, {"l": "Was ", "r": " du gestern gemacht?", "o": ["hast", "bist", "habt", "ist"], "c": 0, "e": "<b>hast … gemacht</b>: haben + participio."}, {"l": "Er ", "r": " zum Arzt gefahren.", "o": ["hat", "ist", "habe", "bin"], "c": 1, "e": "fahren (movimento) → <b>sein</b>: er ist gefahren."}]}, "wortschatz": [{"de": "die Gesundheit", "it": "la salute", "exde": "Gesundheit ist das Wichtigste.", "exit": "La salute è la cosa più importante."}, {"de": "der Arzt", "it": "il medico", "exde": "Ich gehe zum Arzt.", "exit": "Vado dal medico."}, {"de": "krank", "it": "malato", "exde": "Ich bin krank.", "exit": "Sono malato."}, {"de": "die Schmerzen", "it": "i dolori", "exde": "Ich habe Schmerzen.", "exit": "Ho dolori."}, {"de": "das Fieber", "it": "la febbre", "exde": "Sie hat hohes Fieber.", "exit": "Ha la febbre alta."}, {"de": "die Erkältung", "it": "il raffreddore", "exde": "Ich habe eine Erkältung.", "exit": "Ho il raffreddore."}, {"de": "das Medikament", "it": "il medicinale", "exde": "Nimm das Medikament.", "exit": "Prendi il medicinale."}, {"de": "die Apotheke", "it": "la farmacia", "exde": "Die Apotheke ist um die Ecke.", "exit": "La farmacia è dietro l'angolo."}, {"de": "sich fühlen", "it": "sentirsi", "exde": "Wie fühlst du dich?", "exit": "Come ti senti?"}, {"de": "der Körper", "it": "il corpo", "exde": "Der Körper braucht Schlaf.", "exit": "Il corpo ha bisogno di sonno."}, {"de": "gesund", "it": "sano", "exde": "Obst ist gesund.", "exit": "La frutta fa bene."}, {"de": "müde", "it": "stanco", "exde": "Ich bin müde und krank.", "exit": "Sono stanco e malato."}], "idiome": [{"de": "Gesundheit geht vor.", "lit": "La salute viene prima.", "mean": "La salute è più importante di tutto il resto.", "it": "Prima la salute.", "exde": "Bleib zu Hause — Gesundheit geht vor.", "exit": "Resta a casa: prima la salute."}, {"de": "auf dem Damm sein", "lit": "Essere sull'argine.", "mean": "Stare bene, essere in forma.", "it": "Essere in forma / a posto.", "exde": "Nach der Grippe bin ich wieder auf dem Damm.", "exit": "Dopo l'influenza sono di nuovo in forma."}], "schreiben": {"impuls": "Schreib über deine Gewohnheiten: Was tust du, um gesund zu bleiben? Was solltest du besser machen?", "fragen": ["Ist die Gesundheit nur Privatsache oder auch Aufgabe des Staates? Was meinst du?", "Schläfst du genug? Was raubt dir am meisten den Schlaf?"]}, "freunde": [{"de": "das Problem", "it": "problema / problem"}, {"de": "die Idee", "it": "idea"}, {"de": "der Moment", "it": "momento"}, {"de": "die Natur", "it": "natura / nature"}, {"de": "die Information", "it": "informazione"}, {"de": "die Situation", "it": "situazione"}], "falsch": [{"de": "fast", "it": "quasi", "warn": "NON „veloce\" (= schnell)"}, {"de": "bald", "it": "presto", "warn": "NON „baldo\""}, {"de": "komisch", "it": "strano (spesso) / buffo", "warn": "attenzione: di solito = strano"}, {"de": "die Birne", "it": "la pera / la lampadina", "warn": "NON „birra\" (= das Bier)"}, {"de": "sensibel", "it": "sensibile / delicato", "warn": "NON „sensato\" (= vernünftig)"}], "lit": {"de": "Der Mensch ist frei geschaffen, ist frei.", "it": "L'uomo è creato libero, è libero.", "src": "F. Schiller"}, "trad": {"id": "gedanken", "title": "Die Gedanken sind frei", "artist": "Volkslied", "note": "Canto popolare sulla libertà di pensiero, amatissimo in Germania.", "ytq": "Die Gedanken sind frei Lied", "de": ["Die Gedanken sind frei,", "wer kann sie erraten?", "Sie fliehen vorbei", "wie nächtliche Schatten.", "Kein Mensch kann sie wissen,", "kein Jäger erschießen;", "es bleibet dabei:", "die Gedanken sind frei!"], "it": ["I pensieri sono liberi,", "chi può indovinarli?", "Volano via", "come ombre nella notte.", "Nessuno può conoscerli,", "nessun cacciatore può abbatterli;", "resta così:", "i pensieri sono liberi!"]}, "voice": {"id": "kRq3WzSwUw0", "t": "Straßeninterviews in Magdeburg", "note": "Ascolto autentico con sottotitoli tedeschi."}, "gram_extra": [{"de": "Gestern habe ich einen Film gesehen.", "it": "Ieri ho visto un film."}, {"de": "Wir sind am Wochenende nach Rom gefahren.", "it": "Nel weekend siamo andati a Roma."}], "song1": {"id": "MTveMR0wxT0", "artist": "Udo Lindenberg feat. Clueso", "titel": "Cello"}, "song2": {"id": "5PST7Ld4wWU", "artist": "Max Giesinger", "titel": "Wenn sie tanzt"}, "articles": [{"title": "Wikipedia: Gesundheit", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Gesundheit"}, {"title": "Klexikon: Menschlicher_K%C3%B6rper (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Menschlicher_K%C3%B6rper"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Einkaufen & Geld — Acquisti e denaro", "level": "A2", "lesen": {"title": "Online oder im Geschäft?", "text": "Früher bin ich für jeden Einkauf in die Stadt gefahren. Heute bestelle ich vieles einfach online: Kleidung, Bücher und sogar Lebensmittel. Das ist bequem, denn ich spare Zeit und die Pakete kommen direkt nach Hause. Trotzdem gehe ich manchmal gern in echte Geschäfte. Im Laden kann ich die Sachen anfassen, anprobieren und sofort mitnehmen. Außerdem treffe ich dort Menschen und bekomme eine echte Beratung. Beim Online-Shopping gibt es aber auch Nachteile: Manchmal passt die Größe nicht, oder die Farbe sieht auf dem Bildschirm anders aus. Dann muss ich alles zurückschicken — und das nervt. Am Ende kommt es darauf an, was ich kaufe. Schuhe probiere ich lieber im Geschäft, ein Buch bestelle ich online.", "glos": {"Einkauf": "acquisto", "bestelle": "ordino", "Kleidung": "abbigliamento", "Lebensmittel": "generi alimentari", "bequem": "comodo", "spare": "risparmio", "Pakete": "pacchi", "Geschäfte": "negozi", "Laden": "negozio", "anfassen": "toccare", "anprobieren": "provare", "Beratung": "consulenza", "Nachteile": "svantaggi", "Größe": "taglia", "Farbe": "colore", "zurückschicken": "rimandare indietro", "nervt": "dà fastidio", "Schuhe": "scarpe"}, "q": [{"q": "Was bestellt die Person gern online?", "o": ["Schuhe", "Bücher", "Nichts"], "c": 1, "e": "„ein Buch bestelle ich online\"."}, {"q": "Was ist ein Vorteil vom echten Geschäft?", "o": ["Es ist billiger", "Man kann anprobieren", "Es ist immer offen"], "c": 1, "e": "„anfassen, anprobieren und sofort mitnehmen\"."}, {"q": "Was ist ein Nachteil vom Online-Shopping?", "o": ["Es ist zu teuer", "Die Größe passt manchmal nicht", "Es gibt keine Auswahl"], "c": 1, "e": "„Manchmal passt die Größe nicht\"."}], "frage": "Kaufst du lieber online oder im Geschäft ein? Was sind für dich die wichtigsten Gründe?"}, "artikel": {"title": "Warum Bargeld in Deutschland so beliebt ist", "text": "In vielen Ländern zahlen die Menschen fast alles mit Karte oder Handy. In Deutschland ist das anders: Hier lieben viele Menschen das Bargeld. „Nur Bares ist Wahres\", sagt ein altes Sprichwort. In kleinen Geschäften, Bäckereien oder auf dem Markt ist Bargeld oft noch das normale Zahlungsmittel. Warum ist das so? Ein Grund ist der Datenschutz: Wer bar zahlt, hinterlässt keine digitalen Spuren. Ein anderer Grund ist die Kontrolle — viele Menschen haben so einen besseren Überblick über ihre Ausgaben. Doch die Zeiten ändern sich. Vor allem junge Leute zahlen immer öfter mit dem Handy. Trotzdem wird das Bargeld in Deutschland wohl noch lange nicht verschwinden.", "glos": {"zahlen": "pagano", "Karte": "carta", "Bargeld": "contanti", "Bares": "contanti", "Wahres": "vero", "Sprichwort": "proverbio", "Zahlungsmittel": "mezzo di pagamento", "Datenschutz": "privacy/protezione dati", "hinterlässt": "lascia", "Spuren": "tracce", "Kontrolle": "controllo", "Überblick": "visione d'insieme", "Ausgaben": "spese", "verschwinden": "sparire"}, "q": [{"q": "Was sagt das deutsche Sprichwort?", "o": ["Zeit ist Geld", "Nur Bares ist Wahres", "Geld stinkt nicht"], "c": 1, "e": "„Nur Bares ist Wahres\"."}, {"q": "Nenne einen Grund für Bargeld.", "o": ["Es ist moderner", "Datenschutz / keine digitalen Spuren", "Es ist schneller"], "c": 1, "e": "„Wer bar zahlt, hinterlässt keine digitalen Spuren\"."}], "news": "Bargeld Deutschland bezahlen"}, "dialog": {"title": "Im Kleidungsgeschäft", "lines": [{"who": "Verkäufer", "de": "Guten Tag! Kann ich Ihnen helfen?"}, {"who": "Kunde", "de": "Ja, ich suche eine Jacke für den Winter."}, {"who": "Verkäufer", "de": "Welche Größe haben Sie?"}, {"who": "Kunde", "de": "Größe L, glaube ich. Haben Sie die in Blau?"}, {"who": "Verkäufer", "de": "Einen Moment … Ja, hier. Möchten Sie sie anprobieren?"}, {"who": "Kunde", "de": "Gern. Wo ist die Umkleidekabine?"}, {"who": "Verkäufer", "de": "Dort hinten links. … Und, passt sie?"}, {"who": "Kunde", "de": "Ja, sehr gut! Was kostet die Jacke?"}, {"who": "Verkäufer", "de": "Sie kostet neunundachtzig Euro."}, {"who": "Kunde", "de": "Okay, die nehme ich. Kann ich mit Karte zahlen?"}, {"who": "Verkäufer", "de": "Natürlich, kein Problem."}], "q": [{"q": "Was sucht der Kunde?", "o": ["Eine Hose", "Eine Jacke", "Schuhe"], "c": 1, "e": "„ich suche eine Jacke\"."}, {"q": "Welche Farbe möchte er?", "o": ["Schwarz", "Blau", "Rot"], "c": 1, "e": "„Haben Sie die in Blau?\""}, {"q": "Wie möchte er zahlen?", "o": ["Bar", "Mit Karte", "Mit dem Handy"], "c": 1, "e": "„Kann ich mit Karte zahlen?\""}]}, "musik": {"key": "bourani", "task": "Riascolta „Auf uns\": pensa a un brindisi con gli amici. Prova a ripetere ad alta voce il ritornello „Auf uns!\" e nota l'intonazione festosa.", "level": "A2–B1 · energico"}, "sprechen": {"read": "Entschuldigung, ich suche eine Jacke in Größe L. Haben Sie die auch in Blau? Wo ist die Umkleidekabine? … Die Jacke passt gut. Was kostet sie, und kann ich mit Karte zahlen?", "prompts": [{"q": "Was hast du zuletzt gekauft?", "e": "Zuletzt habe ich … gekauft."}, {"q": "Gibst du gern Geld aus oder sparst du lieber?", "e": "Ich … lieber, weil …"}, {"q": "Was würdest du mit 1000 Euro machen?", "e": "Mit 1000 Euro würde ich …"}], "scenario": "Du bist im Geschäft und möchtest eine Hose kaufen. Frag nach Größe, Farbe und Preis."}, "grammatik": {"titel": "Der Dativ (a chi? complemento di termine)", "regel_html": "<p>Il <b>dativo</b> risponde a <i>wem?</i> (a chi?) e si usa per il complemento di termine e dopo certe preposizioni. Gli articoli cambiano così:</p><table class='gtab'><tr><th></th><th>masch.</th><th>femm.</th><th>neutro</th><th>plurale</th></tr><tr><td>Nominativo</td><td>der</td><td>die</td><td>das</td><td>die</td></tr><tr><td>Dativo</td><td><b>dem</b></td><td><b>der</b></td><td><b>dem</b></td><td><b>den</b> (+n)</td></tr></table><p>Preposizioni sempre col dativo: <b>mit, bei, von, zu, aus, nach, seit</b>.</p><p><b>Esempi:</b> <i>Ich helfe <u>dem</u> Mann.</i> · <i>Ich fahre <u>mit dem</u> Bus.</i> · <i>Ich komme <u>aus der</u> Schweiz.</i> · <i>Das Geschenk ist für die Kinder → Ich gebe <u>den</u> Kinder<u>n</u> ein Geschenk.</i></p>", "ex": [{"l": "Ich fahre ", "r": " Bus.", "o": ["mit dem", "mit der", "mit den", "mit das"], "c": 0, "e": "mit + Dativ masch. → <b>mit dem Bus</b>."}, {"l": "Ich helfe ", "r": " Frau.", "o": ["der", "die", "den", "dem"], "c": 0, "e": "helfen regge il dativo: <b>der Frau</b> (femm.)."}, {"l": "Das Buch gehört ", "r": " Kind.", "o": ["das", "dem", "der", "den"], "c": 1, "e": "<b>dem Kind</b> (neutro, dativo)."}, {"l": "Ich komme ", "r": " der Schweiz.", "o": ["aus", "für", "ohne", "durch"], "c": 0, "e": "<b>aus</b> + dativo: aus der Schweiz."}]}, "wortschatz": [{"de": "einkaufen", "it": "fare la spesa", "exde": "Ich gehe einkaufen.", "exit": "Vado a fare la spesa."}, {"de": "das Geschäft", "it": "il negozio", "exde": "Das Geschäft ist groß.", "exit": "Il negozio è grande."}, {"de": "die Kleidung", "it": "l'abbigliamento", "exde": "Ich brauche neue Kleidung.", "exit": "Mi serve abbigliamento nuovo."}, {"de": "die Größe", "it": "la taglia", "exde": "Welche Größe hast du?", "exit": "Che taglia porti?"}, {"de": "der Preis", "it": "il prezzo", "exde": "Der Preis ist hoch.", "exit": "Il prezzo è alto."}, {"de": "das Geld", "it": "il denaro", "exde": "Ich habe wenig Geld.", "exit": "Ho pochi soldi."}, {"de": "bar zahlen", "it": "pagare in contanti", "exde": "Ich zahle bar.", "exit": "Pago in contanti."}, {"de": "die Karte", "it": "la carta", "exde": "Ich zahle mit Karte.", "exit": "Pago con la carta."}, {"de": "billig", "it": "economico", "exde": "Das ist billig.", "exit": "Questo è economico."}, {"de": "teuer", "it": "caro", "exde": "Das ist zu teuer.", "exit": "È troppo caro."}, {"de": "anprobieren", "it": "provare (indossando)", "exde": "Darf ich das anprobieren?", "exit": "Posso provarlo?"}, {"de": "sparen", "it": "risparmiare", "exde": "Ich möchte Geld sparen.", "exit": "Voglio risparmiare."}], "idiome": [{"de": "Zeit ist Geld.", "lit": "Il tempo è denaro.", "mean": "Non bisogna sprecare il tempo.", "it": "Il tempo è denaro.", "exde": "Beeil dich, Zeit ist Geld!", "exit": "Sbrigati, il tempo è denaro!"}, {"de": "Das kostet ein Vermögen.", "lit": "Costa una fortuna (un patrimonio).", "mean": "È molto costoso.", "it": "Costa un occhio della testa.", "exde": "Dieses Auto kostet ein Vermögen.", "exit": "Quest'auto costa una fortuna."}], "schreiben": {"impuls": "Beschreib deinen letzten großen Einkauf: Was war es, warum hast du es gekauft, hat es sich gelohnt?", "fragen": ["Macht Geld glücklich? Sag deine Meinung mit Beispielen.", "Konsumieren wir heute zu viel? Wie könntest du bewusster einkaufen?"]}, "freunde": [{"de": "die Information", "it": "informazione"}, {"de": "die Situation", "it": "situazione"}, {"de": "das Telefon", "it": "telefono"}, {"de": "die Universität", "it": "università"}, {"de": "der Tourist", "it": "turista"}, {"de": "das Restaurant", "it": "ristorante"}], "falsch": [{"de": "die Birne", "it": "la pera / la lampadina", "warn": "NON „birra\" (= das Bier)"}, {"de": "sensibel", "it": "sensibile / delicato", "warn": "NON „sensato\" (= vernünftig)"}, {"de": "der Termin", "it": "l'appuntamento", "warn": "NON il „termine/scadenza-parola\""}, {"de": "das Rezept", "it": "la ricetta / la prescrizione", "warn": "vale sia in cucina sia dal medico"}, {"de": "bekommen", "it": "ricevere", "warn": "NON „diventare\" (to become)"}], "lit": {"de": "Es irrt der Mensch, solang er strebt.", "it": "Finché l'uomo cerca, egli erra.", "src": "J. W. Goethe, Faust"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Ich gebe dem Kind einen Apfel.", "it": "Do una mela al bambino."}, {"de": "Das Buch gehört meiner Schwester.", "it": "Il libro è di mia sorella."}], "song1": {"id": "MtDPKJSsBgc", "artist": "Mark Forster feat. Sido", "titel": "Au Revoir"}, "song2": {"id": "WnJOJ57EqIA", "artist": "Max Giesinger", "titel": "80 Millionen"}, "articles": [{"title": "Wikipedia: Geld", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Geld"}, {"title": "Klexikon: Geld (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Geld"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Wetter & Reisen — Tempo e viaggi", "level": "A2", "lesen": {"title": "Endlich Urlaub!", "text": "Nächste Woche fliege ich endlich in den Urlaub. Ich habe ein kleines Hotel an der Nordsee gebucht, direkt am Strand. Ehrlich gesagt habe ich das ganze Jahr auf diese Tage gewartet. Mein Plan ist einfach: lange Spaziergänge am Meer, ein gutes Buch und frischer Fisch zum Abendessen. Natürlich kann das Wetter im Norden launisch sein. Mal scheint die Sonne, mal regnet es stundenlang. Aber das macht mir nichts aus. Ich packe einfach eine Regenjacke ein, dann bin ich auf alles vorbereitet. Am meisten freue ich mich darauf, einmal nichts zu müssen: kein Wecker, keine E-Mails, keine Termine. Nur das Rauschen der Wellen und die frische Luft. Manchmal ist das der schönste Luxus.", "glos": {"Urlaub": "vacanza", "fliege": "volo", "Nordsee": "Mare del Nord", "gebucht": "prenotato", "Strand": "spiaggia", "gewartet": "aspettato", "Spaziergänge": "passeggiate", "Meer": "mare", "frischer": "fresco", "launisch": "capriccioso", "regnet": "piove", "stundenlang": "per ore", "Regenjacke": "giacca antipioggia", "vorbereitet": "preparato", "freue mich": "non vedo l'ora", "Rauschen": "sciabordio", "Wellen": "onde", "Luft": "aria", "Luxus": "lusso"}, "q": [{"q": "Wohin fährt die Person in den Urlaub?", "o": ["In die Berge", "An die Nordsee", "In eine Stadt"], "c": 1, "e": "„ein … Hotel an der Nordsee\"."}, {"q": "Wie ist das Wetter im Norden?", "o": ["Immer sonnig", "Launisch (mal Sonne, mal Regen)", "Immer kalt"], "c": 1, "e": "„Mal scheint die Sonne, mal regnet es\"."}, {"q": "Worauf freut sie sich am meisten?", "o": ["Auf die Arbeit", "Darauf, nichts zu müssen", "Auf die E-Mails"], "c": 1, "e": "„einmal nichts zu müssen\"."}], "frage": "Was ist für dich der perfekte Urlaub: Strand, Berge oder Stadt? Warum?"}, "artikel": {"title": "Reisen ohne Flugzeug: ein neuer Trend", "text": "Immer mehr Menschen in Europa wollen reisen, ohne zu fliegen. Der Grund ist meistens die Umwelt: Ein Flug produziert sehr viel CO2. Deshalb steigen viele lieber in den Zug. In Europa ist das oft leichter als gedacht. Mit dem Nachtzug kann man zum Beispiel abends in Wien einsteigen und morgens in Rom oder Paris ankommen — und dabei sogar schlafen. Die Bahn ist nicht immer billiger als das Flugzeug, aber viele finden sie angenehmer: Man sieht die Landschaft, hat mehr Platz und muss nicht stundenlang am Flughafen warten. Natürlich gibt es auch Nachteile. Manche Strecken dauern lange, und nicht jedes Ziel ist gut erreichbar. Trotzdem sagen immer mehr Reisende: „Der Weg ist das Ziel.\"", "glos": {"reisen": "viaggiare", "fliegen": "volare", "Umwelt": "ambiente", "Flug": "volo", "steigen": "salgono", "Zug": "treno", "Nachtzug": "treno notturno", "einsteigen": "salire", "ankommen": "arrivare", "Bahn": "ferrovia", "angenehmer": "più piacevole", "Landschaft": "paesaggio", "Platz": "spazio", "Flughafen": "aeroporto", "Strecken": "tratte", "Ziel": "meta", "erreichbar": "raggiungibile"}, "q": [{"q": "Warum reisen viele ohne Flugzeug?", "o": ["Es ist langweilig", "Wegen der Umwelt (CO2)", "Es gibt keine Flüge"], "c": 1, "e": "„Ein Flug produziert sehr viel CO2\"."}, {"q": "Was ist ein Vorteil vom Zug?", "o": ["Man sieht die Landschaft", "Er ist immer billiger", "Er ist immer schneller"], "c": 0, "e": "„Man sieht die Landschaft, hat mehr Platz\"."}], "news": "Reisen ohne Flugzeug Zug Nachtzug"}, "dialog": {"title": "Am Bahnhof — eine Fahrkarte kaufen", "lines": [{"who": "Reisender", "de": "Guten Tag, ich möchte nach München fahren."}, {"who": "Beamter", "de": "Einfach oder hin und zurück?"}, {"who": "Reisender", "de": "Hin und zurück, bitte. Wann fährt der nächste Zug?"}, {"who": "Beamter", "de": "Der nächste fährt um 14:20 Uhr, Gleis 7."}, {"who": "Reisender", "de": "Und wann komme ich in München an?"}, {"who": "Beamter", "de": "Gegen 18 Uhr. Sie müssen einmal umsteigen, in Nürnberg."}, {"who": "Reisender", "de": "Okay. Was kostet die Fahrkarte?"}, {"who": "Beamter", "de": "Neunundvierzig Euro mit Sitzplatzreservierung."}, {"who": "Reisender", "de": "Gut, die nehme ich. Ist der Zug pünktlich?"}, {"who": "Beamter", "de": "Im Moment ja. Gute Reise!"}], "q": [{"q": "Wohin möchte der Reisende fahren?", "o": ["Nach Nürnberg", "Nach München", "Nach Berlin"], "c": 1, "e": "„ich möchte nach München fahren\"."}, {"q": "Muss er umsteigen?", "o": ["Nein", "Ja, in Nürnberg", "Ja, in Berlin"], "c": 1, "e": "„Sie müssen einmal umsteigen, in Nürnberg\"."}, {"q": "Was kostet die Fahrkarte?", "o": ["19 €", "49 €", "99 €"], "c": 1, "e": "„Neunundvierzig Euro\"."}]}, "musik": {"key": "fox", "task": "„Haus am See\" descrive il sogno di una vita tranquilla, lontano dallo stress. Ascolta e cerca le parole legate al viaggio e alla natura: „Welt\" (mondo), „See\" (lago). Perfetta per il tema vacanza.", "level": "B1 · calmo"}, "sprechen": {"read": "Guten Tag, ich möchte nach München fahren, hin und zurück. Wann fährt der nächste Zug und von welchem Gleis? Muss ich umsteigen? Was kostet die Fahrkarte mit Reservierung?", "prompts": [{"q": "Wohin reist du gern und warum?", "e": "Ich reise gern nach …, weil …"}, {"q": "Wie ist das Wetter heute bei dir?", "e": "Heute ist es …"}, {"q": "Fliegst du lieber oder fährst du lieber Zug? Warum?", "e": "Ich … lieber, weil …"}], "scenario": "Du bist am Bahnhof. Kauf eine Fahrkarte: Ziel, hin und zurück, Abfahrtszeit und Preis."}, "grammatik": {"titel": "Das Futur und die Modalverben für Pläne", "regel_html": "<p>Per parlare di piani futuri il tedesco usa spesso il <b>presente + un'espressione di tempo</b> (<i>Morgen fahre ich …</i>) oppure il <b>Futur I</b>: <b>werden</b> + infinito.</p><table class='gtab'><tr><th>forma</th><th>esempio</th></tr><tr><td>Presente + tempo</td><td><b>Nächste Woche</b> fliege ich nach Rom.</td></tr><tr><td>Futur I (werden + Inf.)</td><td>Ich <b>werde</b> bald Deutsch <b>sprechen</b>.</td></tr><tr><td>möchten (desiderio)</td><td>Ich <b>möchte</b> ans Meer <b>fahren</b>.</td></tr><tr><td>wollen (volontà)</td><td>Wir <b>wollen</b> einen Nachtzug <b>nehmen</b>.</td></tr></table><p>💡 Ricorda la regola V2: il verbo coniugato è sempre al 2° posto, l'infinito va alla fine.</p>", "ex": [{"l": "Morgen ", "r": " ich nach Berlin.", "o": ["fahre", "fahren", "gefahren", "fährt"], "c": 0, "e": "presente + tempo: <b>fahre</b> (ich)."}, {"l": "Ich ", "r": " nächstes Jahr nach Japan reisen.", "o": ["werde", "wird", "bin", "habe"], "c": 0, "e": "Futur: <b>werde</b> + infinito (reisen)."}, {"l": "Wir ", "r": " einen Nachtzug nehmen.", "o": ["wollen", "will", "wollt", "gewollt"], "c": 0, "e": "wollen (wir) → <b>wollen</b> + infinito."}, {"l": "Ich ", "r": " gern ans Meer fahren.", "o": ["möchte", "mag", "muss nicht", "darf nicht"], "c": 0, "e": "desiderio: <b>möchte</b> + infinito."}]}, "wortschatz": [{"de": "die Reise", "it": "il viaggio", "exde": "Die Reise war schön.", "exit": "Il viaggio è stato bello."}, {"de": "der Urlaub", "it": "le ferie", "exde": "Ich brauche Urlaub.", "exit": "Ho bisogno di ferie."}, {"de": "das Hotel", "it": "l'hotel", "exde": "Das Hotel liegt am Strand.", "exit": "L'hotel è sulla spiaggia."}, {"de": "der Zug", "it": "il treno", "exde": "Der Zug fährt um acht.", "exit": "Il treno parte alle otto."}, {"de": "die Fahrkarte", "it": "il biglietto", "exde": "Ich kaufe eine Fahrkarte.", "exit": "Compro un biglietto."}, {"de": "umsteigen", "it": "cambiare (mezzo)", "exde": "Ich muss in Nürnberg umsteigen.", "exit": "Devo cambiare a Norimberga."}, {"de": "das Wetter", "it": "il tempo (meteo)", "exde": "Wie ist das Wetter?", "exit": "Com'è il tempo?"}, {"de": "der Regen", "it": "la pioggia", "exde": "Der Regen hört nicht auf.", "exit": "La pioggia non smette."}, {"de": "die Sonne", "it": "il sole", "exde": "Die Sonne scheint.", "exit": "Il sole splende."}, {"de": "der Strand", "it": "la spiaggia", "exde": "Wir gehen an den Strand.", "exit": "Andiamo in spiaggia."}, {"de": "buchen", "it": "prenotare", "exde": "Ich habe ein Zimmer gebucht.", "exit": "Ho prenotato una camera."}, {"de": "pünktlich", "it": "puntuale", "exde": "Der Zug ist pünktlich.", "exit": "Il treno è puntuale."}], "idiome": [{"de": "Der Weg ist das Ziel.", "lit": "La via è la meta.", "mean": "Conta il percorso, non solo il risultato.", "it": "Il viaggio è la meta.", "exde": "Genieß die Reise — der Weg ist das Ziel.", "exit": "Goditi il viaggio: la via è la meta."}, {"de": "ins Wasser fallen", "lit": "Cadere nell'acqua.", "mean": "Saltare, non avere luogo (un piano).", "it": "Andare a monte / saltare.", "exde": "Wegen des Regens ist der Ausflug ins Wasser gefallen.", "exit": "Per la pioggia la gita è saltata."}], "schreiben": {"impuls": "Erzähl von deiner schönsten Reise: Wohin ging es, mit wem, und was hat dich am meisten beeindruckt?", "fragen": ["Sollte man wegen des Klimas weniger fliegen? Was ist deine Meinung?", "Reist du lieber spontan oder planst du alles genau? Warum?"]}, "freunde": [{"de": "der Tourist", "it": "turista"}, {"de": "das Restaurant", "it": "ristorante"}, {"de": "die Pizza", "it": "pizza"}, {"de": "das Auto", "it": "auto"}, {"de": "der Bus", "it": "autobus / bus"}, {"de": "das Theater", "it": "teatro"}], "falsch": [{"de": "das Rezept", "it": "la ricetta / la prescrizione", "warn": "vale sia in cucina sia dal medico"}, {"de": "bekommen", "it": "ricevere", "warn": "NON „diventare\" (to become)"}, {"de": "das Gift", "it": "il veleno", "warn": "NON „regalo\" (gift)"}, {"de": "der Chef", "it": "il capo", "warn": "NON il cuoco (= der Koch)"}, {"de": "kalt", "it": "freddo", "warn": "NON „caldo\": è l'opposto!"}], "lit": {"de": "Was mich nicht umbringt, macht mich stärker.", "it": "Ciò che non mi uccide mi rende più forte.", "src": "F. Nietzsche"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [{"de": "Nächstes Jahr werde ich nach Berlin ziehen.", "it": "L'anno prossimo mi trasferirò a Berlino."}, {"de": "Wir wollen morgen früh losfahren.", "it": "Vogliamo partire domani mattina presto."}], "song1": {"id": "BgWgufeKUgU", "artist": "Giovanni Zarrella feat. Pietro Lombardi", "titel": "Senza te", "original": "Cover italo-tedesca di „Ohne dich\" (Münchner Freiheit)."}, "song2": {"id": "3ryohiCVq3M", "artist": "Namika", "titel": "Lieblingsmensch"}, "articles": [{"title": "Wikipedia: Wetter", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Wetter"}, {"title": "Klexikon: Wetter (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Wetter"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Feste & Feiertage — Feste e ricorrenze", "level": "A2", "lesen": {"title": "Weihnachten bei uns zu Hause", "text": "Weihnachten ist für meine Familie das wichtigste Fest des Jahres. Schon im Dezember schmücken wir die Wohnung und backen Plätzchen. Es riecht überall nach Zimt und Vanille. Am 24. Dezember, dem Heiligabend, kommen wir alle zusammen. Erst essen wir gemeinsam zu Abend, dann singen wir ein paar Lieder. Die Kinder können es kaum erwarten, denn am Abend gibt es endlich die Geschenke. Mein Großvater liest immer eine kurze Geschichte vor, bevor wir den Baum bewundern. Am 25. und 26. Dezember besuchen wir Verwandte und essen viel zu viel. Ich mag an Weihnachten am meisten, dass die ganze Familie einmal im Jahr wirklich Zeit füreinander hat.", "glos": {"Weihnachten": "Natale", "Fest": "festa", "schmücken": "addobbare", "backen": "cuocere (al forno)", "Plätzchen": "biscottini", "riecht": "profuma", "Zimt": "cannella", "Heiligabend": "vigilia di Natale", "zusammen": "insieme", "singen": "cantare", "Lieder": "canzoni", "erwarten": "aspettare", "Geschenke": "regali", "Großvater": "nonno", "vorlesen": "leggere ad alta voce", "Baum": "albero", "bewundern": "ammirare", "Verwandte": "parenti", "füreinander": "l'uno per l'altro"}, "q": [{"q": "Wann kommt die Familie zusammen?", "o": ["Am 1. Dezember", "Am Heiligabend (24.12.)", "Am 31. Dezember"], "c": 1, "e": "„Am 24. Dezember, dem Heiligabend\"."}, {"q": "Was machen sie vor den Geschenken?", "o": ["Sie schlafen", "Sie essen und singen", "Sie gehen spazieren"], "c": 1, "e": "„essen wir … zu Abend, dann singen wir\"."}, {"q": "Was mag die Person am meisten?", "o": ["Die Geschenke", "Das Essen", "Die Zeit mit der Familie"], "c": 2, "e": "„dass die ganze Familie … Zeit füreinander hat\"."}], "frage": "Welches Fest ist für dich am wichtigsten? Wie feierst du es?"}, "artikel": {"title": "Karneval: wenn ganz Deutschland verrücktspielt", "text": "In manchen Regionen Deutschlands gibt es im Februar eine ganz besondere Zeit: den Karneval, auch „Fasching\" oder „die fünfte Jahreszeit\" genannt. Vor allem in Städten wie Köln, Düsseldorf und Mainz feiern die Menschen tagelang auf den Straßen. Sie verkleiden sich als Clowns, Tiere oder Superhelden, singen, tanzen und rufen laut „Helau!\" oder „Alaaf!\". Der Höhepunkt ist der Rosenmontag mit großen Umzügen: Bunte Wagen fahren durch die Stadt, und von ihnen werden Süßigkeiten ins Publikum geworfen. Für viele ist Karneval die schönste Zeit des Jahres, weil man einfach fröhlich sein und für ein paar Tage jemand anderes sein kann. Wer es ruhiger mag, fährt in dieser Zeit lieber in den Urlaub.", "glos": {"Regionen": "regioni", "Karneval": "carnevale", "Fasching": "carnevale", "Jahreszeit": "stagione", "feiern": "festeggiano", "tagelang": "per giorni", "verkleiden": "travestirsi", "Tiere": "animali", "tanzen": "ballare", "rufen": "gridano", "Höhepunkt": "culmine", "Umzügen": "sfilate", "Wagen": "carri", "Süßigkeiten": "dolci", "geworfen": "lanciati", "Publikum": "pubblico", "fröhlich": "allegro", "ruhiger": "più tranquillo"}, "q": [{"q": "Wie heißt Karneval auch?", "o": ["Ostern", "Fasching", "Advent"], "c": 1, "e": "„auch „Fasching\" … genannt\"."}, {"q": "Was passiert am Rosenmontag?", "o": ["Man schläft", "Es gibt große Umzüge", "Die Geschäfte öffnen"], "c": 1, "e": "„Der Höhepunkt ist der Rosenmontag mit großen Umzügen\"."}], "news": "Karneval Köln Deutschland Fasching"}, "dialog": {"title": "Eine Einladung zur Geburtstagsfeier", "lines": [{"who": "Lena", "de": "Du, am Samstag mache ich eine kleine Geburtstagsfeier. Kommst du?"}, {"who": "Tom", "de": "Klar, sehr gern! Wie alt wirst du denn?"}, {"who": "Lena", "de": "Dreißig. Ein bisschen verrückt, oder?"}, {"who": "Tom", "de": "Dreißig ist doch super! Wo feierst du?"}, {"who": "Lena", "de": "Bei mir zu Hause, ab acht Uhr abends."}, {"who": "Tom", "de": "Soll ich etwas mitbringen?"}, {"who": "Lena", "de": "Nur gute Laune! Für Essen und Getränke ist gesorgt."}, {"who": "Tom", "de": "Perfekt. Darf ich meine Freundin mitbringen?"}, {"who": "Lena", "de": "Natürlich, je mehr, desto besser!"}, {"who": "Tom", "de": "Super, dann bis Samstag. Und schon mal alles Gute!"}], "q": [{"q": "Was feiert Lena?", "o": ["Eine Hochzeit", "Ihren 30. Geburtstag", "Weihnachten"], "c": 1, "e": "„Dreißig\" … Geburtstagsfeier."}, {"q": "Wann beginnt die Feier?", "o": ["Um sechs Uhr", "Ab acht Uhr abends", "Mittags"], "c": 1, "e": "„ab acht Uhr abends\"."}, {"q": "Was soll Tom mitbringen?", "o": ["Essen", "Getränke", "Nur gute Laune"], "c": 2, "e": "„Nur gute Laune!\""}]}, "musik": {"key": "nena", "task": "„99 Luftballons\" è un classico tedesco perfetto per imparare. Ascolta e prova a contare quante volte senti „Luftballons\". Canzone allegra ma con un testo profondo.", "level": "B1 · classico"}, "sprechen": {"read": "Am Samstag mache ich eine kleine Feier bei mir zu Hause, ab acht Uhr. Kommst du? Du musst nichts mitbringen, nur gute Laune. Darf deine Freundin auch kommen?", "prompts": [{"q": "Welche Feste feierst du im Jahr?", "e": "Ich feiere …"}, {"q": "Wie hast du deinen letzten Geburtstag gefeiert?", "e": "Letztes Jahr habe ich …"}, {"q": "Lädst du einen Freund zu einer Feier ein — was sagst du?", "e": "Am … mache ich eine Feier. Kommst du?"}], "scenario": "Lad einen Freund zu deiner Party ein: sag wann, wo, und antworte auf seine Fragen (mitbringen? wer kommt?)."}, "grammatik": {"titel": "Das Datum und die Ordinalzahlen", "regel_html": "<p>Per le date servono i <b>numeri ordinali</b>. Fino a 19 si aggiunge <b>-te</b>, da 20 in poi <b>-ste</b>. Si scrivono con un punto: <i>1. = erste, 3. = dritte, 20. = zwanzigste</i>.</p><table class='gtab'><tr><th>domanda</th><th>risposta</th></tr><tr><td>Der Wievielte ist heute?</td><td>Heute ist der <b>erste</b> Mai. (1.)</td></tr><tr><td>Wann hast du Geburtstag?</td><td>Am <b>dritten</b> März. (am 3.)</td></tr><tr><td>Wann ist Weihnachten?</td><td>Am <b>vierundzwanzigsten</b> Dezember.</td></tr></table><p>💡 Attenzione a due irregolari: <i>1. = erste</i>, <i>3. = dritte</i> (non „einte/dreite\"). Con „am\" l'ordinale prende <b>-n</b>: <i>am ersten, am dritten</i>.</p>", "ex": [{"l": "Heute ist der ", "r": " Mai. (1.)", "o": ["erste", "einte", "eine", "erst"], "c": 0, "e": "1. = <b>erste</b> (irregolare)."}, {"l": "Ich habe am ", "r": " März Geburtstag. (3.)", "o": ["dritten", "dreiten", "drei", "dritte"], "c": 0, "e": "am 3. = <b>am dritten</b> (irregolare + n)."}, {"l": "Weihnachten ist am ", "r": " Dezember. (24.)", "o": ["zwanzigvierten", "vierundzwanzigsten", "vierundzwanzig", "vierte"], "c": 1, "e": "24. = <b>vierundzwanzigsten</b> (-ste + n)."}, {"l": "Der ", "r": " Januar ist Neujahr. (1.)", "o": ["erste", "einste", "ein", "erster"], "c": 0, "e": "1. = <b>erste</b>."}]}, "wortschatz": [{"de": "das Fest", "it": "la festa", "exde": "Das war ein schönes Fest.", "exit": "È stata una bella festa."}, {"de": "der Feiertag", "it": "il giorno festivo", "exde": "Montag ist ein Feiertag.", "exit": "Lunedì è festivo."}, {"de": "feiern", "it": "festeggiare", "exde": "Wir feiern zusammen.", "exit": "Festeggiamo insieme."}, {"de": "das Geschenk", "it": "il regalo", "exde": "Danke für das Geschenk!", "exit": "Grazie per il regalo!"}, {"de": "die Einladung", "it": "l'invito", "exde": "Danke für die Einladung.", "exit": "Grazie per l'invito."}, {"de": "einladen", "it": "invitare", "exde": "Ich lade dich ein.", "exit": "Ti invito."}, {"de": "der Geburtstag", "it": "il compleanno", "exde": "Heute ist mein Geburtstag.", "exit": "Oggi è il mio compleanno."}, {"de": "Weihnachten", "it": "il Natale", "exde": "Frohe Weihnachten!", "exit": "Buon Natale!"}, {"de": "Ostern", "it": "la Pasqua", "exde": "Wir feiern Ostern.", "exit": "Festeggiamo la Pasqua."}, {"de": "gratulieren", "it": "congratularsi/fare gli auguri", "exde": "Ich gratuliere dir!", "exit": "Ti faccio gli auguri!"}, {"de": "schenken", "it": "regalare", "exde": "Was schenkst du ihr?", "exit": "Cosa le regali?"}, {"de": "die Überraschung", "it": "la sorpresa", "exde": "Das ist eine Überraschung!", "exit": "È una sorpresa!"}], "idiome": [{"de": "etwas aus dem Ärmel schütteln", "lit": "Scrollarsi qualcosa dalla manica.", "mean": "Fare qualcosa con grande facilità, all'improvviso.", "it": "Tirare fuori dal cilindro.", "exde": "Sie hat die Rede aus dem Ärmel geschüttelt.", "exit": "Ha improvvisato il discorso con disinvoltura."}, {"de": "die Daumen drücken", "lit": "Premere i pollici.", "mean": "Fare il tifo / augurare buona fortuna a qualcuno.", "it": "Fare gli scongiuri / tenere le dita incrociate.", "exde": "Ich drücke dir die Daumen für die Prüfung!", "exit": "Ti faccio un grosso in bocca al lupo per l'esame!"}], "schreiben": {"impuls": "Beschreib dein Lieblingsfest: Wann ist es, mit wem feierst du, und was macht es besonders?", "fragen": ["Sind Feste heute noch wichtig, oder verlieren sie an Bedeutung? Was denkst du?", "Gibt es ein Fest aus einem anderen Land, das du gern feiern würdest? Warum?"]}, "freunde": [{"de": "der Bus", "it": "autobus / bus"}, {"de": "das Theater", "it": "teatro"}, {"de": "die Kultur", "it": "cultura"}, {"de": "das Konzert", "it": "concerto"}, {"de": "der Park", "it": "parco"}, {"de": "das Museum", "it": "museo"}], "falsch": [{"de": "der Chef", "it": "il capo", "warn": "NON il cuoco (= der Koch)"}, {"de": "kalt", "it": "freddo", "warn": "NON „caldo\": è l'opposto!"}, {"de": "die Firma", "it": "la ditta / azienda", "warn": "NON la firma (= die Unterschrift)"}, {"de": "das Regal", "it": "lo scaffale", "warn": "NON il regalo (= das Geschenk)"}, {"de": "eventuell", "it": "forse / se necessario", "warn": "NON „eventually\" (= schließlich)"}], "lit": {"de": "Wo man Bücher verbrennt, verbrennt man am Ende auch Menschen.", "it": "Dove si bruciano i libri, alla fine si bruciano anche gli uomini.", "src": "H. Heine, Almansor"}, "trad": {"id": "gedanken", "title": "Die Gedanken sind frei", "artist": "Volkslied", "note": "Canto popolare sulla libertà di pensiero, amatissimo in Germania.", "ytq": "Die Gedanken sind frei Lied", "de": ["Die Gedanken sind frei,", "wer kann sie erraten?", "Sie fliehen vorbei", "wie nächtliche Schatten.", "Kein Mensch kann sie wissen,", "kein Jäger erschießen;", "es bleibet dabei:", "die Gedanken sind frei!"], "it": ["I pensieri sono liberi,", "chi può indovinarli?", "Volano via", "come ombre nella notte.", "Nessuno può conoscerli,", "nessun cacciatore può abbatterli;", "resta così:", "i pensieri sono liberi!"]}, "voice": {"id": "kRq3WzSwUw0", "t": "Straßeninterviews in Magdeburg", "note": "Ascolto autentico con sottotitoli tedeschi."}, "gram_extra": [], "song1": {"id": "jP4-XrbGt3M", "artist": "Mark Forster", "titel": "Sowieso"}, "song2": {"id": "MYbFfQYDFTQ", "artist": "Seeed", "titel": "Augenbling"}, "articles": [{"title": "Wikipedia: Feste", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Feste"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Telefonieren & Kommunikation — Telefonare e comunicare", "level": "A2", "lesen": {"title": "Immer erreichbar?", "text": "Früher hatten die Menschen ein Telefon zu Hause, und das war alles. Heute habe ich mein Handy immer dabei und bin fast überall erreichbar. Das ist praktisch, aber manchmal auch anstrengend. Ich bekomme jeden Tag Dutzende Nachrichten: von der Familie, von Freunden, von der Arbeit. Oft schreibe ich lieber eine kurze Nachricht, als zu telefonieren. Ein Anruf fühlt sich für mich persönlicher an, kostet aber mehr Zeit. Was mich wirklich stört, sind Anrufe von unbekannten Nummern, meistens Werbung. Am Wochenende versuche ich deshalb, mein Handy öfter wegzulegen. Ein paar Stunden ohne Bildschirm tun einfach gut. Trotzdem: Ganz ohne Handy könnte ich heute wahrscheinlich nicht mehr leben.", "glos": {"erreichbar": "raggiungibile", "Handy": "cellulare", "dabei": "con sé", "praktisch": "pratico", "anstrengend": "faticoso", "Nachrichten": "messaggi", "telefonieren": "telefonare", "Anruf": "chiamata", "persönlicher": "più personale", "stört": "dà fastidio", "unbekannten": "sconosciuti", "Nummern": "numeri", "Werbung": "pubblicità", "wegzulegen": "mettere via", "Bildschirm": "schermo"}, "q": [{"q": "Was macht die Person lieber als telefonieren?", "o": ["Schlafen", "Eine kurze Nachricht schreiben", "Nichts"], "c": 1, "e": "„schreibe ich lieber eine kurze Nachricht\"."}, {"q": "Was stört die Person besonders?", "o": ["Nachrichten von Freunden", "Werbeanrufe von unbekannten Nummern", "E-Mails"], "c": 1, "e": "„Anrufe von unbekannten Nummern, meistens Werbung\"."}, {"q": "Was macht sie am Wochenende?", "o": ["Mehr telefonieren", "Das Handy öfter weglegen", "Neue Apps laden"], "c": 1, "e": "„mein Handy öfter wegzulegen\"."}], "frage": "Telefonierst du lieber oder schreibst du lieber? Wie oft schaust du auf dein Handy?"}, "artikel": {"title": "Smartphone-Pause: der neue Luxus", "text": "Im Schnitt schauen viele Menschen mehr als hundertmal am Tag auf ihr Smartphone. Kein Wunder, dass immer mehr von ihnen bewusst Pausen machen wollen. „Digital Detox\" nennt man das — eine Zeit ohne Handy, ohne Internet, ohne ständige Nachrichten. Manche legen das Handy nur abends weg, andere machen ein ganzes Wochenende ohne Bildschirm. Die Idee dahinter ist einfach: Wer ständig erreichbar ist, kann schlecht abschalten und kommt nie richtig zur Ruhe. Experten raten zu kleinen Schritten: das Handy beim Essen weglegen, nachts nicht ans Bett nehmen, Benachrichtigungen ausschalten. Niemand muss ganz auf das Smartphone verzichten. Aber bewusst zu entscheiden, wann man online ist, gibt vielen ein Stück Freiheit zurück.", "glos": {"im Schnitt": "in media", "Wunder": "meraviglia", "bewusst": "consapevolmente", "Pausen": "pause", "ständige": "costanti", "weglegen": "mettere via", "Bildschirm": "schermo", "erreichbar": "raggiungibile", "abschalten": "staccare", "zur Ruhe kommen": "trovare pace", "raten": "consigliano", "Schritten": "passi", "Benachrichtigungen": "notifiche", "ausschalten": "spegnere", "verzichten": "rinunciare", "Freiheit": "libertà"}, "q": [{"q": "Was bedeutet „Digital Detox\"?", "o": ["Mehr Apps nutzen", "Eine Zeit ohne Handy und Internet", "Ein neues Handy kaufen"], "c": 1, "e": "„eine Zeit ohne Handy, ohne Internet\"."}, {"q": "Was raten die Experten?", "o": ["Ganz auf das Handy verzichten", "Kleine Schritte, z. B. beim Essen weglegen", "Mehr telefonieren"], "c": 1, "e": "„Experten raten zu kleinen Schritten\"."}], "news": "Digital Detox Smartphone Handy"}, "dialog": {"title": "Ein Anruf — der Chef ist nicht da", "lines": [{"who": "Sekretärin", "de": "Firma Berg, guten Tag, was kann ich für Sie tun?"}, {"who": "Frau Roth", "de": "Guten Tag, hier ist Frau Roth. Kann ich bitte mit Herrn Klein sprechen?"}, {"who": "Sekretärin", "de": "Tut mir leid, Herr Klein ist gerade in einer Besprechung."}, {"who": "Frau Roth", "de": "Ach so. Wann kann ich ihn denn erreichen?"}, {"who": "Sekretärin", "de": "Versuchen Sie es bitte nach 14 Uhr noch einmal."}, {"who": "Frau Roth", "de": "Gut. Können Sie ihm vielleicht etwas ausrichten?"}, {"who": "Sekretärin", "de": "Natürlich, sagen Sie mir einfach Bescheid."}, {"who": "Frau Roth", "de": "Er soll mich bitte zurückrufen. Er hat meine Nummer."}, {"who": "Sekretärin", "de": "Mache ich. Auf Wiederhören, Frau Roth!"}, {"who": "Frau Roth", "de": "Vielen Dank. Auf Wiederhören!"}], "q": [{"q": "Warum kann Frau Roth nicht mit Herrn Klein sprechen?", "o": ["Er ist krank", "Er ist in einer Besprechung", "Er ist im Urlaub"], "c": 1, "e": "„Herr Klein ist gerade in einer Besprechung\"."}, {"q": "Wann soll sie es noch einmal versuchen?", "o": ["Vor 10 Uhr", "Nach 14 Uhr", "Morgen"], "c": 1, "e": "„nach 14 Uhr noch einmal\"."}, {"q": "Was soll Herr Klein tun?", "o": ["Eine E-Mail schreiben", "Frau Roth zurückrufen", "Vorbeikommen"], "c": 1, "e": "„Er soll mich bitte zurückrufen\"."}]}, "musik": {"key": "helden", "task": "„Nur ein Wort\" parla del desiderio di una sola parola, di comunicare. Ascolta e prova a cogliere i verbi della comunicazione: sagen, hören, sprechen. Testo chiaro e ripetitivo.", "level": "A2 · ritmo medio"}, "sprechen": {"read": "Guten Tag, hier ist … . Kann ich bitte mit Herrn Klein sprechen? Ach so, er ist nicht da. Können Sie ihm bitte etwas ausrichten? Er soll mich zurückrufen. Vielen Dank!", "prompts": [{"q": "Wie oft telefonierst du am Tag?", "e": "Ich telefoniere … mal am Tag."}, {"q": "Schreibst du lieber Nachrichten oder telefonierst du?", "e": "Ich … lieber, weil …"}, {"q": "Was machst du, um weniger am Handy zu sein?", "e": "Um weniger am Handy zu sein, …"}], "scenario": "Ruf in einer Firma an. Die Person, die du suchst, ist nicht da: hinterlass eine Nachricht und bitte um Rückruf."}, "grammatik": {"titel": "Personalpronomen im Akkusativ und Dativ", "regel_html": "<p>I pronomi cambiano forma a seconda del caso. <b>Akkusativo</b> = complemento oggetto (chi?), <b>Dativo</b> = a chi? (spesso con dare, dire, telefonare, aiutare).</p><table class='gtab'><tr><th>nominativo</th><th>accusativo</th><th>dativo</th></tr><tr><td>ich</td><td>mich</td><td>mir</td></tr><tr><td>du</td><td>dich</td><td>dir</td></tr><tr><td>er</td><td>ihn</td><td>ihm</td></tr><tr><td>sie</td><td>sie</td><td>ihr</td></tr><tr><td>wir</td><td>uns</td><td>uns</td></tr></table><p><b>Esempi:</b> <i>Ruf <u>mich</u> an!</i> (Akk.) · <i>Ich gebe <u>dir</u> meine Nummer.</i> (Dat.) · <i>Ich helfe <u>ihm</u>.</i> (Dat.) · <i>Kennst du <u>sie</u>?</i> (Akk.)</p><p>💡 Verbi col dativo da ricordare: <i>helfen, danken, geben, schreiben, antworten, gehören</i>.</p>", "ex": [{"l": "Ruf ", "r": " heute Abend an! (io)", "o": ["mich", "mir", "ich", "mein"], "c": 0, "e": "anrufen + Akkusativo: <b>mich</b>."}, {"l": "Ich gebe ", "r": " meine Nummer. (tu)", "o": ["dich", "dir", "du", "dein"], "c": 1, "e": "geben + Dativo: <b>dir</b>."}, {"l": "Kannst du ", "r": " helfen? (lui)", "o": ["ihn", "er", "ihm", "sein"], "c": 2, "e": "helfen + Dativo: <b>ihm</b>."}, {"l": "Ich kenne ", "r": " gut. (lei)", "o": ["ihr", "sie", "ihm", "ihre"], "c": 1, "e": "kennen + Akkusativo: <b>sie</b>."}]}, "wortschatz": [{"de": "telefonieren", "it": "telefonare", "exde": "Ich telefoniere mit Oma.", "exit": "Telefono con la nonna."}, {"de": "anrufen", "it": "chiamare", "exde": "Ruf mich an!", "exit": "Chiamami!"}, {"de": "zurückrufen", "it": "richiamare", "exde": "Ich rufe dich zurück.", "exit": "Ti richiamo."}, {"de": "die Nachricht", "it": "il messaggio", "exde": "Ich schicke dir eine Nachricht.", "exit": "Ti mando un messaggio."}, {"de": "das Handy", "it": "il cellulare", "exde": "Mein Handy ist leer.", "exit": "Il mio cellulare è scarico."}, {"de": "erreichen", "it": "raggiungere/contattare", "exde": "Ich kann ihn nicht erreichen.", "exit": "Non riesco a contattarlo."}, {"de": "ausrichten", "it": "riferire (un messaggio)", "exde": "Kann ich etwas ausrichten?", "exit": "Posso riferire qualcosa?"}, {"de": "Bescheid sagen", "it": "far sapere", "exde": "Sag mir Bescheid!", "exit": "Fammi sapere!"}, {"de": "die Nummer", "it": "il numero", "exde": "Wie ist deine Nummer?", "exit": "Qual è il tuo numero?"}, {"de": "schicken", "it": "mandare", "exde": "Ich schicke ein Foto.", "exit": "Mando una foto."}, {"de": "antworten", "it": "rispondere", "exde": "Bitte antworte mir.", "exit": "Per favore rispondimi."}, {"de": "besetzt", "it": "occupato (linea)", "exde": "Die Leitung ist besetzt.", "exit": "La linea è occupata."}], "idiome": [{"de": "jemandem auf den Wecker gehen", "lit": "Andare sulla sveglia di qualcuno.", "mean": "Dare molto fastidio a qualcuno, infastidirlo.", "it": "Stare sulle scatole a qualcuno.", "exde": "Die ständigen Anrufe gehen mir auf den Wecker.", "exit": "Le chiamate continue mi stanno sulle scatole."}, {"de": "die Leitung steht", "lit": "La linea è in piedi.", "mean": "La connessione/comunicazione funziona.", "it": "C'è linea / la comunicazione regge.", "exde": "Endlich steht die Leitung — wir können reden.", "exit": "Finalmente c'è linea: possiamo parlare."}], "schreiben": {"impuls": "Schreib eine kurze Nachricht an einen Freund: Du musst einen Termin verschieben und schlägst einen neuen vor.", "fragen": ["Macht uns das Smartphone freier oder unfreier? Begründe deine Meinung.", "Könntest du eine Woche ohne Handy leben? Was wäre schwierig?"]}, "freunde": [{"de": "der Park", "it": "parco"}, {"de": "das Museum", "it": "museo"}, {"de": "die Person", "it": "persona"}, {"de": "die Politik", "it": "politica"}, {"de": "die Energie", "it": "energia"}, {"de": "das System", "it": "sistema"}], "falsch": [{"de": "das Regal", "it": "lo scaffale", "warn": "NON il regalo (= das Geschenk)"}, {"de": "eventuell", "it": "forse / se necessario", "warn": "NON „eventually\" (= schließlich)"}, {"de": "das Handy", "it": "il cellulare", "warn": "NON „handy / pratico\""}, {"de": "die Kantine", "it": "la mensa", "warn": "NON la cantina (= der Keller)"}, {"de": "die Note", "it": "il voto / la nota musicale", "warn": "NON la notte (= die Nacht)"}], "lit": {"de": "Du musst dein Leben ändern.", "it": "Devi cambiare la tua vita.", "src": "R. M. Rilke"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Schreib mir bitte eine Nachricht.", "it": "Scrivimi un messaggio, per favore."}, {"de": "Ich rufe dich später an, okay?", "it": "Ti chiamo più tardi, va bene?"}], "song1": {"id": "Vf0MC3CFihY", "artist": "Revolverheld", "titel": "Ich lass für dich das Licht an"}, "song2": {"id": "4BAKb2p450Q", "artist": "Tim Bendzko", "titel": "Nur noch kurz die Welt retten"}, "articles": [{"title": "Wikipedia: Telefonieren", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Telefonieren"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Technologie & Internet — Tecnologia e internet", "level": "B1", "lesen": {"title": "Ein Leben ohne Handy?", "text": "Letzte Woche ist mir etwas passiert, das mich zum Nachdenken gebracht hat: Mein Handy ist kaputtgegangen, und ich musste fünf Tage ohne Smartphone leben. Am Anfang war ich richtig nervös. Ständig griff meine Hand in die leere Tasche. Ich wusste nicht, wie spät es war, wie das Wetter wird oder ob mir jemand geschrieben hatte. Nach zwei Tagen aber merkte ich etwas Seltsames: Ich war ruhiger. Im Zug schaute ich aus dem Fenster, statt auf einen Bildschirm zu starren. Abends las ich endlich wieder ein Buch. Ich hatte sogar längere Gespräche mit Freunden, weil mich nichts ablenkte. Natürlich war ich froh, als das neue Handy kam. Aber seitdem versuche ich, es bewusster zu benutzen. Das Smartphone ist ein großartiges Werkzeug — solange wir es kontrollieren und nicht umgekehrt.", "glos": {"passiert": "successo", "Nachdenken": "riflessione", "kaputtgegangen": "si è rotto", "nervös": "nervoso", "ständig": "continuamente", "griff": "afferrava", "leere": "vuota", "Tasche": "tasca", "Seltsames": "di strano", "ruhiger": "più tranquillo", "Bildschirm": "schermo", "starren": "fissare", "Gespräche": "conversazioni", "ablenkte": "distraeva", "bewusster": "più consapevolmente", "Werkzeug": "strumento", "umgekehrt": "al contrario"}, "q": [{"q": "Warum musste die Person ohne Handy leben?", "o": ["Sie wollte es", "Das Handy war kaputt", "Sie hatte kein Geld"], "c": 1, "e": "„Mein Handy ist kaputtgegangen\"."}, {"q": "Was merkte sie nach zwei Tagen?", "o": ["Sie war ruhiger", "Sie war krank", "Es war langweilig"], "c": 0, "e": "„Ich war ruhiger\"."}, {"q": "Was ist die Lehre am Ende?", "o": ["Handys sind schlecht", "Man soll das Handy bewusster benutzen", "Man braucht kein Handy"], "c": 1, "e": "„es bewusster zu benutzen\"."}], "frage": "Könntest du eine Woche ohne Smartphone leben? Was würde dir am meisten fehlen?"}, "artikel": {"title": "Künstliche Intelligenz: Hilfe oder Gefahr?", "text": "Kaum ein Thema wird zurzeit so heftig diskutiert wie die künstliche Intelligenz, kurz KI. Programme können heute Texte schreiben, Bilder malen und sogar Musik komponieren. Für viele ist das ein Wunder: KI hilft Ärzten bei Diagnosen, übersetzt Sprachen in Sekunden und erledigt langweilige Aufgaben. Andere haben aber Angst. Sie fragen sich, ob Maschinen bald ihre Arbeit übernehmen. Werden Journalisten, Übersetzer oder Programmierer noch gebraucht? Und wer trägt die Verantwortung, wenn eine KI einen Fehler macht? Die meisten Experten sind sich einig: KI wird nicht verschwinden. Wichtig ist, dass wir lernen, sie klug und fair zu nutzen. Eine Technik ist nie gut oder böse an sich — es kommt darauf an, was die Menschen daraus machen.", "glos": {"heftig": "acceso", "diskutiert": "discusso", "künstliche": "artificiale", "Wunder": "miracolo", "Diagnosen": "diagnosi", "übersetzt": "traduce", "erledigt": "sbriga", "Aufgaben": "compiti", "Angst": "paura", "Maschinen": "macchine", "übernehmen": "prendere il posto", "gebraucht": "necessari", "Verantwortung": "responsabilità", "einig": "d'accordo", "verschwinden": "sparire", "klug": "saggio", "böse": "cattivo"}, "q": [{"q": "Was können KI-Programme heute?", "o": ["Nur rechnen", "Texte, Bilder und Musik erstellen", "Nichts Nützliches"], "c": 1, "e": "„Texte schreiben, Bilder malen und … Musik komponieren\"."}, {"q": "Was ist die Meinung der meisten Experten?", "o": ["KI verschwindet bald", "Wir müssen lernen, KI klug zu nutzen", "KI soll verboten werden"], "c": 1, "e": "„dass wir lernen, sie klug und fair zu nutzen\"."}], "news": "Künstliche Intelligenz Chancen Risiken"}, "dialog": {"title": "Streit über soziale Medien", "lines": [{"who": "Tim", "de": "Du bist ja schon wieder am Handy! Schaust du den ganzen Tag auf den Bildschirm?"}, {"who": "Lea", "de": "Ach komm, ich beantworte nur kurz eine Nachricht."}, {"who": "Tim", "de": "Das sagst du immer. Beim Essen, im Bus, sogar beim Spazieren."}, {"who": "Lea", "de": "Übertreib nicht. So schlimm ist es auch wieder nicht."}, {"who": "Tim", "de": "Doch, finde ich schon. Wir reden kaum noch richtig miteinander."}, {"who": "Lea", "de": "Okay, da hast du vielleicht recht. Es ist zur Gewohnheit geworden."}, {"who": "Tim", "de": "Wie wäre es mit einer Regel: beim Abendessen kein Handy?"}, {"who": "Lea", "de": "Einverstanden. Aber dann gilt das auch für dich!"}, {"who": "Tim", "de": "Abgemacht. Mal sehen, wer es länger durchhält."}], "q": [{"q": "Worüber streiten Tim und Lea?", "o": ["Übers Essen", "Über die Handynutzung", "Über Geld"], "c": 1, "e": "Lea ist „schon wieder am Handy\"."}, {"q": "Welche Regel schlägt Tim vor?", "o": ["Kein Handy beim Abendessen", "Kein Handy im Bus", "Kein Handy am Wochenende"], "c": 0, "e": "„beim Abendessen kein Handy\"."}, {"q": "Wie reagiert Lea am Ende?", "o": ["Sie ist beleidigt", "Sie ist einverstanden", "Sie geht weg"], "c": 1, "e": "„Einverstanden\"."}]}, "musik": {"key": "helden", "task": "Riascolta „Nur ein Wort\": il testo parla del desiderio di comunicazione vera. Collega il tema alla difficoltà di comunicare nell'era dei social. Concentrati sui verbi sehen/denken/fühlen.", "level": "A2–B1 · testo riflessivo"}, "sprechen": {"read": "Ehrlich gesagt verbringe ich zu viel Zeit am Handy. Ich checke ständig Nachrichten und soziale Medien. Manchmal lenkt mich das von wichtigen Dingen ab. Ich möchte das Handy in Zukunft bewusster benutzen und öfter offline sein.", "prompts": [{"q": "Wie viel Zeit verbringst du täglich am Handy?", "e": "Ungefähr … Stunden, vor allem für …"}, {"q": "Welche App benutzt du am meisten und warum?", "e": "Am meisten benutze ich …, weil …"}, {"q": "Findest du künstliche Intelligenz eher nützlich oder gefährlich? Begründe.", "e": "Ich finde KI eher …, weil …"}], "scenario": "Ein Freund sagt, du seist zu oft am Handy. Reagiere: Stimmst du zu oder verteidigst du dich?"}, "grammatik": {"titel": "Nebensätze mit „weil\", „dass\", „wenn\" (verbo alla fine)", "regel_html": "<p>Le congiunzioni <b>weil</b> (perché), <b>dass</b> (che), <b>wenn</b> (se/quando), <b>obwohl</b> (benché) introducono una <b>frase secondaria</b>: il verbo coniugato va <b>alla fine</b>.</p><table class='gtab'><tr><th>congiunzione</th><th>esempio</th></tr><tr><td>weil</td><td>Ich lerne Deutsch, <b>weil</b> ich in Berlin <u>wohne</u>.</td></tr><tr><td>dass</td><td>Ich glaube, <b>dass</b> KI nützlich <u>ist</u>.</td></tr><tr><td>wenn</td><td><b>Wenn</b> ich Zeit <u>habe</u>, lese ich ein Buch.</td></tr><tr><td>obwohl</td><td>Er kommt, <b>obwohl</b> er krank <u>ist</u>.</td></tr></table><p>💡 Se la frase secondaria viene per prima, la principale comincia col verbo: <i>Wenn ich Zeit habe, <u>gehe</u> ich spazieren.</i></p>", "ex": [{"l": "Ich bleibe zu Hause, weil ich krank ", "r": ".", "o": ["bin", "ist", "sein", "war nicht"], "c": 0, "e": "verbo alla fine: <b>… krank bin</b>."}, {"l": "Ich hoffe, dass du morgen ", "r": ".", "o": ["kommst", "kommen", "gekommen", "komme"], "c": 0, "e": "dass + … verbo alla fine: <b>kommst</b>."}, {"l": "Wenn das Wetter schön ", "r": ", gehen wir spazieren.", "o": ["ist", "sein", "bist", "war"], "c": 0, "e": "wenn + … <b>ist</b> alla fine."}, {"l": "Er arbeitet, obwohl er müde ", "r": ".", "o": ["ist", "sein", "sind", "bist"], "c": 0, "e": "obwohl + … <b>ist</b> alla fine."}]}, "wortschatz": [{"de": "das Handy", "it": "il cellulare", "exde": "Mein Handy ist kaputt.", "exit": "Il mio cellulare è rotto."}, {"de": "der Bildschirm", "it": "lo schermo", "exde": "Der Bildschirm ist hell.", "exit": "Lo schermo è luminoso."}, {"de": "die Nachricht", "it": "il messaggio/notizia", "exde": "Ich habe eine Nachricht bekommen.", "exit": "Ho ricevuto un messaggio."}, {"de": "herunterladen", "it": "scaricare", "exde": "Ich lade die App herunter.", "exit": "Scarico l'app."}, {"de": "speichern", "it": "salvare", "exde": "Speichere die Datei.", "exit": "Salva il file."}, {"de": "die künstliche Intelligenz", "it": "l'intelligenza artificiale", "exde": "KI verändert die Welt.", "exit": "L'IA cambia il mondo."}, {"de": "nützlich", "it": "utile", "exde": "Das ist sehr nützlich.", "exit": "È molto utile."}, {"de": "ablenken", "it": "distrarre", "exde": "Das Handy lenkt mich ab.", "exit": "Il cellulare mi distrae."}, {"de": "benutzen", "it": "usare", "exde": "Wie benutzt man das?", "exit": "Come si usa?"}, {"de": "die Gewohnheit", "it": "l'abitudine", "exde": "Es ist eine schlechte Gewohnheit.", "exit": "È una cattiva abitudine."}, {"de": "die Verantwortung", "it": "la responsabilità", "exde": "Wer trägt die Verantwortung?", "exit": "Chi ha la responsabilità?"}, {"de": "bewusst", "it": "consapevole", "exde": "Benutze es bewusst.", "exit": "Usalo in modo consapevole."}], "idiome": [{"de": "auf dem Laufenden sein", "lit": "Essere al corrente.", "mean": "Essere informato, aggiornato sulle novità.", "it": "Essere al corrente / aggiornato.", "exde": "Dank der App bin ich immer auf dem Laufenden.", "exit": "Grazie all'app sono sempre aggiornato."}, {"de": "den Anschluss verpassen", "lit": "Perdere la coincidenza.", "mean": "Restare indietro, non stare al passo coi tempi.", "it": "Perdere il treno / restare indietro.", "exde": "Wer nichts Neues lernt, verpasst den Anschluss.", "exit": "Chi non impara cose nuove resta indietro."}], "schreiben": {"impuls": "Schreib einen kurzen Kommentar (5–7 Sätze): Macht uns die Technik freier oder abhängiger?", "fragen": ["Sollten Kinder erst ab einem bestimmten Alter ein Smartphone haben? Ab wann und warum?", "Welche Aufgabe würdest du gern an eine KI abgeben — und welche niemals?"]}, "freunde": [{"de": "die Energie", "it": "energia"}, {"de": "das System", "it": "sistema"}, {"de": "das Projekt", "it": "progetto"}, {"de": "die Million", "it": "milione"}, {"de": "der Doktor", "it": "dottore"}, {"de": "die Medizin", "it": "medicina"}], "falsch": [{"de": "die Kantine", "it": "la mensa", "warn": "NON la cantina (= der Keller)"}, {"de": "die Note", "it": "il voto / la nota musicale", "warn": "NON la notte (= die Nacht)"}, {"de": "die Art", "it": "il tipo / il modo", "warn": "NON l'arte (= die Kunst)"}, {"de": "brav", "it": "ubbidiente / buono", "warn": "NON „bravo / capace\""}, {"de": "also", "it": "quindi / dunque", "warn": "NON „anche\" (= auch)"}], "lit": {"de": "Der brave Mann denkt an sich selbst zuletzt.", "it": "L'uomo valoroso pensa a sé per ultimo.", "src": "F. Schiller, Wilhelm Tell"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [{"de": "Ich bleibe zu Hause, weil es regnet.", "it": "Resto a casa perché piove."}, {"de": "Ich glaube, dass er recht hat.", "it": "Credo che abbia ragione."}], "song1": {"id": "VNttGAaek2U", "artist": "Revolverheld", "titel": "Lass uns gehen"}, "song2": {"id": "X5kmM98iklo", "artist": "Wir sind Helden", "titel": "Nur ein Wort"}, "articles": [{"title": "Wikipedia: Internet", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Internet"}, {"title": "Klexikon: Internet (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Internet"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Umwelt & Natur — Ambiente e natura", "level": "B1", "lesen": {"title": "Mein Versuch, nachhaltiger zu leben", "text": "Vor einem Jahr habe ich beschlossen, mein Leben ein bisschen grüner zu gestalten. Ich wollte die Welt nicht retten, aber wenigstens meinen kleinen Teil beitragen. Angefangen habe ich mit einfachen Dingen: Ich trenne meinen Müll, kaufe Gemüse auf dem Markt und nehme immer eine Stofftasche mit. Statt Fleisch zu essen, koche ich jetzt oft vegetarisch. Außerdem fahre ich kurze Strecken mit dem Fahrrad, anstatt das Auto zu nehmen. Ehrlich gesagt war nicht alles leicht. Manchmal ist es teurer oder dauert länger. Und natürlich frage ich mich, ob mein Beitrag überhaupt etwas bringt, wenn große Firmen weitermachen wie bisher. Trotzdem fühle ich mich besser. Ich glaube, Veränderung beginnt im Kleinen — und wenn viele mitmachen, wird daraus etwas Großes.", "glos": {"beschlossen": "deciso", "grüner": "più ecologico", "gestalten": "organizzare", "retten": "salvare", "beitragen": "contribuire", "trenne": "separo", "Müll": "rifiuti", "Stofftasche": "borsa di stoffa", "Fleisch": "carne", "vegetarisch": "vegetariano", "Strecken": "tratte", "teurer": "più costoso", "Beitrag": "contributo", "weitermachen": "continuare", "Veränderung": "cambiamento", "mitmachen": "partecipare"}, "q": [{"q": "Was hat die Person als Erstes geändert?", "o": ["Sie ist umgezogen", "Einfache Dinge wie Müll trennen", "Sie hat ein E-Auto gekauft"], "c": 1, "e": "„Angefangen habe ich mit einfachen Dingen\"."}, {"q": "Was war nicht immer leicht?", "o": ["Es war teurer oder dauerte länger", "Es war verboten", "Niemand half"], "c": 0, "e": "„Manchmal ist es teurer oder dauert länger\"."}, {"q": "Woran glaubt die Person?", "o": ["Nur Firmen können etwas ändern", "Veränderung beginnt im Kleinen", "Nichts bringt etwas"], "c": 1, "e": "„Veränderung beginnt im Kleinen\"."}], "frage": "Was tust du selbst für die Umwelt? Und was könntest du besser machen?"}, "artikel": {"title": "Die Stadt der Zukunft ist grün", "text": "Wie werden wir in dreißig Jahren leben? Viele Stadtplaner sind sich sicher: Die Stadt der Zukunft muss grüner werden. Schon heute kämpfen Großstädte mit Hitze, schlechter Luft und zu viel Verkehr. Bäume und Parks helfen dagegen, denn sie spenden Schatten und kühlen die Luft. In manchen Städten wachsen sogar auf den Dächern ganze Gärten. Auch der Verkehr soll sich ändern: mehr Platz für Fußgänger und Fahrräder, weniger Autos. In Paris zum Beispiel sollen die Menschen alles, was sie täglich brauchen, in fünfzehn Minuten zu Fuß erreichen können. Solche Ideen klingen für manche utopisch. Doch der Klimawandel zwingt uns, neu zu denken. Die gute Nachricht: Eine grüne Stadt ist nicht nur gesünder, sondern auch schöner zum Leben.", "glos": {"Stadtplaner": "urbanisti", "grüner": "più verde", "kämpfen": "lottano", "Hitze": "caldo", "Luft": "aria", "Verkehr": "traffico", "Bäume": "alberi", "spenden": "offrono", "Schatten": "ombra", "kühlen": "rinfrescano", "Dächern": "tetti", "Fußgänger": "pedoni", "erreichen": "raggiungere", "utopisch": "utopistico", "Klimawandel": "cambiamento climatico", "zwingt": "costringe"}, "q": [{"q": "Wie hilft Grün gegen die Hitze?", "o": ["Es macht Lärm", "Bäume spenden Schatten und kühlen die Luft", "Es kostet nichts"], "c": 1, "e": "„sie spenden Schatten und kühlen die Luft\"."}, {"q": "Was ist die Idee in Paris?", "o": ["Keine Autos mehr bauen", "Alles in 15 Minuten zu Fuß erreichen", "Mehr Hochhäuser"], "c": 1, "e": "„in fünfzehn Minuten zu Fuß erreichen\"."}], "news": "grüne Stadt Zukunft Klima"}, "dialog": {"title": "Mülltrennung — gar nicht so einfach", "lines": [{"who": "Nachbar", "de": "Entschuldigung, darf ich fragen? Wo kommt der Joghurtbecher hin?"}, {"who": "Anna", "de": "In den Gelben Sack. Das ist Plastikverpackung."}, {"who": "Nachbar", "de": "Ach so. Und das alte Brot?"}, {"who": "Anna", "de": "Das ist Biomüll, also in die braune Tonne."}, {"who": "Nachbar", "de": "Mensch, das ist ja kompliziert. Und Papier?"}, {"who": "Anna", "de": "Papier und Karton kommen in die blaue Tonne."}, {"who": "Nachbar", "de": "Und wenn ich mir nicht sicher bin?"}, {"who": "Anna", "de": "Dann lieber Restmüll. Aber Glas immer extra, nach Farben getrennt."}, {"who": "Nachbar", "de": "Okay, langsam verstehe ich das System. Danke dir!"}, {"who": "Anna", "de": "Kein Problem. Am Anfang macht das jeder falsch."}], "q": [{"q": "Wo kommt der Joghurtbecher hin?", "o": ["In den Gelben Sack", "In die braune Tonne", "Ins Glas"], "c": 0, "e": "„In den Gelben Sack. Das ist Plastikverpackung\"."}, {"q": "Was kommt in die braune Tonne?", "o": ["Papier", "Biomüll", "Plastik"], "c": 1, "e": "„Das ist Biomüll, also in die braune Tonne\"."}, {"q": "Wie muss man Glas entsorgen?", "o": ["Mit dem Restmüll", "Nach Farben getrennt", "In den Gelben Sack"], "c": 1, "e": "„Glas immer extra, nach Farben getrennt\"."}]}, "musik": {"key": "nena", "task": "„99 Luftballons\" sembra una canzone allegra ma parla di guerra e paura nucleare. Mentre ascolti, nota il contrasto tra la melodia leggera e il tema serio. Cerca la parola „Luftballons\" (palloncini).", "level": "B1 · classico"}, "sprechen": {"read": "Ich versuche, umweltbewusster zu leben. Ich trenne meinen Müll, kaufe regional ein und fahre öfter mit dem Fahrrad. Natürlich ist nicht alles leicht, aber ich glaube, dass jeder kleine Beitrag wichtig ist.", "prompts": [{"q": "Was tust du konkret für die Umwelt?", "e": "Ich … zum Beispiel …"}, {"q": "Wer ist mehr verantwortlich: der Einzelne oder die Politik?", "e": "Ich denke, … weil …"}, {"q": "Würdest du auf das Auto verzichten? Unter welchen Bedingungen?", "e": "Ich würde …, wenn …"}], "scenario": "Dein Nachbar versteht die Mülltrennung nicht. Erklär ihm freundlich das System."}, "grammatik": {"titel": "Der Konjunktiv II mit „würde\" (ipotesi e cortesia)", "regel_html": "<p>Il <b>Konjunktiv II</b> esprime ipotesi, desideri e richieste cortesi. La forma più comune è <b>würde + infinito</b>.</p><table class='gtab'><tr><th>uso</th><th>esempio</th></tr><tr><td>ipotesi</td><td><b>Wenn</b> ich reich <b>wäre</b>, <b>würde</b> ich reisen.</td></tr><tr><td>desiderio</td><td>Ich <b>würde</b> gern ans Meer fahren.</td></tr><tr><td>cortesia</td><td><b>Könnten</b> Sie mir helfen? / Ich <b>hätte</b> gern …</td></tr></table><p>Forme irregolari frequenti: <b>sein → wäre</b>, <b>haben → hätte</b>, <b>können → könnte</b>, <b>werden → würde</b>.</p><p><b>Esempi:</b> <i>Ich <u>hätte</u> gern einen Kaffee.</i> · <i>An deiner Stelle <u>würde</u> ich das nicht tun.</i></p>", "ex": [{"l": "Wenn ich Zeit hätte, ", "r": " ich dir helfen.", "o": ["würde", "werde", "wäre", "habe"], "c": 0, "e": "ipotesi: <b>würde</b> + infinito (helfen)."}, {"l": "Ich ", "r": " gern ein Wasser, bitte.", "o": ["hätte", "habe", "wäre", "würde"], "c": 0, "e": "richiesta cortese: <b>hätte gern</b>."}, {"l": "", "r": " Sie mir bitte helfen?", "o": ["Könnten", "Können", "Konnten", "Könntet"], "c": 0, "e": "forma cortese: <b>Könnten</b> Sie …?"}, {"l": "Wenn ich du ", "r": ", würde ich es versuchen.", "o": ["wäre", "bin", "war", "sein"], "c": 0, "e": "sein → <b>wäre</b> nel Konjunktiv II."}]}, "wortschatz": [{"de": "die Umwelt", "it": "l'ambiente", "exde": "Wir müssen die Umwelt schützen.", "exit": "Dobbiamo proteggere l'ambiente."}, {"de": "der Müll", "it": "i rifiuti", "exde": "Trenn bitte den Müll.", "exit": "Separa i rifiuti, per favore."}, {"de": "der Klimawandel", "it": "il cambiamento climatico", "exde": "Der Klimawandel ist real.", "exit": "Il cambiamento climatico è reale."}, {"de": "die Natur", "it": "la natura", "exde": "Ich liebe die Natur.", "exit": "Amo la natura."}, {"de": "der Baum", "it": "l'albero", "exde": "Der Baum ist sehr alt.", "exit": "L'albero è molto vecchio."}, {"de": "schützen", "it": "proteggere", "exde": "Wir schützen die Tiere.", "exit": "Proteggiamo gli animali."}, {"de": "nachhaltig", "it": "sostenibile", "exde": "Wir leben nachhaltig.", "exit": "Viviamo in modo sostenibile."}, {"de": "vermeiden", "it": "evitare", "exde": "Vermeide Plastik.", "exit": "Evita la plastica."}, {"de": "die Energie", "it": "l'energia", "exde": "Spar Energie!", "exit": "Risparmia energia!"}, {"de": "der Beitrag", "it": "il contributo", "exde": "Jeder Beitrag zählt.", "exit": "Ogni contributo conta."}, {"de": "verzichten auf", "it": "rinunciare a", "exde": "Ich verzichte auf Plastik.", "exit": "Rinuncio alla plastica."}, {"de": "verschmutzen", "it": "inquinare", "exde": "Autos verschmutzen die Luft.", "exit": "Le auto inquinano l'aria."}], "idiome": [{"de": "auf großem Fuß leben", "lit": "Vivere su un piede grande.", "mean": "Vivere nel lusso, spendere molto.", "it": "Vivere alla grande / nel lusso.", "exde": "Sie lebt auf großem Fuß und verbraucht viel.", "exit": "Vive nel lusso e consuma molto."}, {"de": "ins Gras beißen", "lit": "Mordere l'erba.", "mean": "Morire (colloquiale e ironico).", "it": "Tirare le cuoia.", "exde": "Ohne Wasser beißen die Pflanzen bald ins Gras.", "exit": "Senza acqua le piante presto muoiono."}], "schreiben": {"impuls": "Schreib einen kurzen Text: Welche drei Dinge sollte jeder für die Umwelt tun? Begründe.", "fragen": ["Ist es fair, vom Einzelnen Verzicht zu verlangen, während Konzerne weitermachen?", "Was würdest du in deiner Stadt ändern, um sie grüner zu machen?"]}, "freunde": [{"de": "der Doktor", "it": "dottore"}, {"de": "die Medizin", "it": "medicina"}, {"de": "die Rose", "it": "rosa"}, {"de": "der Salat", "it": "insalata (≈ salad)"}, {"de": "die Tomate", "it": "pomodoro (≈ tomato)"}, {"de": "die Banane", "it": "banana"}], "falsch": [{"de": "brav", "it": "ubbidiente / buono", "warn": "NON „bravo / capace\""}, {"de": "also", "it": "quindi / dunque", "warn": "NON „anche\" (= auch)"}, {"de": "fast", "it": "quasi", "warn": "NON „veloce\" (= schnell)"}, {"de": "bald", "it": "presto", "warn": "NON „baldo\""}, {"de": "komisch", "it": "strano (spesso) / buffo", "warn": "attenzione: di solito = strano"}], "lit": {"de": "Edel sei der Mensch, hilfreich und gut.", "it": "Sia nobile l'uomo, generoso e buono.", "src": "J. W. Goethe"}, "trad": {"id": "gedanken", "title": "Die Gedanken sind frei", "artist": "Volkslied", "note": "Canto popolare sulla libertà di pensiero, amatissimo in Germania.", "ytq": "Die Gedanken sind frei Lied", "de": ["Die Gedanken sind frei,", "wer kann sie erraten?", "Sie fliehen vorbei", "wie nächtliche Schatten.", "Kein Mensch kann sie wissen,", "kein Jäger erschießen;", "es bleibet dabei:", "die Gedanken sind frei!"], "it": ["I pensieri sono liberi,", "chi può indovinarli?", "Volano via", "come ombre nella notte.", "Nessuno può conoscerli,", "nessun cacciatore può abbatterli;", "resta così:", "i pensieri sono liberi!"]}, "voice": {"id": "kRq3WzSwUw0", "t": "Straßeninterviews in Magdeburg", "note": "Ascolto autentico con sottotitoli tedeschi."}, "gram_extra": [{"de": "An deiner Stelle würde ich mehr schlafen.", "it": "Al posto tuo dormirei di più."}, {"de": "Würden Sie mir bitte helfen?", "it": "Mi aiuterebbe, per favore?"}], "song1": {"id": "GsRuJjgyZdQ", "artist": "Silbermond", "titel": "Irgendwas bleibt"}, "song2": {"id": "1il3RFk5Okw", "artist": "Mark Forster", "titel": "Chöre"}, "articles": [{"title": "Wikipedia: Umweltschutz", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Umweltschutz"}, {"title": "Klexikon: Natur (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Natur"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Bildung & Lernen — Istruzione e apprendimento", "level": "B1", "lesen": {"title": "Warum ich nie aufhöre zu lernen", "text": "Als ich die Schule beendet habe, dachte ich: Endlich vorbei mit dem Lernen! Heute, viele Jahre später, weiß ich, wie falsch dieser Gedanke war. Das Lernen hat nie aufgehört — es hat sich nur verändert. Statt für Prüfungen zu pauken, lerne ich heute, weil ich neugierig bin. Ich lese Bücher über Themen, die mich interessieren, schaue Dokumentationen und natürlich lerne ich Deutsch. Das Schöne daran ist: Niemand zwingt mich. Ich entscheide selbst, was und wie schnell ich lerne. Manchmal mache ich Fehler oder verstehe etwas lange nicht. Früher hätte mich das frustriert, heute sehe ich es als Teil des Weges. Ich bin überzeugt: Wer aufhört zu lernen, wird alt — egal in welchem Alter. Solange wir neugierig bleiben, bleiben wir lebendig.", "glos": {"beendet": "finita", "Gedanke": "pensiero", "verändert": "cambiato", "Prüfungen": "esami", "pauken": "sgobbare", "neugierig": "curioso", "Dokumentationen": "documentari", "zwingt": "costringe", "entscheide": "decido", "Fehler": "errori", "frustriert": "frustrato", "überzeugt": "convinto", "aufhört": "smette", "Alter": "età", "lebendig": "vivi"}, "q": [{"q": "Was dachte die Person nach der Schule?", "o": ["Sie will weiterlernen", "Endlich vorbei mit dem Lernen", "Sie will Lehrerin werden"], "c": 1, "e": "„Endlich vorbei mit dem Lernen!\""}, {"q": "Warum lernt sie heute?", "o": ["Weil sie muss", "Weil sie neugierig ist", "Für eine Prüfung"], "c": 1, "e": "„weil ich neugierig bin\"."}, {"q": "Was ist ihre Überzeugung?", "o": ["Wer aufhört zu lernen, wird alt", "Lernen ist sinnlos", "Nur junge Menschen lernen"], "c": 0, "e": "„Wer aufhört zu lernen, wird alt\"."}], "frage": "Was möchtest du in deinem Leben noch lernen — und was hält dich bisher davon ab?"}, "artikel": {"title": "Macht die Schule uns wirklich fürs Leben fit?", "text": "Über kaum etwas wird so viel gestritten wie über die Schule. Viele Erwachsene erinnern sich mit gemischten Gefühlen: An gute Lehrer, aber auch an Stress, Noten und Fächer, die sie nie wieder gebraucht haben. Eine alte Kritik lautet: Die Schule bereitet uns nicht aufs echte Leben vor. Wir lernen die Hauptstädte ferner Länder, aber nicht, wie man eine Steuererklärung macht oder mit Geld umgeht. Verteidiger der Schule antworten, dass es nicht nur um Wissen geht, sondern darum, Denken zu lernen. Wer einmal gelernt hat, ein Problem zu analysieren, kann das später überall anwenden. Sicher ist: Die Schule muss sich verändern. In einer Welt, die sich so schnell wandelt, reicht es nicht mehr, nur Fakten auswendig zu lernen. Viel wichtiger ist die Fähigkeit, immer wieder Neues zu lernen.", "glos": {"gestritten": "discusso", "Erwachsene": "adulti", "gemischten": "contrastanti", "Noten": "voti", "Fächer": "materie", "Kritik": "critica", "bereitet … vor": "prepara", "Steuererklärung": "dichiarazione dei redditi", "umgeht": "gestisce", "Verteidiger": "difensori", "Wissen": "sapere", "analysieren": "analizzare", "anwenden": "applicare", "wandelt": "cambia", "Fakten": "fatti", "auswendig": "a memoria", "Fähigkeit": "capacità"}, "q": [{"q": "Wie lautet eine alte Kritik an der Schule?", "o": ["Sie ist zu leicht", "Sie bereitet nicht aufs echte Leben vor", "Sie ist zu kurz"], "c": 1, "e": "„bereitet uns nicht aufs echte Leben vor\"."}, {"q": "Was ist laut Text heute besonders wichtig?", "o": ["Fakten auswendig lernen", "Immer wieder Neues lernen können", "Viele Sprachen sprechen"], "c": 1, "e": "„die Fähigkeit, immer wieder Neues zu lernen\"."}], "news": "Schule Bildung Reform Deutschland"}, "dialog": {"title": "Lerntipps unter Freunden", "lines": [{"who": "Sara", "de": "Du sprichst schon so gut Deutsch! Wie machst du das?"}, {"who": "Jonas", "de": "Danke! Ehrlich gesagt: jeden Tag ein bisschen, nicht alles auf einmal."}, {"who": "Sara", "de": "Bei mir bleibt nichts hängen. Ich vergesse die Vokabeln sofort."}, {"who": "Jonas", "de": "Lernst du sie mit Sätzen oder nur als Liste?"}, {"who": "Sara", "de": "Nur als Liste, eine Spalte Deutsch, eine Spalte Italienisch."}, {"who": "Jonas", "de": "Das ist das Problem. Lern die Wörter lieber in einem Satz."}, {"who": "Sara", "de": "Echt? Hilft das wirklich?"}, {"who": "Jonas", "de": "Total. Und sprich laut, auch wenn du Fehler machst."}, {"who": "Sara", "de": "Okay, das probiere ich. Und Serien auf Deutsch?"}, {"who": "Jonas", "de": "Super Idee. Erst mit Untertiteln, später ohne."}], "q": [{"q": "Wie lernt Jonas?", "o": ["Alles auf einmal", "Jeden Tag ein bisschen", "Nur am Wochenende"], "c": 1, "e": "„jeden Tag ein bisschen\"."}, {"q": "Was ist Saras Problem?", "o": ["Sie hat keine Zeit", "Sie lernt Wörter nur als Liste", "Sie spricht zu viel"], "c": 1, "e": "„Nur als Liste …\""}, {"q": "Welchen Tipp gibt Jonas für Serien?", "o": ["Ohne Ton schauen", "Erst mit, später ohne Untertitel", "Nur auf Italienisch"], "c": 1, "e": "„Erst mit Untertiteln, später ohne\"."}]}, "musik": {"key": "amk", "task": "„Pocahontas\" di AnnenMayKantereit ha un tedesco moderno e una voce molto particolare. È più difficile da capire: usalo per allenare l'orecchio al parlato reale. Riascolta più volte e cerca di afferrare singole parole.", "level": "B1–B2 · voce particolare"}, "sprechen": {"read": "Ich lerne jeden Tag ein bisschen Deutsch, denn so bleibt mehr hängen. Ich lerne neue Wörter immer in einem ganzen Satz und ich spreche laut, auch wenn ich Fehler mache. Außerdem schaue ich Serien auf Deutsch, erst mit Untertiteln, später ohne.", "prompts": [{"q": "Wie lernst du am liebsten? Beschreib deine Methode.", "e": "Am liebsten lerne ich, indem ich …"}, {"q": "Was war das Schwierigste, das du je gelernt hast?", "e": "Das Schwierigste war …, weil …"}, {"q": "Sollte man in der Schule mehr Praktisches lernen? Deine Meinung.", "e": "Ich finde, … weil …"}], "scenario": "Ein Freund will Italienisch lernen und fragt dich um Rat. Gib ihm drei konkrete Tipps."}, "grammatik": {"titel": "Relativsätze (der, die, das …)", "regel_html": "<p>Le <b>frasi relative</b> danno informazioni in più su un nome. Il pronome relativo (<b>der/die/das</b>) concorda in genere e numero col nome, ma il suo <b>caso</b> dipende dalla funzione nella frase relativa. Il verbo va <b>alla fine</b>.</p><table class='gtab'><tr><th></th><th>masch.</th><th>femm.</th><th>neutro</th><th>plur.</th></tr><tr><td>Nom.</td><td>der</td><td>die</td><td>das</td><td>die</td></tr><tr><td>Akk.</td><td>den</td><td>die</td><td>das</td><td>die</td></tr><tr><td>Dat.</td><td>dem</td><td>der</td><td>dem</td><td>denen</td></tr></table><p><b>Esempi:</b> <i>Der Mann, <u>der</u> dort steht, ist mein Lehrer.</i> (Nom.) · <i>Das Buch, <u>das</u> ich lese, ist spannend.</i> (Akk.) · <i>Die Frau, <u>der</u> ich helfe, ist nett.</i> (Dat.)</p>", "ex": [{"l": "Das ist der Mann, ", "r": " in Berlin wohnt.", "o": ["der", "den", "dem", "die"], "c": 0, "e": "soggetto della relativa → Nom. masch.: <b>der</b>."}, {"l": "Das Buch, ", "r": " ich lese, ist toll.", "o": ["der", "das", "dem", "die"], "c": 1, "e": "oggetto, neutro → Akk.: <b>das</b>."}, {"l": "Die Stadt, in ", "r": " ich wohne, ist klein.", "o": ["der", "die", "dem", "das"], "c": 0, "e": "in + Dat. femm.: in <b>der</b>."}, {"l": "Die Leute, ", "r": " ich helfe, sind nett.", "o": ["die", "der", "den", "denen"], "c": 3, "e": "helfen + Dat. plurale: <b>denen</b>."}]}, "wortschatz": [{"de": "lernen", "it": "imparare", "exde": "Ich lerne jeden Tag.", "exit": "Imparo ogni giorno."}, {"de": "die Prüfung", "it": "l'esame", "exde": "Die Prüfung ist morgen.", "exit": "L'esame è domani."}, {"de": "die Note", "it": "il voto", "exde": "Ich habe eine gute Note.", "exit": "Ho un bel voto."}, {"de": "das Fach", "it": "la materia", "exde": "Mein Lieblingsfach ist Kunst.", "exit": "La mia materia preferita è arte."}, {"de": "der Fehler", "it": "l'errore", "exde": "Aus Fehlern lernt man.", "exit": "Si impara dagli errori."}, {"de": "üben", "it": "esercitarsi", "exde": "Ich übe Vokabeln.", "exit": "Esercito i vocaboli."}, {"de": "verstehen", "it": "capire", "exde": "Ich verstehe das nicht.", "exit": "Non lo capisco."}, {"de": "vergessen", "it": "dimenticare", "exde": "Ich vergesse die Wörter.", "exit": "Dimentico le parole."}, {"de": "neugierig", "it": "curioso", "exde": "Sei neugierig!", "exit": "Sii curioso!"}, {"de": "das Wissen", "it": "il sapere", "exde": "Wissen ist Macht.", "exit": "Sapere è potere."}, {"de": "die Fähigkeit", "it": "la capacità", "exde": "Das ist eine wichtige Fähigkeit.", "exit": "È una capacità importante."}, {"de": "auswendig", "it": "a memoria", "exde": "Ich lerne es auswendig.", "exit": "Lo imparo a memoria."}], "idiome": [{"de": "Es ist noch kein Meister vom Himmel gefallen.", "lit": "Nessun maestro è caduto dal cielo.", "mean": "Nessuno nasce esperto; tutto richiede pratica.", "it": "Nessuno nasce imparato.", "exde": "Mach weiter — es ist noch kein Meister vom Himmel gefallen.", "exit": "Continua: nessuno nasce imparato."}, {"de": "Lehrjahre sind keine Herrenjahre.", "lit": "Gli anni di apprendistato non sono da signori.", "mean": "All'inizio si fatica e si impara, senza pretese.", "it": "Chi vuole imparare deve faticare.", "exde": "Sei geduldig: Lehrjahre sind keine Herrenjahre.", "exit": "Abbi pazienza: l'apprendistato richiede sacrificio."}], "schreiben": {"impuls": "Beschreib deine beste Lernerfahrung: Was hast du gelernt und warum hat es funktioniert?", "fragen": ["Braucht man im Zeitalter des Internets überhaupt noch Schulen? Begründe.", "Was ist wichtiger: gute Noten oder echtes Verständnis? Warum?"]}, "freunde": [{"de": "die Tomate", "it": "pomodoro (≈ tomato)"}, {"de": "die Banane", "it": "banana"}, {"de": "der Tee", "it": "tè / tea"}, {"de": "die Lampe", "it": "lampada / lamp"}, {"de": "die Garage", "it": "garage"}, {"de": "die Schokolade", "it": "cioccolato (≈ chocolate)"}], "falsch": [{"de": "bald", "it": "presto", "warn": "NON „baldo\""}, {"de": "komisch", "it": "strano (spesso) / buffo", "warn": "attenzione: di solito = strano"}, {"de": "die Birne", "it": "la pera / la lampadina", "warn": "NON „birra\" (= das Bier)"}, {"de": "sensibel", "it": "sensibile / delicato", "warn": "NON „sensato\" (= vernünftig)"}, {"de": "der Termin", "it": "l'appuntamento", "warn": "NON il „termine/scadenza-parola\""}], "lit": {"de": "Früh übt sich, was ein Meister werden will.", "it": "Presto si esercita chi vuol diventare maestro.", "src": "F. Schiller"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Das ist der Mann, der nebenan wohnt.", "it": "È l'uomo che abita di fianco."}, {"de": "Die Stadt, die ich besucht habe, war schön.", "it": "La città che ho visitato era bella."}], "song1": {"id": "deDquONycuA", "artist": "Silbermond", "titel": "Symphonie"}, "song2": {"id": "k9EYjn5f_nE", "artist": "Andreas Bourani", "titel": "Auf uns"}, "articles": [{"title": "Wikipedia: Bildung", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Bildung"}, {"title": "Klexikon: Schule (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Schule"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Gefühle & Beziehungen — Emozioni e relazioni", "level": "B1", "lesen": {"title": "Der Wert echter Freundschaft", "text": "In einer Zeit, in der man Hunderte „Freunde\" im Internet haben kann, frage ich mich oft, was Freundschaft eigentlich bedeutet. Für mich ist ein echter Freund nicht der, der jeden Tag schreibt, sondern der, der da ist, wenn es darauf ankommt. Meine beste Freundin und ich sehen uns manchmal monatelang nicht, weil wir in verschiedenen Städten leben. Trotzdem ist es jedes Mal, wenn wir telefonieren, als hätten wir uns gestern erst gesehen. Echte Freundschaft braucht keine ständige Aufmerksamkeit, sondern Vertrauen. Natürlich gibt es auch Streit. Aber gerade die Fähigkeit, sich zu streiten und sich danach wieder zu versöhnen, macht eine Beziehung stark. Ich bin überzeugt: Lieber drei Menschen, denen ich wirklich vertraue, als dreihundert, die mich kaum kennen. Qualität schlägt Quantität — bei Freundschaften ganz besonders.", "glos": {"Wert": "valore", "Freundschaft": "amicizia", "bedeutet": "significa", "ankommt": "conta", "monatelang": "per mesi", "verschiedenen": "diverse", "Aufmerksamkeit": "attenzione", "Vertrauen": "fiducia", "Streit": "litigio", "Fähigkeit": "capacità", "versöhnen": "riconciliarsi", "Beziehung": "relazione", "überzeugt": "convinto", "vertraue": "mi fido", "Qualität": "qualità", "Quantität": "quantità"}, "q": [{"q": "Was ist für die Person ein echter Freund?", "o": ["Wer jeden Tag schreibt", "Wer da ist, wenn es darauf ankommt", "Wer viele Likes gibt"], "c": 1, "e": "„der da ist, wenn es darauf ankommt\"."}, {"q": "Was braucht echte Freundschaft?", "o": ["Ständige Aufmerksamkeit", "Vertrauen", "Tägliche Treffen"], "c": 1, "e": "„sondern Vertrauen\"."}, {"q": "Was ist ihre Überzeugung am Ende?", "o": ["Quantität ist wichtig", "Qualität schlägt Quantität", "Freunde braucht man nicht"], "c": 1, "e": "„Qualität schlägt Quantität\"."}], "frage": "Was bedeutet Freundschaft für dich? Und wie hältst du Kontakt zu Menschen, die weit weg sind?"}, "artikel": {"title": "Warum es okay ist, über Gefühle zu reden", "text": "Lange galt in vielen Kulturen die Regel: Über Gefühle spricht man nicht, vor allem Männer nicht. „Ein Junge weint nicht\", hieß es früher oft. Heute ändert sich das langsam. Immer mehr Menschen verstehen, dass es Stärke und nicht Schwäche ist, über Sorgen, Angst oder Traurigkeit zu sprechen. Psychologen betonen, dass unterdrückte Gefühle krank machen können. Wer dagegen offen redet — mit Freunden, der Familie oder einem Therapeuten — fühlt sich oft erleichtert und findet leichter Lösungen. Auch in Schulen und Firmen wird das Thema wichtiger. Man spricht heute offener über mentale Gesundheit als noch vor zwanzig Jahren. Das ist eine gute Entwicklung. Denn am Ende ist niemand allein mit seinen Problemen — man muss nur den Mut finden, darüber zu sprechen.", "glos": {"galt": "valeva", "Regel": "regola", "weint": "piange", "Stärke": "forza", "Schwäche": "debolezza", "Sorgen": "preoccupazioni", "Angst": "paura", "Traurigkeit": "tristezza", "betonen": "sottolineano", "unterdrückte": "represse", "offen": "apertamente", "Therapeuten": "terapeuta", "erleichtert": "sollevato", "Lösungen": "soluzioni", "mentale": "mentale", "Entwicklung": "sviluppo", "Mut": "coraggio"}, "q": [{"q": "Welche alte Regel nennt der Text?", "o": ["Männer reden nicht über Gefühle", "Man muss immer lächeln", "Gefühle sind verboten"], "c": 0, "e": "„Ein Junge weint nicht\"."}, {"q": "Was sagen Psychologen über unterdrückte Gefühle?", "o": ["Sie sind gesund", "Sie können krank machen", "Sie sind egal"], "c": 1, "e": "„unterdrückte Gefühle … können krank machen\"."}], "news": "über Gefühle reden mentale Gesundheit"}, "dialog": {"title": "Ein offenes Gespräch", "lines": [{"who": "Mia", "de": "Du wirkst in letzter Zeit so müde. Ist alles okay?"}, {"who": "Tom", "de": "Ach … ehrlich gesagt nicht so richtig."}, {"who": "Mia", "de": "Willst du darüber reden? Ich höre dir gern zu."}, {"who": "Tom", "de": "Ich habe gerade viel Stress, und ich fühle mich überfordert."}, {"who": "Mia", "de": "Das tut mir leid. Seit wann geht das schon so?"}, {"who": "Tom", "de": "Seit ein paar Wochen. Ich schlafe schlecht und bin oft gereizt."}, {"who": "Mia", "de": "Hast du mal überlegt, mit jemandem professionell zu sprechen?"}, {"who": "Tom", "de": "Daran habe ich gedacht, aber ich traue mich nicht so recht."}, {"who": "Mia", "de": "Das ist kein Zeichen von Schwäche, im Gegenteil."}, {"who": "Tom", "de": "Danke, dass du fragst. Das tut schon gut, einfach zu reden."}], "q": [{"q": "Wie fühlt sich Tom?", "o": ["Glücklich", "Überfordert und gestresst", "Gelangweilt"], "c": 1, "e": "„ich fühle mich überfordert\"."}, {"q": "Was schlägt Mia vor?", "o": ["Urlaub machen", "Mit jemandem professionell sprechen", "Mehr arbeiten"], "c": 1, "e": "„mit jemandem professionell zu sprechen\"."}, {"q": "Was sagt Mia über das Reden?", "o": ["Es ist Schwäche", "Es ist kein Zeichen von Schwäche", "Es bringt nichts"], "c": 1, "e": "„kein Zeichen von Schwäche\"."}]}, "musik": {"key": "amk", "task": "„Pocahontas\" parla di sentimenti e di un amore complicato. Ascolta l'emozione nella voce. Prova a capire l'atmosfera del brano anche senza capire ogni parola: è un'abilità importante.", "level": "B1–B2 · emotivo"}, "sprechen": {"read": "Für mich ist ein echter Freund jemand, der da ist, wenn es darauf ankommt. Wir sehen uns nicht oft, aber wir vertrauen einander. Ich glaube, dass Qualität wichtiger ist als Quantität, gerade bei Freundschaften.", "prompts": [{"q": "Wie würdest du einen guten Freund beschreiben?", "e": "Ein guter Freund ist jemand, der …"}, {"q": "Fällt es dir leicht, über Gefühle zu reden? Warum (nicht)?", "e": "Es fällt mir (nicht) leicht, weil …"}, {"q": "Was machst du, wenn ein Freund traurig ist?", "e": "Wenn ein Freund traurig ist, …"}], "scenario": "Ein Freund wirkt traurig. Sprich ihn vorsichtig an und biete deine Hilfe an."}, "grammatik": {"titel": "Reflexive Verben und Wechselpräpositionen", "regel_html": "<p>I <b>verbi riflessivi</b> usano un pronome riflessivo (mich, dich, sich …): <i>sich freuen</i> (rallegrarsi), <i>sich fühlen</i> (sentirsi), <i>sich treffen</i> (incontrarsi).</p><table class='gtab'><tr><th>persona</th><th>pronome</th><th>esempio</th></tr><tr><td>ich</td><td>mich</td><td>Ich freue <b>mich</b>.</td></tr><tr><td>du</td><td>dich</td><td>Du fühlst <b>dich</b> gut.</td></tr><tr><td>er/sie</td><td>sich</td><td>Sie freut <b>sich</b>.</td></tr></table><p>Spesso seguono una preposizione fissa: <i>sich freuen <b>auf</b></i> (qualcosa di futuro), <i>sich freuen <b>über</b></i> (qualcosa di presente/passato), <i>sich ärgern <b>über</b></i>.</p><p><b>Esempi:</b> <i>Ich freue mich <u>auf</u> das Wochenende.</i> · <i>Sie ärgert sich <u>über</u> den Stau.</i></p>", "ex": [{"l": "Ich freue ", "r": " auf das Wochenende.", "o": ["mich", "mir", "sich", "dich"], "c": 0, "e": "riflessivo (ich) → <b>mich</b>."}, {"l": "Wie fühlst du ", "r": " heute?", "o": ["dich", "dir", "sich", "mich"], "c": 0, "e": "riflessivo (du) → <b>dich</b>."}, {"l": "Sie ärgert sich ", "r": " den Stau.", "o": ["über", "auf", "für", "mit"], "c": 0, "e": "sich ärgern <b>über</b>."}, {"l": "Wir treffen ", "r": " um acht Uhr.", "o": ["uns", "sich", "euch", "mich"], "c": 0, "e": "riflessivo (wir) → <b>uns</b>."}]}, "wortschatz": [{"de": "das Gefühl", "it": "il sentimento", "exde": "Ich habe ein gutes Gefühl.", "exit": "Ho una bella sensazione."}, {"de": "die Freundschaft", "it": "l'amicizia", "exde": "Unsere Freundschaft ist stark.", "exit": "La nostra amicizia è forte."}, {"de": "das Vertrauen", "it": "la fiducia", "exde": "Vertrauen ist wichtig.", "exit": "La fiducia è importante."}, {"de": "glücklich", "it": "felice", "exde": "Ich bin glücklich.", "exit": "Sono felice."}, {"de": "traurig", "it": "triste", "exde": "Warum bist du traurig?", "exit": "Perché sei triste?"}, {"de": "die Angst", "it": "la paura", "exde": "Ich habe keine Angst.", "exit": "Non ho paura."}, {"de": "sich freuen", "it": "rallegrarsi", "exde": "Ich freue mich sehr.", "exit": "Sono molto contento."}, {"de": "sich ärgern", "it": "arrabbiarsi", "exde": "Ärgere dich nicht.", "exit": "Non arrabbiarti."}, {"de": "der Streit", "it": "il litigio", "exde": "Wir hatten einen Streit.", "exit": "Abbiamo litigato."}, {"de": "sich versöhnen", "it": "riconciliarsi", "exde": "Sie haben sich versöhnt.", "exit": "Si sono riconciliati."}, {"de": "vermissen", "it": "sentire la mancanza", "exde": "Ich vermisse dich.", "exit": "Mi manchi."}, {"de": "zuhören", "it": "ascoltare", "exde": "Ich höre dir zu.", "exit": "Ti ascolto."}], "idiome": [{"de": "Geteiltes Leid ist halbes Leid.", "lit": "Un dolore condiviso è un dolore dimezzato.", "mean": "Parlare dei problemi li rende più leggeri.", "it": "Mal comune mezzo gaudio (≈).", "exde": "Erzähl es mir — geteiltes Leid ist halbes Leid.", "exit": "Raccontamelo: il dolore condiviso pesa meno."}, {"de": "jemandem das Herz ausschütten", "lit": "Versare il cuore a qualcuno.", "mean": "Confidare a qualcuno tutti i propri problemi.", "it": "Aprirsi / sfogarsi con qualcuno.", "exde": "Sie hat mir gestern ihr Herz ausgeschüttet.", "exit": "Ieri si è confidata con me."}], "schreiben": {"impuls": "Schreib über einen Menschen, der dir wichtig ist, und warum. Wie habt ihr euch kennengelernt?", "fragen": ["Können echte Freundschaften nur online entstehen und bestehen? Was denkst du?", "Wann hast du das letzte Mal jemandem geholfen — und wie hat sich das angefühlt?"]}, "freunde": [{"de": "die Garage", "it": "garage"}, {"de": "die Schokolade", "it": "cioccolato (≈ chocolate)"}, {"de": "der Tiger", "it": "tigre"}, {"de": "die Familie", "it": "famiglia"}, {"de": "die Familie", "it": "famiglia / family"}, {"de": "das Hotel", "it": "hotel"}], "falsch": [{"de": "sensibel", "it": "sensibile / delicato", "warn": "NON „sensato\" (= vernünftig)"}, {"de": "der Termin", "it": "l'appuntamento", "warn": "NON il „termine/scadenza-parola\""}, {"de": "das Rezept", "it": "la ricetta / la prescrizione", "warn": "vale sia in cucina sia dal medico"}, {"de": "bekommen", "it": "ricevere", "warn": "NON „diventare\" (to become)"}, {"de": "das Gift", "it": "il veleno", "warn": "NON „regalo\" (gift)"}], "lit": {"de": "Wer fremde Sprachen nicht kennt, weiß nichts von seiner eigenen.", "it": "Chi non conosce lingue straniere non sa nulla della propria.", "src": "J. W. Goethe"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [{"de": "Ich freue mich auf das Wochenende.", "it": "Non vedo l'ora che arrivi il weekend."}, {"de": "Das Bild hängt an der Wand.", "it": "Il quadro è appeso alla parete."}], "song1": {"id": "ohHJjPSsW8c", "artist": "Silbermond", "titel": "Leichtes Gepäck"}, "song2": {"id": "Fpu5a0Bl8eY", "artist": "Nena", "titel": "99 Luftballons"}, "articles": [{"title": "Wikipedia: Gef%C3%BChl", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Gef%C3%BChl"}, {"title": "Klexikon: Liebe (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Liebe"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Kommunikation & Konflikte — Comunicare e discutere", "level": "B1", "lesen": {"title": "Ein schwieriges Gespräch", "text": "Gestern Abend hatte ich endlich das Gespräch, vor dem ich mich seit Wochen gefürchtet hatte. Mein bester Freund Tom und ich hatten uns seit einem Streit kaum noch gesehen. Eigentlich ging es nur um eine Kleinigkeit, aber aus einer Mücke wurde schnell ein Elefant. Beide waren wir zu stolz, um den ersten Schritt zu machen. Schließlich habe ich ihn angerufen und vorgeschlagen, etwas trinken zu gehen. Am Anfang war die Stimmung etwas gespannt, doch nach dem zweiten Bier konnten wir ehrlich reden. Ich habe zugegeben, dass ich überreagiert habe, und er hat sich auch entschuldigt. Am Ende haben wir sogar darüber gelacht. Es tut gut zu wissen, dass eine echte Freundschaft auch einen Streit aushält. Manchmal muss man einfach über seinen Schatten springen.", "glos": {"Gespräch": "conversazione", "gefürchtet": "temuto", "Streit": "litigio", "kaum": "a malapena", "Kleinigkeit": "sciocchezza", "stolz": "orgogliosi", "Schritt": "passo", "vorgeschlagen": "proposto", "Stimmung": "atmosfera", "gespannt": "tesa", "ehrlich": "sinceramente", "zugegeben": "ammesso", "überreagiert": "esagerato", "entschuldigt": "scusato", "Freundschaft": "amicizia", "aushält": "regge/sopporta"}, "q": [{"q": "Warum hatten sich die Freunde kaum gesehen?", "o": ["Wegen eines Streits", "Wegen der Arbeit", "Wegen einer Reise"], "c": 0, "e": "„seit einem Streit kaum noch gesehen\"."}, {"q": "Wer hat den ersten Schritt gemacht?", "o": ["Tom", "Der Erzähler", "Niemand"], "c": 1, "e": "„Schließlich habe ich ihn angerufen\"."}, {"q": "Wie endet das Gespräch?", "o": ["Mit einem neuen Streit", "Sie versöhnen sich", "Tom geht weg"], "c": 1, "e": "„Am Ende haben wir sogar darüber gelacht\"."}], "frage": "Wie gehst du mit Streit um? Machst du eher den ersten Schritt oder wartest du?"}, "artikel": {"title": "Freundschaft im digitalen Zeitalter", "text": "Hunderte „Freunde\" in den sozialen Medien — und trotzdem fühlen sich viele Menschen einsam. Studien zeigen, dass echte Freundschaften heute oft schwerer werden. Wir schreiben kurze Nachrichten, liken Fotos und glauben, in Kontakt zu sein. Doch ein Like ersetzt kein echtes Gespräch. Psychologen sagen: Für eine tiefe Freundschaft braucht man Zeit, gemeinsame Erlebnisse und vor allem Vertrauen. Das Internet kann dabei helfen, Kontakte zu halten, besonders über große Entfernungen. Gefährlich wird es nur, wenn die digitale Welt die echte ersetzt. Wer den ganzen Abend allein durch Instagram scrollt, hat danach selten das Gefühl, einem Freund nah gewesen zu sein. Vielleicht lautet die Lösung einfach: öfter anrufen statt nur schreiben.", "glos": {"sozialen Medien": "social media", "einsam": "soli", "Studien": "studi", "Nachrichten": "messaggi", "liken": "mettere like", "ersetzt": "sostituisce", "tiefe": "profonda", "gemeinsame": "comuni", "Erlebnisse": "esperienze", "Vertrauen": "fiducia", "Entfernungen": "distanze", "Gefährlich": "pericoloso", "scrollt": "scorre", "Lösung": "soluzione"}, "q": [{"q": "Was ersetzt ein Like laut Text nicht?", "o": ["Ein Foto", "Ein echtes Gespräch", "Eine Nachricht"], "c": 1, "e": "„Ein Like ersetzt kein echtes Gespräch\"."}, {"q": "Was braucht eine tiefe Freundschaft?", "o": ["Viele Follower", "Zeit und Vertrauen", "Teure Geschenke"], "c": 1, "e": "„Zeit, gemeinsame Erlebnisse und … Vertrauen\"."}], "news": "Freundschaft soziale Medien Einsamkeit"}, "dialog": {"title": "Sich versöhnen", "lines": [{"who": "Lena", "de": "Hey Max, hast du kurz Zeit? Ich muss mit dir reden."}, {"who": "Max", "de": "Klar. Ist alles okay? Du klingst ernst."}, {"who": "Lena", "de": "Es geht um neulich. Ich war ziemlich gemein zu dir. Das tut mir leid."}, {"who": "Max", "de": "Ehrlich gesagt war ich auch verletzt. Aber ich habe auch Fehler gemacht."}, {"who": "Lena", "de": "Ich glaube, wir haben beide übertrieben."}, {"who": "Max", "de": "Stimmt. Lass uns das einfach vergessen, okay?"}, {"who": "Lena", "de": "Gern. Mir ist unsere Freundschaft wirklich wichtig."}, {"who": "Max", "de": "Mir auch. Komm, ich lade dich auf einen Kaffee ein."}, {"who": "Lena", "de": "Abgemacht. Danke, dass du so verständnisvoll bist."}], "q": [{"q": "Warum will Lena reden?", "o": ["Sie braucht Geld", "Sie will sich entschuldigen", "Sie ist krank"], "c": 1, "e": "„Das tut mir leid\" — si scusa."}, {"q": "Wie reagiert Max?", "o": ["Wütend", "Verständnisvoll", "Gleichgültig"], "c": 1, "e": "„Lass uns das einfach vergessen\"."}, {"q": "Was schlägt Max am Ende vor?", "o": ["Einen Kaffee", "Ein Geschenk", "Eine Reise"], "c": 0, "e": "„ich lade dich auf einen Kaffee ein\"."}]}, "musik": {"key": "amk", "task": "„Pocahontas\" degli AnnenMayKantereit ha un testo poetico sulle relazioni e i ricordi. La voce particolare del cantante è una bella sfida. Ascolta e cogli l'emozione, poi prova a leggere il testo.", "level": "B1–B2 · voce intensa"}, "sprechen": {"read": "Ich muss ehrlich mit dir reden. Neulich war ich ziemlich gemein, und das tut mir wirklich leid. Ich glaube, wir haben beide übertrieben. Mir ist unsere Freundschaft sehr wichtig, deshalb möchte ich das klären.", "prompts": [{"q": "Beschreib einen guten Freund. Was macht ihn besonders?", "e": "Mein bester Freund ist …, weil …"}, {"q": "Wie wichtig sind dir soziale Medien für deine Freundschaften?", "e": "Für mich …"}, {"q": "Streitest du oft? Wie löst du Konflikte?", "e": "Wenn ich Streit habe, …"}], "scenario": "Du hast dich mit einem Freund gestritten. Ruf ihn an, entschuldige dich und schlag eine Lösung vor."}, "grammatik": {"titel": "Nebensätze mit „weil\", „dass\", „wenn\" (Verbo alla fine)", "regel_html": "<p>Nelle <b>frasi secondarie</b> introdotte da congiunzioni come <b>weil</b> (perché), <b>dass</b> (che), <b>wenn</b> (se/quando), <b>obwohl</b> (sebbene), il <b>verbo coniugato va alla fine</b>.</p><table class='gtab'><tr><th>congiunzione</th><th>esempio</th></tr><tr><td>weil</td><td>Ich bleibe zu Hause, <b>weil</b> ich krank <b>bin</b>.</td></tr><tr><td>dass</td><td>Ich glaube, <b>dass</b> du recht <b>hast</b>.</td></tr><tr><td>wenn</td><td><b>Wenn</b> es <b>regnet</b>, bleibe ich drinnen.</td></tr><tr><td>obwohl</td><td>Ich gehe raus, <b>obwohl</b> es <b>regnet</b>.</td></tr></table><p>💡 Differenza: <b>weil</b> + verbo alla fine; <b>denn</b> (perché) NON cambia l'ordine: <i>Ich bleibe zu Hause, denn ich <u>bin</u> krank.</i></p>", "ex": [{"l": "Ich lerne Deutsch, weil ich in Berlin arbeiten ", "r": ".", "o": ["möchte", "möchte ich", "will ich", "mag"], "c": 0, "e": "weil → verbo alla fine: <b>möchte</b>."}, {"l": "Ich glaube, dass er heute nicht ", "r": ".", "o": ["kommt", "kommt er", "er kommt", "gekommen"], "c": 0, "e": "dass → verbo alla fine: <b>kommt</b>."}, {"l": "Wenn das Wetter schön ", "r": ", gehen wir spazieren.", "o": ["ist", "ist es", "es ist", "war es"], "c": 0, "e": "wenn → verbo alla fine: <b>ist</b>."}, {"l": "Er arbeitet viel, ", "r": " er müde ist.", "o": ["obwohl", "trotzdem", "deshalb", "denn"], "c": 0, "e": "<b>obwohl</b> + frase secondaria (verbo alla fine)."}]}, "wortschatz": [{"de": "der Streit", "it": "il litigio", "exde": "Wir hatten einen Streit.", "exit": "Abbiamo avuto un litigio."}, {"de": "sich entschuldigen", "it": "scusarsi", "exde": "Ich möchte mich entschuldigen.", "exit": "Vorrei scusarmi."}, {"de": "das Vertrauen", "it": "la fiducia", "exde": "Vertrauen ist wichtig.", "exit": "La fiducia è importante."}, {"de": "die Freundschaft", "it": "l'amicizia", "exde": "Unsere Freundschaft ist stark.", "exit": "La nostra amicizia è forte."}, {"de": "ehrlich", "it": "sincero", "exde": "Sei ehrlich zu mir.", "exit": "Sii sincero con me."}, {"de": "sich fühlen", "it": "sentirsi", "exde": "Ich fühle mich allein.", "exit": "Mi sento solo."}, {"de": "vermissen", "it": "sentire la mancanza", "exde": "Ich vermisse dich.", "exit": "Mi manchi."}, {"de": "sich versöhnen", "it": "riconciliarsi", "exde": "Sie haben sich versöhnt.", "exit": "Si sono riconciliati."}, {"de": "eifersüchtig", "it": "geloso", "exde": "Er ist eifersüchtig.", "exit": "È geloso."}, {"de": "die Beziehung", "it": "la relazione", "exde": "Die Beziehung ist kompliziert.", "exit": "La relazione è complicata."}, {"de": "traurig", "it": "triste", "exde": "Ich bin heute traurig.", "exit": "Oggi sono triste."}, {"de": "stolz", "it": "orgoglioso", "exde": "Ich bin stolz auf dich.", "exit": "Sono orgoglioso di te."}], "idiome": [{"de": "aus einer Mücke einen Elefanten machen", "lit": "Fare di una zanzara un elefante.", "mean": "Esagerare, ingigantire un problema piccolo.", "it": "Fare di una mosca un elefante.", "exde": "Beruhig dich, du machst aus einer Mücke einen Elefanten.", "exit": "Calmati, stai facendo di una mosca un elefante."}, {"de": "über seinen Schatten springen", "lit": "Saltare oltre la propria ombra.", "mean": "Superare i propri limiti, vincere l'orgoglio.", "it": "Fare uno sforzo / vincere se stessi.", "exde": "Entschuldige dich — spring über deinen Schatten.", "exit": "Scusati: vinci il tuo orgoglio."}], "schreiben": {"impuls": "Erzähl von einer Freundschaft, die dir viel bedeutet. Wie habt ihr euch kennengelernt und was verbindet euch?", "fragen": ["Kann man im Internet echte Freunde finden? Begründe deine Meinung.", "Was ist für dich wichtiger in einer Freundschaft: Ehrlichkeit oder Rücksicht? Warum?"]}, "freunde": [{"de": "die Familie", "it": "famiglia / family"}, {"de": "das Hotel", "it": "hotel"}, {"de": "der Computer", "it": "computer"}, {"de": "die Musik", "it": "musica / music"}, {"de": "das Problem", "it": "problema / problem"}, {"de": "die Idee", "it": "idea"}], "falsch": [{"de": "bekommen", "it": "ricevere", "warn": "NON „diventare\" (to become)"}, {"de": "das Gift", "it": "il veleno", "warn": "NON „regalo\" (gift)"}, {"de": "der Chef", "it": "il capo", "warn": "NON il cuoco (= der Koch)"}, {"de": "kalt", "it": "freddo", "warn": "NON „caldo\": è l'opposto!"}, {"de": "die Firma", "it": "la ditta / azienda", "warn": "NON la firma (= die Unterschrift)"}], "lit": {"de": "Es war einmal …", "it": "C'era una volta …", "src": "Brüder Grimm, Märchen"}, "trad": {"id": "gedanken", "title": "Die Gedanken sind frei", "artist": "Volkslied", "note": "Canto popolare sulla libertà di pensiero, amatissimo in Germania.", "ytq": "Die Gedanken sind frei Lied", "de": ["Die Gedanken sind frei,", "wer kann sie erraten?", "Sie fliehen vorbei", "wie nächtliche Schatten.", "Kein Mensch kann sie wissen,", "kein Jäger erschießen;", "es bleibet dabei:", "die Gedanken sind frei!"], "it": ["I pensieri sono liberi,", "chi può indovinarli?", "Volano via", "come ombre nella notte.", "Nessuno può conoscerli,", "nessun cacciatore può abbatterli;", "resta così:", "i pensieri sono liberi!"]}, "voice": {"id": "kRq3WzSwUw0", "t": "Straßeninterviews in Magdeburg", "note": "Ascolto autentico con sottotitoli tedeschi."}, "gram_extra": [{"de": "Sag mir, wenn du fertig bist.", "it": "Dimmi quando hai finito."}, {"de": "Er ist sauer, weil ich zu spät war.", "it": "È arrabbiato perché ero in ritardo."}], "song1": {"id": "1gDbpWC_9pE", "artist": "Sarah Connor", "titel": "Wie schön du bist"}, "song2": {"id": "cIfx8QiNXfs", "artist": "Peter Fox", "titel": "Haus am See"}, "articles": [{"title": "Wikipedia: Kommunikation", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Kommunikation"}, {"title": "Klexikon: Streit (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Streit"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Digitale Welt & Medien — Mondo digitale", "level": "B1", "lesen": {"title": "Mein Leben ohne Handy — ein Experiment", "text": "Eine Woche lang habe ich versucht, mein Smartphone so wenig wie möglich zu benutzen. Die ersten Stunden waren die Hölle. Immer wieder griff meine Hand automatisch zur Tasche, obwohl gar keine Nachricht da war. Ich merkte zum ersten Mal, wie sehr dieses kleine Gerät meinen Alltag bestimmt. Doch nach zwei oder drei Tagen passierte etwas Seltsames: Ich wurde ruhiger. Ich las wieder ein richtiges Buch, beobachtete die Menschen in der U-Bahn und langweilte mich — was gar nicht so schlecht ist. Plötzlich hatte ich abends Zeit, die ich vorher nicht hatte. Natürlich will ich nicht für immer ohne Handy leben; es ist einfach zu praktisch. Aber das Experiment hat mir gezeigt, dass ich der Chef über mein Telefon sein sollte — und nicht umgekehrt.", "glos": {"versucht": "provato", "Smartphone": "smartphone", "Hölle": "inferno", "griff": "afferrava", "Tasche": "tasca", "Nachricht": "messaggio", "merkte": "mi accorsi", "Gerät": "dispositivo", "bestimmt": "determina", "Seltsames": "strano", "ruhiger": "più tranquillo", "beobachtete": "osservavo", "langweilte": "annoiavo", "praktisch": "pratico", "gezeigt": "mostrato", "umgekehrt": "il contrario"}, "q": [{"q": "Wie war der Anfang des Experiments?", "o": ["Leicht", "Sehr schwer", "Langweilig"], "c": 1, "e": "„Die ersten Stunden waren die Hölle\"."}, {"q": "Was passierte nach ein paar Tagen?", "o": ["Er wurde nervöser", "Er wurde ruhiger", "Nichts"], "c": 1, "e": "„Ich wurde ruhiger\"."}, {"q": "Was ist die Lehre des Experiments?", "o": ["Handys sind böse", "Man sollte sein Telefon kontrollieren", "Bücher sind langweilig"], "c": 1, "e": "„ich der Chef über mein Telefon sein sollte\"."}], "frage": "Wie viel Zeit verbringst du am Handy? Könntest du eine Woche darauf verzichten?"}, "artikel": {"title": "Künstliche Intelligenz im Alltag", "text": "Vor wenigen Jahren klang künstliche Intelligenz noch nach Science-Fiction. Heute ist sie längst Teil unseres Alltags. KI schlägt uns Serien vor, übersetzt Texte in Sekunden und hilft sogar Ärzten bei der Diagnose. Für viele ist das eine große Chance: Programme können langweilige Aufgaben übernehmen, sodass mehr Zeit für kreative Arbeit bleibt. Doch es gibt auch Sorgen. Manche Menschen haben Angst, ihren Job zu verlieren. Andere fragen sich, ob wir den Maschinen zu sehr vertrauen. Wer kontrolliert die Daten? Wer trägt die Verantwortung, wenn ein Computer einen Fehler macht? Experten sind sich einig: KI ist weder gut noch böse. Entscheidend ist, wie wir Menschen sie nutzen — und welche Regeln wir ihr geben.", "glos": {"künstliche Intelligenz": "intelligenza artificiale", "klang": "suonava", "übersetzt": "traduce", "Diagnose": "diagnosi", "Chance": "opportunità", "Aufgaben": "compiti", "übernehmen": "assumere/svolgere", "Sorgen": "preoccupazioni", "verlieren": "perdere", "vertrauen": "fidarsi", "Daten": "dati", "Verantwortung": "responsabilità", "einig": "d'accordo", "Entscheidend": "decisivo", "Regeln": "regole"}, "q": [{"q": "Was kann KI laut Text tun?", "o": ["Nur spielen", "Texte übersetzen und bei Diagnosen helfen", "Nichts Nützliches"], "c": 1, "e": "„übersetzt Texte … hilft … bei der Diagnose\"."}, {"q": "Was sagen die Experten über KI?", "o": ["Sie ist böse", "Sie ist weder gut noch böse", "Sie ist nutzlos"], "c": 1, "e": "„KI ist weder gut noch böse\"."}], "news": "künstliche Intelligenz Alltag"}, "dialog": {"title": "Diskussion über Bildschirmzeit", "lines": [{"who": "Vater", "de": "Tim, du sitzt schon den ganzen Nachmittag am Computer."}, {"who": "Tim", "de": "Ich mache doch nur kurz meine Hausaufgaben fertig."}, {"who": "Vater", "de": "Hausaufgaben? Du spielst doch ein Spiel."}, {"who": "Tim", "de": "Nur eine Pause! Alle meine Freunde spielen das."}, {"who": "Vater", "de": "Das verstehe ich, aber zu viel Bildschirm tut nicht gut."}, {"who": "Tim", "de": "Aber im Internet lerne ich auch viel, Papa."}, {"who": "Vater", "de": "Das stimmt. Es geht mir nur um die Balance."}, {"who": "Tim", "de": "Okay. Was schlägst du vor?"}, {"who": "Vater", "de": "Zwei Stunden am Tag für Spiele. Den Rest für andere Dinge."}, {"who": "Tim", "de": "Einverstanden. Aber am Wochenende ein bisschen mehr, oder?"}], "q": [{"q": "Was macht Tim wirklich am Computer?", "o": ["Hausaufgaben", "Ein Spiel spielen", "Lesen"], "c": 1, "e": "„Du spielst doch ein Spiel\"."}, {"q": "Worum geht es dem Vater?", "o": ["Ums Verbot", "Um die Balance", "Ums Geld"], "c": 1, "e": "„Es geht mir nur um die Balance\"."}, {"q": "Was vereinbaren sie?", "o": ["Kein Computer mehr", "Zwei Stunden am Tag", "Unbegrenzt"], "c": 1, "e": "„Zwei Stunden am Tag für Spiele\"."}]}, "musik": {"key": "helden", "task": "„Nur ein Wort\" parla del desiderio di comunicare davvero, oltre i messaggi superficiali — tema perfetto per il mondo digitale. Ascolta e rifletti: quante volte comunichiamo senza dire nulla?", "level": "A2–B1"}, "sprechen": {"read": "Ich glaube, künstliche Intelligenz bringt große Chancen, aber auch Risiken. Einerseits spart sie Zeit und hilft uns im Alltag. Andererseits haben viele Menschen Angst um ihre Arbeit. Entscheidend ist, welche Regeln wir der Technik geben.", "prompts": [{"q": "Wie viel Zeit verbringst du täglich online?", "e": "Ich bin etwa … Stunden online, vor allem für …"}, {"q": "Ist künstliche Intelligenz eher Chance oder Gefahr? Warum?", "e": "Ich denke, KI ist eher …, weil …"}, {"q": "Könntest du eine Woche ohne Internet leben?", "e": "Ja/Nein, weil …"}], "scenario": "Ein Freund verbringt zu viel Zeit am Handy. Sprich ihn vorsichtig darauf an und gib einen Rat."}, "grammatik": {"titel": "Komparativ und Superlativ (comparativi e superlativi)", "regel_html": "<p>Per confrontare si usano <b>comparativo</b> (-er + als) e <b>superlativo</b> (am …-sten).</p><table class='gtab'><tr><th>base</th><th>comparativo</th><th>superlativo</th></tr><tr><td>schnell</td><td>schneller</td><td>am schnellsten</td></tr><tr><td>schön</td><td>schöner</td><td>am schönsten</td></tr><tr><td>gut (irreg.)</td><td>besser</td><td>am besten</td></tr><tr><td>viel (irreg.)</td><td>mehr</td><td>am meisten</td></tr><tr><td>gern (irreg.)</td><td>lieber</td><td>am liebsten</td></tr></table><p><b>Esempi:</b> <i>Mein Handy ist <u>schneller als</u> deins.</i> · <i>Sie spricht <u>besser</u> Deutsch <u>als</u> ich.</i> · <i>Das ist <u>am besten</u>.</i></p><p>💡 „als\" si usa nel comparativo (più di), „wie\" nell'uguaglianza: <i>so groß <u>wie</u> du</i>.</p>", "ex": [{"l": "Mein Computer ist ", "r": " als deiner.", "o": ["schnell", "schneller", "am schnellsten", "schnellsten"], "c": 1, "e": "comparativo: <b>schneller als</b>."}, {"l": "Sie spricht ", "r": " Deutsch als ich.", "o": ["gut", "besser", "am besten", "gern"], "c": 1, "e": "gut → <b>besser</b> (irregolare)."}, {"l": "Das Internet hier ist am ", "r": ".", "o": ["schnell", "schneller", "schnellsten", "schnellste"], "c": 2, "e": "superlativo: <b>am schnellsten</b>."}, {"l": "Ich trinke ", "r": " Tee als Kaffee.", "o": ["gern", "lieber", "am liebsten", "gut"], "c": 1, "e": "gern → <b>lieber</b> (preferisco)."}]}, "wortschatz": [{"de": "das Handy", "it": "il cellulare", "exde": "Mein Handy ist kaputt.", "exit": "Il mio cellulare è rotto."}, {"de": "der Bildschirm", "it": "lo schermo", "exde": "Der Bildschirm ist groß.", "exit": "Lo schermo è grande."}, {"de": "die Nachricht", "it": "il messaggio", "exde": "Ich schicke dir eine Nachricht.", "exit": "Ti mando un messaggio."}, {"de": "das Internet", "it": "internet", "exde": "Das Internet ist langsam.", "exit": "Internet è lento."}, {"de": "herunterladen", "it": "scaricare", "exde": "Ich lade die App herunter.", "exit": "Scarico l'app."}, {"de": "speichern", "it": "salvare", "exde": "Speichere die Datei.", "exit": "Salva il file."}, {"de": "die Daten", "it": "i dati", "exde": "Schütze deine Daten.", "exit": "Proteggi i tuoi dati."}, {"de": "künstliche Intelligenz", "it": "intelligenza artificiale", "exde": "KI verändert die Welt.", "exit": "L'IA cambia il mondo."}, {"de": "die Sorge", "it": "la preoccupazione", "exde": "Ich habe Sorgen.", "exit": "Ho preoccupazioni."}, {"de": "vertrauen", "it": "fidarsi", "exde": "Ich vertraue der Technik nicht.", "exit": "Non mi fido della tecnologia."}, {"de": "praktisch", "it": "pratico", "exde": "Das ist sehr praktisch.", "exit": "È molto pratico."}, {"de": "die Gefahr", "it": "il pericolo", "exde": "Es gibt auch Gefahren.", "exit": "Ci sono anche pericoli."}], "idiome": [{"de": "auf dem neuesten Stand sein", "lit": "Essere all'ultimo stato.", "mean": "Essere aggiornato.", "it": "Essere al passo / aggiornato.", "exde": "Mit dieser App bist du auf dem neuesten Stand.", "exit": "Con quest'app sei aggiornato."}, {"de": "den Stecker ziehen", "lit": "Staccare la spina.", "mean": "Spegnere tutto, fare una pausa dalla tecnologia.", "it": "Staccare la spina.", "exde": "Ich ziehe am Wochenende den Stecker.", "exit": "Nel weekend stacco la spina."}], "schreiben": {"impuls": "Beschreib einen Tag in deinem digitalen Leben: Welche Apps und Geräte benutzt du, und wofür?", "fragen": ["Macht uns die Technik freier oder abhängiger? Was meinst du?", "Welche Regeln würdest du Kindern für das Smartphone geben?"]}, "freunde": [{"de": "das Problem", "it": "problema / problem"}, {"de": "die Idee", "it": "idea"}, {"de": "der Moment", "it": "momento"}, {"de": "die Natur", "it": "natura / nature"}, {"de": "die Information", "it": "informazione"}, {"de": "die Situation", "it": "situazione"}], "falsch": [{"de": "kalt", "it": "freddo", "warn": "NON „caldo\": è l'opposto!"}, {"de": "die Firma", "it": "la ditta / azienda", "warn": "NON la firma (= die Unterschrift)"}, {"de": "das Regal", "it": "lo scaffale", "warn": "NON il regalo (= das Geschenk)"}, {"de": "eventuell", "it": "forse / se necessario", "warn": "NON „eventually\" (= schließlich)"}, {"de": "das Handy", "it": "il cellulare", "warn": "NON „handy / pratico\""}], "lit": {"de": "Mut verloren – alles verloren.", "it": "Perso il coraggio, perso tutto.", "src": "J. W. Goethe"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Berlin ist größer als Rom.", "it": "Berlino è più grande di Roma."}, {"de": "Das ist das beste Restaurant der Stadt.", "it": "È il miglior ristorante della città."}], "song1": {"id": "AvYwpEDfOWk", "artist": "Howard Carpendale & Stereoact", "titel": "Ti Amo (Remix)", "original": "Versione moderna di „Ti amo\" (Umberto Tozzi)."}, "song2": {"id": "HeW9ZmB3-_g", "artist": "Howard Carpendale", "titel": "Ti Amo", "original": "Cover di „Ti amo\" di Umberto Tozzi (1977)."}, "articles": [{"title": "Wikipedia: Soziale_Medien", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Soziale_Medien"}, {"title": "Klexikon: Internet (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Internet"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Arbeitswelt der Zukunft — Il mondo del lavoro di domani", "level": "B2", "lesen": {"title": "Wenn das Büro überall ist", "text": "Noch vor wenigen Jahren war klar: Arbeiten bedeutet, morgens ins Büro zu fahren und abends wieder nach Hause. Heute sieht das für viele anders aus. Seit der Pandemie ist das Homeoffice für Millionen Menschen zur Normalität geworden. Was zunächst wie eine Notlösung wirkte, hat unsere Vorstellung von Arbeit grundlegend verändert. Die Vorteile liegen auf der Hand: kein langer Arbeitsweg, mehr Flexibilität, eine bessere Vereinbarkeit von Beruf und Familie. Doch es gibt auch eine Kehrseite. Wer ständig zu Hause arbeitet, dem fehlt oft der persönliche Kontakt zu den Kollegen. Die Grenze zwischen Arbeit und Freizeit verschwimmt, und nicht selten arbeiten Menschen im Homeoffice sogar mehr als vorher. Wahrscheinlich liegt die Zukunft, wie so oft, in der Mitte: in einem hybriden Modell, das das Beste aus beiden Welten verbindet. Entscheidend wird sein, dass nicht die Technik über den Menschen bestimmt, sondern der Mensch über die Technik.", "glos": {"bedeutet": "significa", "Pandemie": "pandemia", "Homeoffice": "lavoro da casa", "Notlösung": "soluzione di ripiego", "wirkte": "sembrava", "Vorstellung": "idea", "grundlegend": "radicalmente", "Arbeitsweg": "tragitto", "Vereinbarkeit": "conciliabilità", "Kehrseite": "rovescio della medaglia", "fehlt": "manca", "Grenze": "confine", "verschwimmt": "si sfuma", "hybriden": "ibrido", "verbindet": "unisce", "Entscheidend": "decisivo", "bestimmt": "decide"}, "q": [{"q": "Was ist seit der Pandemie zur Normalität geworden?", "o": ["Das Büro", "Das Homeoffice", "Die Vier-Tage-Woche"], "c": 1, "e": "„ist das Homeoffice … zur Normalität geworden\"."}, {"q": "Was ist eine Kehrseite des Homeoffice?", "o": ["Mehr Gehalt", "Fehlender Kontakt zu Kollegen", "Kürzere Arbeitszeit"], "c": 1, "e": "„fehlt oft der persönliche Kontakt zu den Kollegen\"."}, {"q": "Wo liegt laut Text wahrscheinlich die Zukunft?", "o": ["Nur im Büro", "Nur zu Hause", "In einem hybriden Modell"], "c": 2, "e": "„in einem hybriden Modell\"."}], "frage": "Würdest du lieber im Büro, zu Hause oder hybrid arbeiten? Begründe deine Wahl ausführlich."}, "artikel": {"title": "Welche Berufe verschwinden — und welche entstehen?", "text": "Die Angst ist alt: Schon zu Beginn der Industrialisierung fürchteten die Menschen, dass Maschinen ihnen die Arbeit wegnehmen. Tatsächlich sind seither unzählige Berufe verschwunden — doch gleichzeitig sind viele neue entstanden, die sich früher niemand vorstellen konnte. Heute steht die Arbeitswelt durch Digitalisierung und künstliche Intelligenz erneut vor einem tiefen Wandel. Routinetätigkeiten, die nach festen Regeln ablaufen, lassen sich zunehmend automatisieren. Kassiererinnen, Buchhalter oder Sachbearbeiter spüren das bereits. Auf der anderen Seite wächst der Bedarf an Berufen, in denen es auf Kreativität, Empathie und kritisches Denken ankommt — Fähigkeiten, die Maschinen nur schwer ersetzen können. Pflege, Bildung und Forschung gehören dazu. Fest steht: Wer flexibel bleibt und bereit ist, sich weiterzubilden, muss die Zukunft nicht fürchten. Die wichtigste Kompetenz von morgen ist die Fähigkeit, immer wieder Neues zu lernen.", "glos": {"fürchteten": "temevano", "wegnehmen": "togliere", "unzählige": "innumerevoli", "verschwunden": "spariti", "entstanden": "nati", "Wandel": "trasformazione", "Routinetätigkeiten": "attività ripetitive", "ablaufen": "si svolgono", "automatisieren": "automatizzare", "Buchhalter": "contabili", "Sachbearbeiter": "impiegati", "Bedarf": "bisogno/domanda", "Empathie": "empatia", "ersetzen": "sostituire", "Pflege": "assistenza", "Forschung": "ricerca", "weiterzubilden": "aggiornarsi"}, "q": [{"q": "Welche Tätigkeiten lassen sich leicht automatisieren?", "o": ["Kreative", "Routinetätigkeiten", "Soziale"], "c": 1, "e": "„Routinetätigkeiten, die nach festen Regeln ablaufen\"."}, {"q": "Welche Berufe wachsen laut Text?", "o": ["Solche mit Kreativität und Empathie", "Nur technische", "Gar keine"], "c": 0, "e": "„Kreativität, Empathie und kritisches Denken\"."}], "news": "Zukunft der Arbeit Automatisierung Berufe"}, "dialog": {"title": "Ein Bewerbungsgespräch", "lines": [{"who": "Personalerin", "de": "Schön, dass Sie da sind. Erzählen Sie doch ein wenig von sich."}, {"who": "Bewerber", "de": "Gern. Ich habe fünf Jahre als Projektmanager gearbeitet und suche eine neue Herausforderung."}, {"who": "Personalerin", "de": "Was reizt Sie an dieser Stelle besonders?"}, {"who": "Bewerber", "de": "Vor allem die Möglichkeit, ein Team eigenverantwortlich zu leiten."}, {"who": "Personalerin", "de": "Wo sehen Sie Ihre größten Stärken?"}, {"who": "Bewerber", "de": "Ich bin gut organisiert und bleibe auch unter Druck ruhig."}, {"who": "Personalerin", "de": "Und eine Schwäche?"}, {"who": "Bewerber", "de": "Ich bin manchmal zu perfektionistisch, daran arbeite ich aber."}, {"who": "Personalerin", "de": "Haben Sie noch Fragen an uns?"}, {"who": "Bewerber", "de": "Ja, wie sieht die Einarbeitung in den ersten Wochen aus?"}], "q": [{"q": "Was sucht der Bewerber?", "o": ["Mehr Geld", "Eine neue Herausforderung", "Weniger Arbeit"], "c": 1, "e": "„suche eine neue Herausforderung\"."}, {"q": "Was nennt er als Stärke?", "o": ["Er ist kreativ", "Er bleibt unter Druck ruhig", "Er ist schnell"], "c": 1, "e": "„bleibe auch unter Druck ruhig\"."}, {"q": "Welche Frage stellt er am Ende?", "o": ["Nach dem Gehalt", "Nach der Einarbeitung", "Nach dem Urlaub"], "c": 1, "e": "„wie sieht die Einarbeitung … aus?\""}]}, "musik": {"key": "bourani", "task": "Riascolta „Auf uns\" come inno motivazionale prima di una sfida (un colloquio, un esame). Nota come la musica può cambiare lo stato d'animo. Concentrati sul messaggio positivo del testo.", "level": "A2–B1 · motivante"}, "sprechen": {"read": "In den letzten Jahren hat sich die Arbeitswelt stark verändert. Viele Menschen arbeiten heute teilweise von zu Hause. Das bringt mehr Flexibilität, aber auch neue Herausforderungen, zum Beispiel die Trennung von Arbeit und Freizeit. Ich glaube, ein hybrides Modell ist die beste Lösung.", "prompts": [{"q": "Wie stellst du dir deinen idealen Job vor?", "e": "Mein idealer Job wäre …, weil …"}, {"q": "Welche Fähigkeiten sind in Zukunft am wichtigsten?", "e": "Am wichtigsten werden … sein, weil …"}, {"q": "Hast du Angst, dass Maschinen deinen Beruf ersetzen? Begründe.", "e": "Ich habe (keine) Angst, weil …"}], "scenario": "Du bist im Bewerbungsgespräch. Stell dich vor und nenne zwei Stärken und eine Schwäche."}, "grammatik": {"titel": "Das Passiv (la forma passiva)", "regel_html": "<p>Il <b>passivo</b> mette in primo piano l'azione, non chi la compie. Si forma con <b>werden</b> + <b>participio</b>.</p><table class='gtab'><tr><th>tempo</th><th>esempio</th></tr><tr><td>Präsens</td><td>Das Auto <b>wird</b> repariert. (viene riparata)</td></tr><tr><td>Präteritum</td><td>Das Haus <b>wurde</b> 1990 gebaut.</td></tr><tr><td>Perfekt</td><td>Der Brief <b>ist</b> geschrieben <b>worden</b>.</td></tr></table><p>Chi compie l'azione si introduce con <b>von</b> (+ Dativo): <i>Der Text <u>wird</u> von der KI <u>geschrieben</u>.</i></p><p>💡 Attenzione: nel Perfekt passivo il participio di werden è <b>worden</b> (non „geworden\").</p>", "ex": [{"l": "Das Auto ", "r": " gerade repariert.", "o": ["wird", "ist", "hat", "wurde"], "c": 0, "e": "Passivo presente: <b>wird</b> + participio."}, {"l": "Das Haus ", "r": " 1990 gebaut.", "o": ["wird", "wurde", "hat", "ist"], "c": 1, "e": "Passivo al Präteritum: <b>wurde</b> gebaut."}, {"l": "Der Brief ist gestern geschrieben ", "r": ".", "o": ["worden", "geworden", "werden", "wurde"], "c": 0, "e": "Perfekt passivo: … geschrieben <b>worden</b>."}, {"l": "Der Text wird ", "r": " der KI geschrieben.", "o": ["von", "mit", "aus", "bei"], "c": 0, "e": "agente con <b>von</b> + Dativo."}]}, "wortschatz": [{"de": "die Arbeitswelt", "it": "il mondo del lavoro", "exde": "Die Arbeitswelt verändert sich.", "exit": "Il mondo del lavoro cambia."}, {"de": "das Homeoffice", "it": "il lavoro da casa", "exde": "Ich bin im Homeoffice.", "exit": "Lavoro da casa."}, {"de": "die Herausforderung", "it": "la sfida", "exde": "Das ist eine große Herausforderung.", "exit": "È una grande sfida."}, {"de": "die Bewerbung", "it": "la candidatura", "exde": "Ich schreibe eine Bewerbung.", "exit": "Scrivo una candidatura."}, {"de": "die Stärke", "it": "il punto di forza", "exde": "Meine Stärke ist Geduld.", "exit": "Il mio punto di forza è la pazienza."}, {"de": "die Schwäche", "it": "la debolezza", "exde": "Jeder hat Schwächen.", "exit": "Tutti hanno debolezze."}, {"de": "sich weiterbilden", "it": "aggiornarsi", "exde": "Ich bilde mich weiter.", "exit": "Mi aggiorno professionalmente."}, {"de": "ersetzen", "it": "sostituire", "exde": "Maschinen ersetzen Menschen.", "exit": "Le macchine sostituiscono le persone."}, {"de": "flexibel", "it": "flessibile", "exde": "Ich bin sehr flexibel.", "exit": "Sono molto flessibile."}, {"de": "der Druck", "it": "la pressione", "exde": "Ich arbeite gut unter Druck.", "exit": "Lavoro bene sotto pressione."}, {"de": "eigenverantwortlich", "it": "in autonomia", "exde": "Ich arbeite eigenverantwortlich.", "exit": "Lavoro in autonomia."}, {"de": "verschwinden", "it": "sparire", "exde": "Viele Berufe verschwinden.", "exit": "Molte professioni spariscono."}], "idiome": [{"de": "die Ärmel hochkrempeln", "lit": "Rimboccarsi le maniche.", "mean": "Mettersi al lavoro con energia e decisione.", "it": "Rimboccarsi le maniche.", "exde": "Jetzt heißt es Ärmel hochkrempeln!", "exit": "Adesso bisogna rimboccarsi le maniche!"}, {"de": "ins kalte Wasser springen", "lit": "Saltare nell'acqua fredda.", "mean": "Affrontare qualcosa di nuovo senza preparazione.", "it": "Buttarsi senza rete.", "exde": "Beim neuen Job musste ich ins kalte Wasser springen.", "exit": "Nel nuovo lavoro mi sono dovuto buttare."}], "schreiben": {"impuls": "Schreib einen kurzen Bewerbungstext (5–7 Sätze): Wer bist du, was kannst du, warum bist du der/die Richtige?", "fragen": ["Sollte der Staat ein Grundeinkommen einführen, wenn Maschinen viele Jobs übernehmen? Diskutiere.", "Was bedeutet für dich ‚guter Arbeitsplatz' — Geld, Sinn, Sicherheit oder Freiheit?"]}, "freunde": [{"de": "die Information", "it": "informazione"}, {"de": "die Situation", "it": "situazione"}, {"de": "das Telefon", "it": "telefono"}, {"de": "die Universität", "it": "università"}, {"de": "der Tourist", "it": "turista"}, {"de": "das Restaurant", "it": "ristorante"}], "falsch": [{"de": "eventuell", "it": "forse / se necessario", "warn": "NON „eventually\" (= schließlich)"}, {"de": "das Handy", "it": "il cellulare", "warn": "NON „handy / pratico\""}, {"de": "die Kantine", "it": "la mensa", "warn": "NON la cantina (= der Keller)"}, {"de": "die Note", "it": "il voto / la nota musicale", "warn": "NON la notte (= die Nacht)"}, {"de": "die Art", "it": "il tipo / il modo", "warn": "NON l'arte (= die Kunst)"}], "lit": {"de": "Der Worte sind genug gewechselt, lasst mich auch endlich Taten sehn!", "it": "Basta con le parole: fatemi vedere finalmente i fatti!", "src": "J. W. Goethe, Faust"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [{"de": "Das Haus wird gerade renoviert.", "it": "La casa viene ristrutturata proprio ora."}, {"de": "Die E-Mail wurde gestern geschickt.", "it": "L'email è stata inviata ieri."}], "song1": {"id": "qkrrqTEH_zg", "artist": "Sarah Connor", "titel": "Vincent"}, "song2": {"id": "DraA3PUuoQc", "artist": "AnnenMayKantereit", "titel": "Pocahontas"}, "articles": [{"title": "Wikipedia: Arbeitswelt", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Arbeitswelt"}, {"title": "Klexikon: K%C3%BCnstliche_Intelligenz (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/K%C3%BCnstliche_Intelligenz"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Migration & Integration — Migrazione e integrazione", "level": "B2", "lesen": {"title": "Zwischen zwei Welten", "text": "Als ich vor zehn Jahren nach Deutschland kam, hatte ich zwei Koffer und ungefähr fünfzig deutsche Wörter im Kopf. Die ersten Monate waren hart. Ich verstand kaum etwas, fühlte mich fremd und vermisste meine Familie sehr. Besonders schwierig war das Gefühl, plötzlich niemand mehr zu sein: In meiner Heimat war ich Lehrerin gewesen, hier konnte ich nicht einmal beim Bäcker richtig bestellen. Mit der Zeit wurde es besser. Ich besuchte einen Sprachkurs, fand Arbeit und lernte Menschen kennen, die mir halfen. Heute fühle ich mich in Deutschland zu Hause — und trotzdem bleibe ich auch ein Stück weit fremd. Das ist das Besondere am Leben zwischen zwei Kulturen: Man gehört nirgendwo ganz dazu, aber man gewinnt auch eine doppelte Heimat. Ich habe gelernt, dass Integration keine Einbahnstraße ist. Sie verlangt Offenheit — von beiden Seiten. Und vor allem verlangt sie Geduld.", "glos": {"Koffer": "valigie", "fremd": "estraneo", "vermisste": "sentivo la mancanza", "plötzlich": "all'improvviso", "Heimat": "patria", "Sprachkurs": "corso di lingua", "kennenlernen": "conoscere", "halfen": "aiutarono", "Kulturen": "culture", "nirgendwo": "da nessuna parte", "doppelte": "doppia", "Integration": "integrazione", "Einbahnstraße": "strada a senso unico", "verlangt": "richiede", "Offenheit": "apertura", "Geduld": "pazienza"}, "q": [{"q": "Was war am Anfang besonders schwierig?", "o": ["Das Wetter", "Das Gefühl, niemand mehr zu sein", "Das Essen"], "c": 1, "e": "„das Gefühl, plötzlich niemand mehr zu sein\"."}, {"q": "Was half der Person, sich einzuleben?", "o": ["Nichts", "Sprachkurs, Arbeit und hilfsbereite Menschen", "Nur Geld"], "c": 1, "e": "„besuchte einen Sprachkurs, fand Arbeit …\"."}, {"q": "Wie beschreibt sie Integration?", "o": ["Als Einbahnstraße", "Sie verlangt Offenheit von beiden Seiten", "Als unmöglich"], "c": 1, "e": "„Integration … verlangt Offenheit von beiden Seiten\"."}], "frage": "Hast du schon einmal in einem fremden Land gelebt oder dich fremd gefühlt? Erzähl davon."}, "artikel": {"title": "Was eine Sprache mit Heimat zu tun hat", "text": "Wer in ein neues Land kommt, merkt schnell: Ohne die Sprache bleibt vieles verschlossen. Die Sprache ist der Schlüssel zu allem — zur Arbeit, zu Freundschaften, zur Kultur und zum Verständnis dafür, wie die Menschen denken. Doch eine neue Sprache zu lernen, ist mehr als Vokabeln zu pauken. Man muss seine Angst überwinden, Fehler zu machen, und akzeptieren, dass man am Anfang wie ein Kind klingt. Genau das empfinden viele Erwachsene als demütigend. Dabei ist gerade der Mut, trotzdem zu sprechen, der wichtigste Schritt. Sprachwissenschaftler betonen außerdem etwas Erstaunliches: Wer eine Sprache wirklich lernt, übernimmt oft auch ein Stück der dazugehörigen Denkweise. Manche sagen sogar, sie fühlten sich in einer anderen Sprache wie ein leicht anderer Mensch. Eine Sprache zu lernen heißt also nicht nur, neue Wörter zu kennen, sondern die Welt mit anderen Augen zu sehen.", "glos": {"verschlossen": "chiuso", "Schlüssel": "chiave", "Verständnis": "comprensione", "überwinden": "superare", "akzeptieren": "accettare", "klingt": "suona", "empfinden": "percepiscono", "demütigend": "umiliante", "Mut": "coraggio", "Schritt": "passo", "Sprachwissenschaftler": "linguisti", "Erstaunliches": "sorprendente", "übernimmt": "assume", "Denkweise": "modo di pensare", "Augen": "occhi"}, "q": [{"q": "Was ist die Sprache laut Text?", "o": ["Ein Hindernis", "Der Schlüssel zu allem", "Unwichtig"], "c": 1, "e": "„Die Sprache ist der Schlüssel zu allem\"."}, {"q": "Was ist der wichtigste Schritt?", "o": ["Perfekt sprechen", "Der Mut, trotzdem zu sprechen", "Nie Fehler machen"], "c": 1, "e": "„der Mut, trotzdem zu sprechen\"."}], "news": "Sprache lernen Integration Identität"}, "dialog": {"title": "Auf dem Amt", "lines": [{"who": "Beamtin", "de": "Guten Tag. Was kann ich für Sie tun?"}, {"who": "Herr Ali", "de": "Guten Tag. Ich möchte meinen Wohnsitz anmelden."}, {"who": "Beamtin", "de": "Haben Sie Ihren Pass und den Mietvertrag dabei?"}, {"who": "Herr Ali", "de": "Ja, hier bitte. Entschuldigung, mein Deutsch ist noch nicht so gut."}, {"who": "Beamtin", "de": "Kein Problem, ich spreche langsam. Seit wann wohnen Sie hier?"}, {"who": "Herr Ali", "de": "Seit dem ersten März."}, {"who": "Beamtin", "de": "Gut. Bitte füllen Sie dieses Formular aus und unterschreiben Sie hier."}, {"who": "Herr Ali", "de": "Welches Feld muss ich hier ausfüllen?"}, {"who": "Beamtin", "de": "Hier Ihren Namen, dort die Adresse. Ich helfe Ihnen gern."}, {"who": "Herr Ali", "de": "Vielen Dank, das ist sehr nett von Ihnen."}], "q": [{"q": "Was möchte Herr Ali machen?", "o": ["Einen Pass beantragen", "Seinen Wohnsitz anmelden", "Geld abheben"], "c": 1, "e": "„meinen Wohnsitz anmelden\"."}, {"q": "Was muss er mitbringen?", "o": ["Nur Geld", "Pass und Mietvertrag", "Ein Foto"], "c": 1, "e": "„Ihren Pass und den Mietvertrag\"."}, {"q": "Wie reagiert die Beamtin auf sein Deutsch?", "o": ["Sie ärgert sich", "Sie spricht langsam und hilft", "Sie schickt ihn weg"], "c": 1, "e": "„ich spreche langsam … Ich helfe Ihnen gern\"."}]}, "musik": {"key": "fox", "task": "„Haus am See\" parla del desiderio di un posto in cui sentirsi a casa. Collega il tema al concetto di „Heimat\" (patria/casa). Ascolta e rifletti su cosa significa „casa\" per te.", "level": "B1 · tematico"}, "sprechen": {"read": "Eine neue Sprache zu lernen bedeutet mehr, als nur Vokabeln zu pauken. Man muss den Mut haben, Fehler zu machen und trotzdem zu sprechen. Für mich ist die Sprache der Schlüssel, um eine andere Kultur und eine andere Art zu denken wirklich zu verstehen.", "prompts": [{"q": "Was bedeutet ‚Heimat' für dich?", "e": "Heimat bedeutet für mich …"}, {"q": "Was ist die größte Hürde beim Sprachenlernen?", "e": "Die größte Hürde ist …, weil …"}, {"q": "Wie kann eine Gesellschaft Neuankömmlinge besser integrieren?", "e": "Eine Gesellschaft sollte …"}], "scenario": "Du bist neu in einer Stadt und meldest dich auf dem Amt an. Erklär dein Anliegen höflich."}, "grammatik": {"titel": "Konnektoren: deshalb, trotzdem, deswegen, dennoch", "regel_html": "<p>I <b>connettori</b> collegano frasi e mostrano la relazione logica. Attenzione: alcuni occupano la 1ª posizione e fanno seguire il <b>verbo</b> (inversione).</p><table class='gtab'><tr><th>connettore</th><th>significato</th><th>esempio</th></tr><tr><td>deshalb / deswegen</td><td>perciò</td><td>Es regnet, <b>deshalb</b> bleibe ich zu Hause.</td></tr><tr><td>trotzdem / dennoch</td><td>nonostante ciò</td><td>Es regnet, <b>trotzdem</b> gehe ich raus.</td></tr><tr><td>außerdem</td><td>inoltre</td><td>Es ist teuer, <b>außerdem</b> ist es weit.</td></tr></table><p>💡 Dopo questi connettori in posizione 1, il verbo viene <b>subito dopo</b>: <i>Deshalb <u>bleibe</u> ich zu Hause.</i> (≠ weil/dass, che mandano il verbo alla fine).</p>", "ex": [{"l": "Es regnet, ", "r": " bleibe ich zu Hause.", "o": ["deshalb", "weil", "dass", "obwohl"], "c": 0, "e": "perciò + inversione: <b>deshalb bleibe</b> ich."}, {"l": "Es ist kalt, trotzdem ", "r": " wir spazieren.", "o": ["gehen", "gehen wir nicht", "wir gehen", "zu gehen"], "c": 0, "e": "trotzdem + verbo subito: <b>gehen wir</b>."}, {"l": "Ich war müde, ", "r": " habe ich weitergearbeitet.", "o": ["dennoch", "weil", "damit", "dass"], "c": 0, "e": "nonostante ciò: <b>dennoch</b> + inversione."}, {"l": "Das Hotel ist teuer, ", "r": " ist es weit weg.", "o": ["außerdem", "obwohl", "weil", "wenn"], "c": 0, "e": "inoltre: <b>außerdem</b> + inversione."}]}, "wortschatz": [{"de": "die Heimat", "it": "la patria", "exde": "Ich vermisse meine Heimat.", "exit": "Sento la mancanza della mia patria."}, {"de": "fremd", "it": "estraneo", "exde": "Am Anfang war alles fremd.", "exit": "All'inizio era tutto estraneo."}, {"de": "die Integration", "it": "l'integrazione", "exde": "Integration braucht Zeit.", "exit": "L'integrazione richiede tempo."}, {"de": "der Ausländer", "it": "lo straniero", "exde": "Er ist Ausländer.", "exit": "È straniero."}, {"de": "die Kultur", "it": "la cultura", "exde": "Ich liebe diese Kultur.", "exit": "Amo questa cultura."}, {"de": "der Sprachkurs", "it": "il corso di lingua", "exde": "Ich besuche einen Sprachkurs.", "exit": "Frequento un corso di lingua."}, {"de": "sich einleben", "it": "ambientarsi", "exde": "Ich habe mich gut eingelebt.", "exit": "Mi sono ambientato bene."}, {"de": "der Wohnsitz", "it": "la residenza", "exde": "Ich melde meinen Wohnsitz an.", "exit": "Registro la mia residenza."}, {"de": "das Amt", "it": "l'ufficio (pubblico)", "exde": "Ich gehe zum Amt.", "exit": "Vado all'ufficio."}, {"de": "der Mut", "it": "il coraggio", "exde": "Hab Mut!", "exit": "Abbi coraggio!"}, {"de": "überwinden", "it": "superare", "exde": "Ich überwinde meine Angst.", "exit": "Supero la mia paura."}, {"de": "die Offenheit", "it": "l'apertura", "exde": "Offenheit ist wichtig.", "exit": "L'apertura è importante."}], "idiome": [{"de": "sich wie zu Hause fühlen", "lit": "Sentirsi come a casa.", "mean": "Sentirsi a proprio agio, accolti.", "it": "Sentirsi a casa.", "exde": "Bei euch fühle ich mich wie zu Hause.", "exit": "Da voi mi sento a casa."}, {"de": "über den Tellerrand schauen", "lit": "Guardare oltre il bordo del piatto.", "mean": "Allargare gli orizzonti, vedere oltre il proprio mondo.", "it": "Allargare gli orizzonti.", "exde": "Reisen hilft, über den Tellerrand zu schauen.", "exit": "Viaggiare aiuta ad allargare gli orizzonti."}], "schreiben": {"impuls": "Schreib über einen Moment, in dem du dich fremd gefühlt hast — oder in dem du jemandem geholfen hast, sich willkommen zu fühlen.", "fragen": ["Was kann jeder Einzelne tun, damit sich Neuankömmlinge willkommen fühlen?", "Macht das Leben zwischen zwei Kulturen reicher oder schwieriger? Begründe."]}, "freunde": [{"de": "der Tourist", "it": "turista"}, {"de": "das Restaurant", "it": "ristorante"}, {"de": "die Pizza", "it": "pizza"}, {"de": "das Auto", "it": "auto"}, {"de": "der Bus", "it": "autobus / bus"}, {"de": "das Theater", "it": "teatro"}], "falsch": [{"de": "die Note", "it": "il voto / la nota musicale", "warn": "NON la notte (= die Nacht)"}, {"de": "die Art", "it": "il tipo / il modo", "warn": "NON l'arte (= die Kunst)"}, {"de": "brav", "it": "ubbidiente / buono", "warn": "NON „bravo / capace\""}, {"de": "also", "it": "quindi / dunque", "warn": "NON „anche\" (= auch)"}, {"de": "fast", "it": "quasi", "warn": "NON „veloce\" (= schnell)"}], "lit": {"de": "Der Mensch ist frei geschaffen, ist frei.", "it": "L'uomo è creato libero, è libero.", "src": "F. Schiller"}, "trad": {"id": "gedanken", "title": "Die Gedanken sind frei", "artist": "Volkslied", "note": "Canto popolare sulla libertà di pensiero, amatissimo in Germania.", "ytq": "Die Gedanken sind frei Lied", "de": ["Die Gedanken sind frei,", "wer kann sie erraten?", "Sie fliehen vorbei", "wie nächtliche Schatten.", "Kein Mensch kann sie wissen,", "kein Jäger erschießen;", "es bleibet dabei:", "die Gedanken sind frei!"], "it": ["I pensieri sono liberi,", "chi può indovinarli?", "Volano via", "come ombre nella notte.", "Nessuno può conoscerli,", "nessun cacciatore può abbatterli;", "resta così:", "i pensieri sono liberi!"]}, "voice": {"id": "kRq3WzSwUw0", "t": "Straßeninterviews in Magdeburg", "note": "Ascolto autentico con sottotitoli tedeschi."}, "gram_extra": [{"de": "Es regnete; trotzdem gingen wir spazieren.", "it": "Pioveva; ciononostante andammo a passeggio."}, {"de": "Ich war krank, deshalb blieb ich zu Hause.", "it": "Ero malato, perciò sono rimasto a casa."}], "song1": {"id": "6z8o7qAIlIU", "artist": "Die Toten Hosen", "titel": "Hier kommt Alex"}, "song2": {"id": "1SG5A3PYaUs", "artist": "Herbert Grönemeyer", "titel": "Mensch"}, "articles": [{"title": "Wikipedia: Migration_(Soziologie)", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Migration_(Soziologie)"}, {"title": "Klexikon: Migration (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Migration"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Medien & Nachrichten — Media e informazione", "level": "B2", "lesen": {"title": "Wem kann man heute noch glauben?", "text": "Früher war die Sache einfacher: Man kaufte morgens eine Zeitung oder schaute abends die Nachrichten, und damit war man informiert. Heute prasseln Informationen rund um die Uhr auf uns ein — aus dem Fernsehen, aus dem Internet, aus den sozialen Netzwerken. Auf den ersten Blick klingt das großartig: Nie war Wissen so leicht zugänglich. Doch genau hier liegt das Problem. Neben seriösen Quellen kursieren unzählige Gerüchte, halbe Wahrheiten und bewusste Falschmeldungen. Eine reißerische Schlagzeile verbreitet sich oft schneller als eine sorgfältig recherchierte Reportage. Hinzu kommt, dass viele Menschen nur noch das lesen, was ihre eigene Meinung bestätigt. So entstehen Blasen, in denen man dem anderen kaum noch zuhört. Was also tun? Experten raten zu einem einfachen, aber wirksamen Mittel: nicht alles sofort glauben, mehrere Quellen vergleichen und sich fragen, wer eine Nachricht warum verbreitet. Kritisches Denken ist heute wichtiger denn je.", "glos": {"informiert": "informato", "prasseln … ein": "si abbattono", "rund um die Uhr": "24 ore su 24", "zugänglich": "accessibile", "seriösen": "serie/affidabili", "Quellen": "fonti", "kursieren": "circolano", "Gerüchte": "voci", "Wahrheiten": "verità", "Falschmeldungen": "notizie false", "reißerische": "sensazionalistica", "Schlagzeile": "titolo", "verbreitet": "si diffonde", "sorgfältig": "accuratamente", "Blasen": "bolle", "bestätigt": "conferma", "wirksamen": "efficace", "vergleichen": "confrontare"}, "q": [{"q": "Was ist heute das Problem mit Informationen?", "o": ["Es gibt zu wenige", "Neben seriösen Quellen kursieren auch Falschmeldungen", "Sie sind zu teuer"], "c": 1, "e": "„kursieren unzählige Gerüchte … und … Falschmeldungen\"."}, {"q": "Was verbreitet sich oft schneller?", "o": ["Eine seriöse Reportage", "Eine reißerische Schlagzeile", "Ein langer Artikel"], "c": 1, "e": "„verbreitet sich oft schneller als eine … recherchierte Reportage\"."}, {"q": "Was raten Experten?", "o": ["Nichts lesen", "Mehrere Quellen vergleichen", "Nur einer Quelle glauben"], "c": 1, "e": "„mehrere Quellen vergleichen\"."}], "frage": "Wie informierst du dich über das Weltgeschehen? Und vertraust du den Medien?"}, "artikel": {"title": "Fake News erkennen: ein kleiner Leitfaden", "text": "Falschmeldungen sind kein neues Phänomen, doch das Internet hat ihnen Flügel verliehen. Eine erfundene Geschichte kann heute in wenigen Stunden Millionen Menschen erreichen. Wie aber erkennt man, ob eine Nachricht stimmt? Der erste Schritt ist, die Quelle zu prüfen: Wer hat die Information veröffentlicht, und ist diese Seite bekannt und vertrauenswürdig? Zweitens lohnt es sich, auf die Sprache zu achten. Wer mit großen Emotionen, vielen Ausrufezeichen und reißerischen Wörtern arbeitet, will oft eher aufregen als informieren. Drittens sollte man prüfen, ob auch andere, seriöse Medien dasselbe berichten. Und schließlich hilft eine gesunde Skepsis: Wenn eine Schlagzeile zu schön oder zu schrecklich klingt, um wahr zu sein, ist sie es oft auch nicht. Medienkompetenz ist heute keine Spezialität für Journalisten mehr, sondern eine Grundfähigkeit für alle.", "glos": {"Phänomen": "fenomeno", "Flügel": "ali", "verliehen": "dato", "erfundene": "inventata", "erreichen": "raggiungere", "stimmt": "è vera", "prüfen": "verificare", "veröffentlicht": "pubblicato", "vertrauenswürdig": "affidabile", "lohnt sich": "vale la pena", "Ausrufezeichen": "punti esclamativi", "aufregen": "agitare", "berichten": "riportano", "Skepsis": "scetticismo", "schrecklich": "terribile", "Medienkompetenz": "competenza mediatica", "Grundfähigkeit": "abilità di base"}, "q": [{"q": "Was ist der erste Schritt, um Fake News zu erkennen?", "o": ["Die Quelle prüfen", "Sie sofort teilen", "Sie ignorieren"], "c": 0, "e": "„die Quelle zu prüfen\"."}, {"q": "Was verrät oft eine Falschmeldung?", "o": ["Sachliche Sprache", "Viele Emotionen und Ausrufezeichen", "Lange Zahlen"], "c": 1, "e": "„mit großen Emotionen, vielen Ausrufezeichen …\"."}], "news": "Fake News erkennen Medienkompetenz"}, "dialog": {"title": "Eine zweifelhafte Nachricht", "lines": [{"who": "Opa", "de": "Hast du das gelesen? Sie wollen angeblich das Bargeld komplett abschaffen!"}, {"who": "Enkelin", "de": "Wo hast du das denn her?"}, {"who": "Opa", "de": "Das stand in einer Nachricht, die mir jemand geschickt hat."}, {"who": "Enkelin", "de": "Und wer hat das geschrieben? Steht da eine seriöse Quelle?"}, {"who": "Opa", "de": "Hmm … nein, eigentlich nicht. Nur ein Link und ein Foto."}, {"who": "Enkelin", "de": "Genau das ist verdächtig. Lass uns mal nachschauen."}, {"who": "Opa", "de": "Und, was findest du?"}, {"who": "Enkelin", "de": "Schau, kein einziges großes Medium berichtet darüber. Das ist Quatsch."}, {"who": "Opa", "de": "Tatsächlich. Da wäre ich fast darauf reingefallen."}, {"who": "Enkelin", "de": "Kein Problem, Opa. Im Zweifel einfach immer nachprüfen."}], "q": [{"q": "Was behauptet die Nachricht?", "o": ["Das Bargeld wird abgeschafft", "Die Preise steigen", "Die Bank schließt"], "c": 0, "e": "„Sie wollen … das Bargeld komplett abschaffen\"."}, {"q": "Warum ist die Nachricht verdächtig?", "o": ["Sie ist zu lang", "Es gibt keine seriöse Quelle", "Sie ist auf Englisch"], "c": 1, "e": "„keine seriöse Quelle … nur ein Link\"."}, {"q": "Was rät die Enkelin?", "o": ["Alles glauben", "Im Zweifel immer nachprüfen", "Nichts mehr lesen"], "c": 1, "e": "„Im Zweifel einfach immer nachprüfen\"."}]}, "musik": {"key": "nena", "task": "„99 Luftballons\" è nata in piena Guerra Fredda e mostra come una notizia o un malinteso possano scatenare il panico. Ascolta pensando al tema dell'informazione e della paura collettiva.", "level": "B1 · storico"}, "sprechen": {"read": "Heute bekommen wir Informationen rund um die Uhr, aus dem Internet und aus sozialen Netzwerken. Das ist praktisch, aber auch gefährlich, denn nicht alles stimmt. Ich versuche deshalb, mehrere Quellen zu vergleichen und nicht alles sofort zu glauben.", "prompts": [{"q": "Wo informierst du dich am liebsten und warum?", "e": "Ich informiere mich am liebsten über …, weil …"}, {"q": "Bist du schon einmal auf eine Falschmeldung hereingefallen? Erzähl.", "e": "Ja/Nein … Einmal …"}, {"q": "Sollten soziale Netzwerke für Fake News verantwortlich sein? Begründe.", "e": "Ich finde, … weil …"}], "scenario": "Ein Verwandter schickt dir eine zweifelhafte Nachricht. Erklär ihm freundlich, wie man sie überprüft."}, "grammatik": {"titel": "Der Genitiv (di chi? appartenenza)", "regel_html": "<p>Il <b>genitivo</b> esprime appartenenza (di chi/di che cosa?). Gli articoli diventano <b>des/eines</b> (masch./neutro, + -s al nome) e <b>der/einer</b> (femm./plur.).</p><table class='gtab'><tr><th></th><th>masch.</th><th>femm.</th><th>neutro</th><th>plur.</th></tr><tr><td>Genitivo</td><td><b>des</b> Mannes</td><td><b>der</b> Frau</td><td><b>des</b> Kindes</td><td><b>der</b> Kinder</td></tr></table><p>Preposizioni col genitivo: <b>wegen</b> (a causa di), <b>trotz</b> (nonostante), <b>während</b> (durante), <b>statt</b> (invece di).</p><p><b>Esempi:</b> <i>das Auto <u>des</u> Mannes</i> · <i><u>wegen</u> des Regens</i> · <i><u>während</u> der Woche</i>. Nel parlato si usa spesso <i>von + Dativo</i>: <i>das Auto von dem Mann</i>.</p>", "ex": [{"l": "Das ist das Auto ", "r": " Mannes.", "o": ["des", "der", "dem", "den"], "c": 0, "e": "genitivo masch.: <b>des</b> Mannes."}, {"l": "", "r": " des Regens bleiben wir zu Hause.", "o": ["Wegen", "Weil", "Während dass", "Trotzdem"], "c": 0, "e": "<b>Wegen</b> + genitivo."}, {"l": "Die Farbe ", "r": " Hauses ist blau.", "o": ["des", "der", "dem", "das"], "c": 0, "e": "genitivo neutro: <b>des</b> Hauses."}, {"l": "Trotz ", "r": " Wetters gehen wir raus.", "o": ["des schlechten", "dem schlechten", "der schlechte", "das schlechte"], "c": 0, "e": "trotz + genitivo: <b>des schlechten</b> Wetters."}]}, "wortschatz": [{"de": "die Nachricht", "it": "la notizia", "exde": "Die Nachricht ist wichtig.", "exit": "La notizia è importante."}, {"de": "die Zeitung", "it": "il giornale", "exde": "Ich lese die Zeitung.", "exit": "Leggo il giornale."}, {"de": "die Quelle", "it": "la fonte", "exde": "Prüf die Quelle!", "exit": "Verifica la fonte!"}, {"de": "die Falschmeldung", "it": "la notizia falsa", "exde": "Das ist eine Falschmeldung.", "exit": "È una notizia falsa."}, {"de": "die Schlagzeile", "it": "il titolo", "exde": "Die Schlagzeile ist reißerisch.", "exit": "Il titolo è sensazionalistico."}, {"de": "berichten", "it": "riferire", "exde": "Die Medien berichten darüber.", "exit": "I media ne parlano."}, {"de": "glauben", "it": "credere", "exde": "Das glaube ich nicht.", "exit": "Non ci credo."}, {"de": "prüfen", "it": "verificare", "exde": "Ich prüfe die Information.", "exit": "Verifico l'informazione."}, {"de": "vertrauenswürdig", "it": "affidabile", "exde": "Die Seite ist vertrauenswürdig.", "exit": "Il sito è affidabile."}, {"de": "die Meinung", "it": "l'opinione", "exde": "Das ist meine Meinung.", "exit": "Questa è la mia opinione."}, {"de": "verbreiten", "it": "diffondere", "exde": "Gerüchte verbreiten sich schnell.", "exit": "Le voci si diffondono in fretta."}, {"de": "kritisch", "it": "critico", "exde": "Sei kritisch!", "exit": "Sii critico!"}], "idiome": [{"de": "etwas mit Vorsicht genießen", "lit": "Godere qualcosa con cautela.", "mean": "Prendere un'informazione con le pinze.", "it": "Prendere con le pinze.", "exde": "Solche Schlagzeilen sollte man mit Vorsicht genießen.", "exit": "Certi titoli vanno presi con le pinze."}, {"de": "die Katze aus dem Sack lassen", "lit": "Far uscire il gatto dal sacco.", "mean": "Rivelare finalmente un segreto.", "it": "Svelare l'arcano / vuotare il sacco.", "exde": "Jetzt lass endlich die Katze aus dem Sack!", "exit": "Adesso vuota il sacco!"}], "schreiben": {"impuls": "Schreib einen kurzen Kommentar: Sind soziale Netzwerke gut oder schlecht für die Demokratie? Nenne Argumente.", "fragen": ["Wie könnte man Kinder am besten vor Falschmeldungen schützen?", "Hast du deine Meinung zu einem Thema schon einmal komplett geändert? Wodurch?"]}, "freunde": [{"de": "der Bus", "it": "autobus / bus"}, {"de": "das Theater", "it": "teatro"}, {"de": "die Kultur", "it": "cultura"}, {"de": "das Konzert", "it": "concerto"}, {"de": "der Park", "it": "parco"}, {"de": "das Museum", "it": "museo"}], "falsch": [{"de": "also", "it": "quindi / dunque", "warn": "NON „anche\" (= auch)"}, {"de": "fast", "it": "quasi", "warn": "NON „veloce\" (= schnell)"}, {"de": "bald", "it": "presto", "warn": "NON „baldo\""}, {"de": "komisch", "it": "strano (spesso) / buffo", "warn": "attenzione: di solito = strano"}, {"de": "die Birne", "it": "la pera / la lampadina", "warn": "NON „birra\" (= das Bier)"}], "lit": {"de": "Es irrt der Mensch, solang er strebt.", "it": "Finché l'uomo cerca, egli erra.", "src": "J. W. Goethe, Faust"}, "trad": {"id": "bruderjakob", "title": "Bruder Jakob / Fra Martino", "artist": "Volkslied / Kanon", "note": "Lo stesso canone in tedesco e in italiano: prova a cantarlo in tutte e due le lingue!", "ytq": "Bruder Jakob Kinderlied", "de": ["Bruder Jakob, Bruder Jakob,", "schläfst du noch? Schläfst du noch?", "Hörst du nicht die Glocken?", "Hörst du nicht die Glocken?", "Ding dang dong, ding dang dong."], "it": ["Fra Martino, campanaro,", "dormi tu? Dormi tu?", "Suona le campane!", "Suona le campane!", "Din don dan, din don dan."]}, "voice": {"id": "Lfoai_nP7lc", "t": "„Wie wichtig ist dir Geld?\" — Straßeninterview", "note": "Persone vere a Berlino. Attiva i sottotitoli con il tasto „C\"."}, "gram_extra": [{"de": "Das ist das Auto meines Vaters.", "it": "È l'auto di mio padre."}, {"de": "Die Farbe des Himmels ist blau.", "it": "Il colore del cielo è blu."}], "song1": {"id": "5PST7Ld4wWU", "artist": "Max Giesinger", "titel": "Wenn sie tanzt"}, "song2": {"id": "xSWJBClrmgo", "artist": "Herbert Grönemeyer", "titel": "Der Weg"}, "articles": [{"title": "Wikipedia: Nachricht", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Nachricht"}, {"title": "Klexikon: Zeitung (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Zeitung"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
DOR_DAYS.push({"thema": "Glück & Lebenssinn — Felicità e senso della vita", "level": "B2", "lesen": {"title": "Was wir vom Glück missverstehen", "text": "Wenn man Menschen fragt, was sie sich im Leben am meisten wünschen, lautet die Antwort fast immer dieselbe: glücklich sein. Doch was bedeutet das eigentlich? Lange dachte man, Glück sei vor allem eine Frage der äußeren Umstände — viel Geld, Erfolg, ein großes Haus. Die Forschung zeichnet ein anderes Bild. Natürlich macht Armut unglücklich, doch ab einem gewissen Wohlstand steigt das Glück kaum noch. Viel entscheidender sind, so zeigen Studien, stabile Beziehungen, das Gefühl, gebraucht zu werden, und eine Aufgabe, die Sinn stiftet. Interessant ist auch, dass wir uns ständig an Gutes gewöhnen. Was uns gestern noch glücklich machte, ist heute selbstverständlich. Vielleicht liegt der Schlüssel deshalb weniger im Streben nach immer mehr, sondern in der Fähigkeit, das Vorhandene wirklich wahrzunehmen. Wer abends bewusst auf die kleinen guten Momente des Tages zurückblickt, fühlt sich nachweislich zufriedener. Glück ist vielleicht keine Sache des Habens, sondern des Bemerkens.", "glos": {"wünschen": "desiderano", "dieselbe": "la stessa", "äußeren": "esterne", "Umstände": "circostanze", "Erfolg": "successo", "Forschung": "ricerca", "Armut": "povertà", "Wohlstand": "benessere", "entscheidender": "più decisivi", "Beziehungen": "relazioni", "Sinn stiftet": "dà senso", "gewöhnen": "abituarsi", "selbstverständlich": "scontato", "Streben": "ambizione", "Vorhandene": "ciò che si ha", "wahrzunehmen": "percepire", "bewusst": "consapevolmente", "nachweislich": "dimostrabilmente", "Bemerkens": "del notare"}, "q": [{"q": "Was dachte man früher über Glück?", "o": ["Es kommt von inneren Werten", "Es hängt vor allem von Geld und Erfolg ab", "Es ist unmöglich"], "c": 1, "e": "„Glück sei vor allem eine Frage der äußeren Umstände\"."}, {"q": "Was ist laut Forschung entscheidend?", "o": ["Mehr Geld", "Stabile Beziehungen und Sinn", "Ein großes Haus"], "c": 1, "e": "„stabile Beziehungen … eine Aufgabe, die Sinn stiftet\"."}, {"q": "Was ist die Schlussidee?", "o": ["Glück ist eine Sache des Habens", "Glück ist eine Sache des Bemerkens", "Glück gibt es nicht"], "c": 1, "e": "„Glück ist vielleicht … des Bemerkens\"."}], "frage": "Was macht dich wirklich glücklich? Und hat sich deine Antwort darauf mit der Zeit verändert?"}, "artikel": {"title": "Die Kunst, weniger zu wollen", "text": "In einer Welt, die uns täglich einredet, wir bräuchten mehr — mehr Dinge, mehr Erfolg, mehr Erlebnisse —, entdecken immer mehr Menschen den Reiz des Gegenteils. „Minimalismus\" nennt sich diese Bewegung, doch im Kern geht es um eine alte Idee: Weniger kann mehr sein. Wer sich von überflüssigem Besitz trennt, gewinnt nicht nur Platz in der Wohnung, sondern oft auch im Kopf. Statt Zeit mit dem Kaufen, Pflegen und Aufräumen von Dingen zu verbringen, bleibt mehr Raum für das, was wirklich zählt: Menschen, Erlebnisse, Ruhe. Kritiker wenden ein, Minimalismus sei ein Luxus für jene, die ohnehin genug haben. Da ist etwas dran. Und doch steckt in dem Gedanken eine Wahrheit, die für alle gilt: Nicht alles, was wir besitzen können, müssen wir auch besitzen. Manchmal ist die Freiheit, etwas nicht zu brauchen, das größte Geschenk, das wir uns selbst machen können.", "glos": {"einredet": "fa credere", "bräuchten": "avremmo bisogno", "Erlebnisse": "esperienze", "Reiz": "fascino", "Gegenteils": "contrario", "Bewegung": "movimento", "Kern": "nucleo", "überflüssigem": "superfluo", "Besitz": "possesso", "trennt": "si separa", "Pflegen": "curare", "Aufräumen": "riordinare", "zählt": "conta", "Kritiker": "critici", "einwenden": "obiettare", "ohnehin": "comunque", "Wahrheit": "verità", "besitzen": "possedere", "Freiheit": "libertà"}, "q": [{"q": "Worum geht es beim Minimalismus im Kern?", "o": ["Mehr kaufen", "Weniger kann mehr sein", "Nichts besitzen dürfen"], "c": 1, "e": "„Weniger kann mehr sein\"."}, {"q": "Was wenden Kritiker ein?", "o": ["Es ist zu teuer", "Es ist ein Luxus für jene, die genug haben", "Es ist verboten"], "c": 1, "e": "„Minimalismus sei ein Luxus für jene, die ohnehin genug haben\"."}], "news": "Minimalismus weniger besitzen Glück"}, "dialog": {"title": "Ein Gespräch über das Wesentliche", "lines": [{"who": "Nina", "de": "Du wirkst seit deinem Umzug irgendwie zufriedener. Täusche ich mich?"}, {"who": "Leon", "de": "Nein, stimmt. Ich habe beim Umzug die Hälfte meiner Sachen weggegeben."}, {"who": "Nina", "de": "Die Hälfte? Hat dir nichts davon gefehlt?"}, {"who": "Leon", "de": "Ehrlich? Fast nichts. Vieles habe ich jahrelang nicht benutzt."}, {"who": "Nina", "de": "Und das macht dich glücklicher?"}, {"who": "Leon", "de": "Auf eine Art schon. Ich habe weniger Chaos und mehr Zeit."}, {"who": "Nina", "de": "Interessant. Ich sammle eher immer mehr an."}, {"who": "Leon", "de": "Das ging mir auch so. Bis ich gemerkt habe, dass die Dinge mich besitzen."}, {"who": "Nina", "de": "Schöner Satz. Vielleicht sollte ich auch mal ausmisten."}, {"who": "Leon", "de": "Fang klein an. Ein Schrank reicht für den Anfang."}], "q": [{"q": "Was hat Leon beim Umzug gemacht?", "o": ["Neue Möbel gekauft", "Die Hälfte seiner Sachen weggegeben", "Nichts verändert"], "c": 1, "e": "„die Hälfte meiner Sachen weggegeben\"."}, {"q": "Wie fühlt er sich jetzt?", "o": ["Gestresster", "Zufriedener, mit mehr Zeit", "Gelangweilt"], "c": 1, "e": "„weniger Chaos und mehr Zeit\"."}, {"q": "Welchen Rat gibt er Nina?", "o": ["Alles wegwerfen", "Klein anfangen, z. B. ein Schrank", "Nichts tun"], "c": 1, "e": "„Fang klein an. Ein Schrank reicht …\"."}]}, "musik": {"key": "bourani", "task": "Per l'ultimo giorno, riascolta „Auf uns\": un brindisi alla vita, agli amici e ai momenti belli. Collega il messaggio al tema della felicità nelle piccole cose. Canta il ritornello a voce alta!", "level": "A2–B1 · celebrativo"}, "sprechen": {"read": "Lange habe ich gedacht, dass Glück vor allem von Erfolg und Geld abhängt. Heute sehe ich das anders. Für mich sind stabile Beziehungen und das Gefühl, etwas Sinnvolles zu tun, viel wichtiger. Vielleicht liegt das Glück gar nicht im Haben, sondern im Bemerken der kleinen Dinge.", "prompts": [{"q": "Was bedeutet ein gelungenes Leben für dich?", "e": "Ein gelungenes Leben bedeutet für mich …"}, {"q": "Würdest du sagen, dass du im Moment glücklich bist? Warum?", "e": "Ich würde sagen, …, weil …"}, {"q": "Kann man lernen, glücklicher zu sein? Wie?", "e": "Ich glaube (nicht), denn …"}], "scenario": "Ein Freund sagt, er sei nie zufrieden und wolle immer mehr. Sprich mit ihm darüber, was wirklich zählt."}, "grammatik": {"titel": "Konjunktiv II der Vergangenheit (rimpianti e ipotesi irreali)", "regel_html": "<p>Per esprimere ipotesi <b>irreali al passato</b> („se avessi …, avrei …\") si usa <b>hätte/wäre + participio</b>.</p><table class='gtab'><tr><th>tipo</th><th>esempio</th></tr><tr><td>con haben</td><td>Wenn ich Zeit <b>gehabt hätte</b>, <b>hätte</b> ich dich <b>besucht</b>.</td></tr><tr><td>con sein</td><td>Wenn er früher <b>gegangen wäre</b>, <b>wäre</b> er pünktlich <b>gewesen</b>.</td></tr></table><p>Si usa per <b>rimpianti</b>: <i>Ich <u>hätte</u> mehr lernen <u>sollen</u>.</i> (Avrei dovuto studiare di più.) · <i>Das <u>hätte</u> ich nicht <u>sagen</u> sollen.</i></p><p>💡 La scelta tra <b>hätte</b> e <b>wäre</b> segue le stesse regole del Perfekt (movimento/cambiamento → wäre).</p>", "ex": [{"l": "Wenn ich Zeit gehabt hätte, ", "r": " ich dich besucht.", "o": ["hätte", "wäre", "habe", "würde"], "c": 0, "e": "con besuchen → <b>hätte</b> … besucht."}, {"l": "Wenn er früher gegangen ", "r": ", wäre er pünktlich gewesen.", "o": ["wäre", "hätte", "ist", "war"], "c": 0, "e": "gehen (movimento) → <b>wäre</b> gegangen."}, {"l": "Ich ", "r": " mehr lernen sollen.", "o": ["hätte", "wäre", "habe", "bin"], "c": 0, "e": "rimpianto: <b>hätte</b> … sollen."}, {"l": "Das ", "r": " ich nicht sagen sollen.", "o": ["hätte", "wäre", "habe", "würde"], "c": 0, "e": "rimpianto: <b>hätte</b> … sollen."}]}, "wortschatz": [{"de": "das Glück", "it": "la felicità/fortuna", "exde": "Glück kann man nicht kaufen.", "exit": "La felicità non si compra."}, {"de": "der Sinn", "it": "il senso", "exde": "Was ist der Sinn des Lebens?", "exit": "Qual è il senso della vita?"}, {"de": "zufrieden", "it": "soddisfatto", "exde": "Ich bin zufrieden.", "exit": "Sono soddisfatto."}, {"de": "der Erfolg", "it": "il successo", "exde": "Erfolg ist nicht alles.", "exit": "Il successo non è tutto."}, {"de": "der Wohlstand", "it": "il benessere", "exde": "Wohlstand allein reicht nicht.", "exit": "Il benessere da solo non basta."}, {"de": "die Beziehung", "it": "la relazione", "exde": "Beziehungen machen glücklich.", "exit": "Le relazioni rendono felici."}, {"de": "sich gewöhnen an", "it": "abituarsi a", "exde": "Man gewöhnt sich an alles.", "exit": "Ci si abitua a tutto."}, {"de": "wahrnehmen", "it": "percepire", "exde": "Nimm die kleinen Dinge wahr.", "exit": "Percepisci le piccole cose."}, {"de": "verzichten", "it": "rinunciare", "exde": "Manchmal ist Verzicht Freiheit.", "exit": "A volte rinunciare è libertà."}, {"de": "der Besitz", "it": "il possesso", "exde": "Besitz macht nicht glücklich.", "exit": "Il possesso non rende felici."}, {"de": "dankbar", "it": "grato", "exde": "Ich bin dankbar.", "exit": "Sono grato."}, {"de": "das Wesentliche", "it": "l'essenziale", "exde": "Konzentrier dich aufs Wesentliche.", "exit": "Concentrati sull'essenziale."}], "idiome": [{"de": "Jeder ist seines Glückes Schmied.", "lit": "Ognuno è il fabbro della propria fortuna.", "mean": "Ciascuno è in gran parte responsabile della propria felicità.", "it": "Ognuno è artefice del proprio destino.", "exde": "Tu entscheidest — jeder ist seines Glückes Schmied.", "exit": "Decidi tu: ognuno è artefice del proprio destino."}, {"de": "Weniger ist mehr.", "lit": "Meno è di più.", "mean": "La semplicità vale spesso più dell'abbondanza.", "it": "Il meno è meglio del troppo.", "exde": "Bei Design gilt oft: weniger ist mehr.", "exit": "Nel design vale spesso: meno è meglio."}], "schreiben": {"impuls": "Schreib einen kurzen persönlichen Text: Was macht für dich ein glückliches Leben aus? Hat sich deine Sicht mit der Zeit verändert?", "fragen": ["Glaubst du, dass man Glück lernen kann — oder ist es Schicksal?", "Welche drei Dinge, für die du dankbar bist, fallen dir spontan ein? Schreib auf Deutsch."]}, "freunde": [{"de": "der Park", "it": "parco"}, {"de": "das Museum", "it": "museo"}, {"de": "die Person", "it": "persona"}, {"de": "die Politik", "it": "politica"}, {"de": "die Energie", "it": "energia"}, {"de": "das System", "it": "sistema"}], "falsch": [{"de": "komisch", "it": "strano (spesso) / buffo", "warn": "attenzione: di solito = strano"}, {"de": "die Birne", "it": "la pera / la lampadina", "warn": "NON „birra\" (= das Bier)"}, {"de": "sensibel", "it": "sensibile / delicato", "warn": "NON „sensato\" (= vernünftig)"}, {"de": "der Termin", "it": "l'appuntamento", "warn": "NON il „termine/scadenza-parola\""}, {"de": "das Rezept", "it": "la ricetta / la prescrizione", "warn": "vale sia in cucina sia dal medico"}], "lit": {"de": "Was mich nicht umbringt, macht mich stärker.", "it": "Ciò che non mi uccide mi rende più forte.", "src": "F. Nietzsche"}, "trad": {"id": "mond", "title": "Der Mond ist aufgegangen", "artist": "Matthias Claudius (1779)", "note": "Una delle più amate canzoni della sera in Germania.", "ytq": "Der Mond ist aufgegangen Lied", "de": ["Der Mond ist aufgegangen,", "die goldnen Sternlein prangen", "am Himmel hell und klar;", "der Wald steht schwarz und schweiget,", "und aus den Wiesen steiget", "der weiße Nebel wunderbar."], "it": ["La luna è sorta,", "le dorate stelline brillano", "nel cielo chiaro e limpido;", "il bosco sta nero e tace,", "e dai prati si leva", "la bianca nebbia, meravigliosa."]}, "voice": {"id": "cGQZ8lTHn1M", "t": "„Was macht dich sympathisch?\" — Straßeninterview", "note": "Tedeschi veri intervistati per strada, a velocità reale."}, "gram_extra": [{"de": "Ich hätte mehr lernen sollen.", "it": "Avrei dovuto studiare di più."}, {"de": "Wenn ich Zeit gehabt hätte, wäre ich gekommen.", "it": "Se avessi avuto tempo, sarei venuto."}], "song1": {"id": "WnJOJ57EqIA", "artist": "Max Giesinger", "titel": "80 Millionen"}, "song2": {"id": "_IZsxfo8ITw", "artist": "Herbert Grönemeyer", "titel": "Männer"}, "articles": [{"title": "Wikipedia: Gl%C3%BCck", "source": "Wikipedia (DE)", "url": "https://de.wikipedia.org/wiki/Gl%C3%BCck"}, {"title": "Klexikon: Gl%C3%BCck (tedesco facile)", "source": "Klexikon", "url": "https://klexikon.zum.de/wiki/Gl%C3%BCck"}, {"title": "Deutsche Welle — Deutsch lernen", "source": "DW", "url": "https://learngerman.dw.com/de/overview"}]});
